// Device.js
var DeviceQuality = {
    'lowEndDevice': 1,
    'mediumEndDevice': 2,
    'highEndDevice': 3
};

var Device = (function () {
    var instance;      

    function createInstance() {
        var object = {};
        var ua = navigator.userAgent;
        
        object.vita = false;
        object.kindle = false;
        object.android = false;
        object.chromeOS = false;
        object.iOS = false;
        object.linux = false;
        object.macOS = false;
        object.windows = false;
        object.windowsPhone = false;
        object.silk = false;
        object.ipad = false;
        object.ipadOS = false;
        object.ipad2 = false;
        object.ipad3 = false;
        object.desktop = false;
        object.mobile = false;
        object.buttonSize = window.matchMedia( "(min-width: 700px)" ) ? "tablet_" : "mobile_";
        object.isWKWebView = IsWKWebView();
        object.shouldDisplayBrim = false;
        object.ram = navigator.deviceMemory ? navigator.deviceMemory : 8;

        
        
        object.hasTouchScreen = navigator.maxTouchPoints && navigator.maxTouchPoints > 2;
        
        if (/Playstation Vita/.test(ua))
        {
            object.vita = true;
        }
        else if (/Kindle/.test(ua) || /\bKF[A-Z][A-Z]+/.test(ua) || /Silk.*Mobile Safari/.test(ua))
        {
            object.kindle = true;
            // This will NOT detect early generations of Kindle Fire, I think there is no reliable way...
            // E.g. "Mozilla/5.0 (Macintosh; U; Intel Mac OS X 10_6_3; en-us; Silk/1.1.0-80) AppleWebKit/533.16 (KHTML, like Gecko) Version/5.0 Safari/533.16 Silk-Accelerated=true"
        }
        else if (/Android/.test(ua))
        {
            object.android = true;
        }
        else if (/CrOS/.test(ua))
        {
            object.chromeOS = true;
        }
        else if (/iP[ao]d|iPhone/i.test(ua) || (navigator.userAgent.match(/Mac/) && object.hasTouchScreen))
        {
            object.iOS = true;
        }
        else if (/Linux/.test(ua))
        {
            object.linux = true;
        }
        else if (/Mac OS/.test(ua))
        {
            object.macOS = true;
        }
        else if (/Windows/.test(ua))
        {
            object.windows = true;
        }

        if (/Windows Phone/i.test(ua) || /IEMobile/i.test(ua))
        {
            object.android = false;
            object.iOS = false;
            object.macOS = false;
            object.windows = true;
            object.windowsPhone = true;
        }

        object.silk = /Silk/.test(ua); // detected in browsers
    
        var isOldIpad = navigator.platform === 'iPad' || /iPad/i.test(ua);
        var suspectedNewIpad = (object.iOS && (/Mac/i.test(ua) && navigator.maxTouchPoints && navigator.maxTouchPoints > 1));

        
        if(isOldIpad || suspectedNewIpad){
            object.ipad = true;
        }
        
        if(object.ipad && window.devicePixelRatio === 1 && ((window.screen.height === 768 && window.screen.width === 1024) || (window.screen.height === 1024 && window.screen.width === 768))) {
            object.ipad2 = true;
        }
        else if(object.ipad && window.devicePixelRatio === 2 && CheckIpad3()){
            object.ipad3 = true;
        }

        object.mobile = object.iOS || object.android || object.kindle;
        object.desktop = !object.mobile;

        object.deviceQuality = DeviceQuality.highEndDevice;
        if(!object.desktop){
            if(object.ipad2 || object.ram <= 2){
                object.deviceQuality = DeviceQuality.lowEndDevice;
            }
            else{
                object.deviceQuality = DeviceQuality.mediumEndDevice;
            }
        }

        object.GetButtonSize = function() {
            return object.buttonSize;
        };
        
        //Might have to remove this (is fales when emulating iphone in chrome) ("standalone" in window.navigator)
        
        object.shouldDisplayBrim = (!object.ipad && !object.isWKWebView && (object.iOS || ua.indexOf('like Mac OS X') != -1));// && ("standalone" in window.navigator) && !window.navigator.standalone);
        return object;
    }
    
    //Differentiates between Ipad3/4 - Value of 2 means Ipad3
    function CheckIpad3() {
        var canvas = document.getElementById("application-canvas");
        var gl = canvas.getContext("experimental-webgl");

        if(gl === null){
            return false;
        }

        var ext = (
          gl.getExtension('EXT_texture_filter_anisotropic') ||
          gl.getExtension('MOZ_EXT_texture_filter_anisotropic') ||
          gl.getExtension('WEBKIT_EXT_texture_filter_anisotropic')
        );

        if (ext){
          var max = gl.getParameter(ext.MAX_TEXTURE_MAX_ANISOTROPY_EXT);
            if(max == 2){
                return true;
            }
        }

        return false;
    }

    function IsWKWebView() {
        if (window.webkit && window.webkit.messageHandlers) {
            return true;
        }

        return false;
    }
 
    return {
        Instance: function () {
            if (!instance) {
                instance = createInstance();
            }
            return instance;
        }
    };
})();

// Boot.js
var Boot = pc.createScript('boot');

Boot.attributes.add("domClasses", {
    type: 'asset',
    title: "DOM Classes JSON"
});

Boot.attributes.add("deviceOrientationCheckerEntity", {type: 'entity'});
Boot.attributes.add("brimEntity", {type: 'entity'});

Boot.prototype.initialize = function() {    
    MPDOMClasses.LoadData(this.domClasses);
    
    this.deviceOrientationChecker = this.deviceOrientationCheckerEntity.script.deviceOrientationChecker;
    this.brim = this.brimEntity.script.brim;
    
    this.checkLoad = true;
    
    this.app.assets.on("load", function (asset) {
        if(SceneManager.Instance.loadedScene != "SceneLoader" && asset.type != "material" && asset.type != "sprite"){
            console.log("Loose asset loaded... " + asset.name);
        }
        
    });
    this.app.tick = this.MakeTick(this.app);
};



Boot.prototype.postUpdate = function() {   
    if(this.checkLoad && GameManager.Instance.config && !this.brim.visible && this.deviceOrientationChecker.isValidOrientation){
        this.checkLoad = false;
        this.LoadMainMenu();
    }
    
};

var _frameEndData = {};

Boot.prototype.MakeTick = function(_app) {   
    var app = _app;
    return function () {
        if (! app.graphicsDevice)
            return;

        // have current application pointer in pc
        pc.app = app;
        var now = pc.now();
        var ms = now - (app._time || now);
        var dt = ms / 1000.0;
        dt = pc.math.clamp(dt, 0, 0.1);
        dt *= app.timeScale;

        app._time = now;

        // Submit a request to queue up a new animation frame immediately
        if (app.vr && app.vr.display) {
            app.vr.display.requestAnimationFrame(app.tick);
        } else {
            window.requestAnimationFrame(app.tick);
        }

        // #ifdef PROFILER
        app._fillFrameStats(now, dt, ms);
        // #endif

        app.update(dt);

        if (app.autoRender || app.renderNextFrame) {
            app.render();
            app.renderNextFrame = false;
        }

        // set event data
        _frameEndData.timestamp = pc.now();
        _frameEndData.target = app;

        app.fire("frameend", _frameEndData);
        app.fire("frameEnd", _frameEndData);// deprecated old event, remove when editor updated

        if (app.vr && app.vr.display && app.vr.display.presenting) {
            app.vr.display.submitFrame();
        }
    };
    
};

Boot.prototype.LoadMainMenu = function() { 
    this.AttemptHydraConnect();

    this.entity.dontDestroyOnLoad = true;
    SceneManager.Instance.SetState("SplashScreen");
};

Boot.prototype.AttemptHydraConnect = function() { 

    var authToken = SaveDataManager.Instance.GetGameData("authToken") || null;
    var accountID = SaveDataManager.Instance.GetGameData("accountID") || null;
    var locale = GameManager.Instance.config.language;

    if(GameManager.Instance.config.locale){
        locale += "-" + GameManager.Instance.config.locale;
    }

    Hydra.Connect({
        logResponses: false,
        rootUrl: "https://central-api.wbagora.com",
        apiKey: "093f9fcf420e4e47bbc0ddd147ffb1fe", 
        locale: locale,
        authToken: authToken,
        accountID: accountID,
    }, this.OnHydraConnectSuccess.bind(this), this.OnHydraConnectFailed.bind(this)); 
};

Boot.prototype.OnHydraConnectSuccess = function(response) { 
    SaveDataManager.Instance.SetGameData("authToken", Hydra.authToken);
    SaveDataManager.Instance.SetGameData("accountID", Hydra.accountID);
	SaveDataManager.Instance.SaveToStorage();
};

Boot.prototype.OnHydraConnectFailed = function(response) { 
    if(response && response.code == 400 && response.hydra_error == 1){
        Hydra.authToken = null;
        Hydra.accountID = null;
        SaveDataManager.Instance.SetGameData("authToken", undefined);
        SaveDataManager.Instance.SetGameData("accountID", undefined);
	    SaveDataManager.Instance.SaveToStorage();
        this.AttemptHydraConnect();
    }
    
};

// MPScene.js
var MPScene = pc.createScript("scene");

MPScene.prototype.initialize = function() {    
    //Load boot scene if we didn't load from it
    if(!GameManager.Instance){
        this.entity.destroy();
        
        setTimeout(function(){ 
            this.app.scenes.loadSceneHierarchy(SceneManager.Instance.GetSceneUrl("Boot")); 
        }.bind(this), 1000);
        return;
    }
    
    SceneManager.Instance.loadedSceneEntity = this.entity;
    
    this.on('state', this.OnStateChanged, this);
    this.on("destroy", this.OnDestroy, this);   
    
    this.name = SceneManager.Instance.loadedScene;
    
    this.entity.scene = this;
    this.unloadAssetBundlesOnDestroy = true;

    this.Enable();
};

MPScene.prototype.postInitialize = function() {
    MPDOMManager.Instance.screen = this;
};

MPScene.prototype.OnSceneLoaded = function(data) {

};

MPScene.prototype.update = function(dt) {

};

MPScene.prototype.postUpdate = function(dt) {

};

MPScene.prototype.OnStateChanged = function(state) {
    if(state){
        this.Enable();
    }
};


MPScene.prototype.Enable = function() {
    this.entity.enabled = true;
    MPDOMManager.Instance.screen = this;
    
    SceneManager.Instance.loadedSceneEntity = this.entity;

    this.app.scenes.loadSceneSettings(SceneManager.Instance.GetSceneUrl(this.name), function(err){}); //Applies scene settings
};

MPScene.prototype.Disable = function() {
    if(MPDOMManager.Instance.screen == this){
        MPDOMManager.Instance.screen = null;
    }
    this.entity.enabled = false;
};


MPScene.prototype.Pause = function() {  
    GameManager.Instance.PauseAll("pause_screen");
    SceneManager.Instance.SetState("PauseScene");
    
    //this.Disable();
};

MPScene.prototype.RollbackScene = function() {  
    this.entity.destroy();
    SceneManager.Instance.RollbackStateStack();
};

MPScene.prototype.OnDestroy = function() {
    if(this.unloadAssetBundlesOnDestroy){
        setTimeout(function(name){
            GameManager.Instance.UnloadAssetBundles(name);
        }.bind(this, this.entity.name), 1);
    }
    
};

