// PlayCanvasEvent.js
var PlayCanvasEvent = pc.createScript('playCanvasEvent');

PlayCanvasEvent.attributes.add('eventFunctionEntity', { type: 'entity' , title: "Event Function Entity"});
PlayCanvasEvent.attributes.add('eventScriptName', { type: 'string' , title: "Event Function Script Name"});
PlayCanvasEvent.attributes.add('eventFunctionName', { type: 'string' , title: "Event Function Name"});

PlayCanvasEvent.prototype.initialize = function() {
    this.entity.playCanvasEvent = this;

    this.allowInvocation = true;
    
    this.arg1 = null;
    this.arg2 = null;
    this.arg3 = null;
    this.arg4 = null;
    this.arg5 = null;
    
    if(!this.eventFunctionEntity){
        this.eventFunctionEntity = this.entity;
    }

    this.on("destroy", this.OnDestroy);
};

PlayCanvasEvent.prototype.Invoke = function(arg1, arg2, arg3, arg4, arg5) {
    
    arg1 = this.arg1 !== null ? this.arg1 : arg1;
    arg2 = this.arg2 !== null ? this.arg2 : arg2;
    arg3 = this.arg3 !== null ? this.arg3 : arg3;
    arg4 = this.arg4 !== null ? this.arg4 : arg4;
    arg5 = this.arg5 !== null ? this.arg5 : arg5;
    
    this.fire("invoke", arg1, arg2, arg3, arg4, arg5);

    if(this.allowInvocation){
        this.eventFunctionEntity.script[this.eventScriptName][this.eventFunctionName](arg1, arg2, arg3, arg4, arg5);
    }

    
};

PlayCanvasEvent.prototype.OnDestroy = function() {
    this.entity.playCanvasEvent = null;
};

