//Singleton Event
var PlayCanvasStaticEvent = pc.createScript('playCanvasStaticEvent');

PlayCanvasStaticEvent.attributes.add('className', { type: 'string' , title: "Class Name"});
PlayCanvasStaticEvent.attributes.add('classObjectName', { type: 'string' , title: "Singleton Class Object Name", default: "null"});
PlayCanvasStaticEvent.attributes.add('eventFunctionName', { type: 'string' , title: "Event Function Name"});
PlayCanvasStaticEvent.attributes.add('isSingleton', { type: 'boolean' , default: false});

PlayCanvasStaticEvent.prototype.initialize = function() {
    this.entity.playCanvasEvent = this;
    
    this.allowInvocation = true;
    
    this.arg1 = null;
    this.arg2 = null;
    this.arg3 = null;
    this.arg4 = null;
    this.arg5 = null;


    this.on("destroy", this.OnDestroy);
};

PlayCanvasStaticEvent.prototype.Invoke = function(arg1, arg2, arg3, arg4, arg5) {
    arg1 = this.arg1 !== null ? this.arg1 : arg1;
    arg2 = this.arg2 !== null ? this.arg2 : arg2;
    arg3 = this.arg3 !== null ? this.arg3 : arg3;
    arg4 = this.arg4 !== null ? this.arg4 : arg4;
    arg5 = this.arg5 !== null ? this.arg5 : arg5;
    
    this.fire("invoke", arg1, arg2, arg3, arg4, arg5);
    
    if(this.allowInvocation){
        if(this.isSingleton){
            if(window[this.className].Instance){
                if(this.classObjectName == "null"){
                    window[this.className].Instance[this.eventFunctionName](arg1, arg2, arg3, arg4, arg5);
                }
                else{
                    window[this.className].Instance[this.classObjectName][this.eventFunctionName](arg1, arg2, arg3, arg4, arg5);
                }
            }
        }
        else{
            if(window[this.className]){
                if(this.classObjectName == "null"){
                    window[this.className][this.eventFunctionName](arg1, arg2, arg3, arg4, arg5);
                }
                else{
                    window[this.className][this.classObjectName][this.eventFunctionName](arg1, arg2, arg3, arg4, arg5);
                }
            }
        }
        
        
    }
    
};


//Singleton Event
var PlayCanvasFireEvent = pc.createScript('playCanvasFireEvent');

PlayCanvasFireEvent.attributes.add('fireEntity', {type: 'entity', description: "Leave empty to fire on app"});
PlayCanvasFireEvent.attributes.add('fireScriptName', {type: 'string', description: "Leave empty to listen to entity"});
PlayCanvasFireEvent.attributes.add('fireEventName', {type: 'string'});

PlayCanvasFireEvent.prototype.initialize = function() {
    this.entity.playCanvasEvent = this;
    
    this.arg1 = null;
    this.arg2 = null;
    this.arg3 = null;
    this.arg4 = null;
    this.arg5 = null;


    this.on("destroy", this.OnDestroy);
};

PlayCanvasFireEvent.prototype.Invoke = function(arg1, arg2, arg3, arg4, arg5) {
    arg1 = this.arg1 !== null ? this.arg1 : arg1;
    arg2 = this.arg2 !== null ? this.arg2 : arg2;
    arg3 = this.arg3 !== null ? this.arg3 : arg3;
    arg4 = this.arg4 !== null ? this.arg4 : arg4;
    arg5 = this.arg5 !== null ? this.arg5 : arg5;
    
    this.fire("invoke", arg1, arg2, arg3, arg4, arg5);
    
    
    if(this.fireEntity){
        if(this.fireScriptName){
            this.fireEntity.script[this.fireScriptName].fire(this.fireEventName, arg1, arg2, arg3, arg4, arg5);
        }
        else{
            this.fireEntity.fire(this.fireEventName, arg1, arg2, arg3, arg4, arg5);
        }
    }
    else{
        this.app.fire(this.fireEventName, arg1, arg2, arg3, arg4, arg5);
    }
    
};

//Multiple Event
var PlayCanvasEventCollection = pc.createScript('playCanvasEventCollection');

PlayCanvasEventCollection.attributes.add('eventsEntity', { type: 'entity'});

PlayCanvasEventCollection.prototype.initialize = function() {
    this.entity.playCanvasEvent = this;
    
    this.allowInvocation = true;
    
    this.events = [];

    this.on("destroy", this.OnDestroy);
};

PlayCanvasEventCollection.prototype.postInitialize = function() {
    for(var i = 0; i<this.eventsEntity.children.length; i++){
        if(this.eventsEntity.children[i] && this.eventsEntity.children[i].playCanvasEvent){
            this.events.push(this.eventsEntity.children[i].playCanvasEvent);
        }
        
    }
};

PlayCanvasEventCollection.prototype.Invoke = function(arg1, arg2, arg3, arg4, arg5) {
    this.fire("invoke", arg1, arg2, arg3, arg4, arg5);
    
    if(this.allowInvocation){
        for(var i = 0; i<this.events.length; i++){
            this.events[i].Invoke(arg1, arg2, arg3, arg4, arg5);
        }
    }
    
};

//Event parameters
var PlayCanvasEventDelay = pc.createScript('playCanvasEventDelay');

PlayCanvasEventDelay.attributes.add('delay', {type: 'number', default: 1});

PlayCanvasEventDelay.prototype.initialize = function() {
    this.playcanvasEvent = this.entity.playCanvasEvent;
    this.playcanvasEvent.allowInvocation = false;
    
    this.arg1 = null;
    this.arg2 = null;
    this.arg3 = null;
    this.arg4 = null;
    this.arg5 = null;
    
    this.timer = 0;
    
    this.isInvoking = false;
    
    this.playcanvasEvent.on("invoke", this.OnInvoke.bind(this));
    
    this.on("destroy", this.OnDestroy);
};

PlayCanvasEventDelay.prototype.update = function(dt) {
    if(GameManager.Instance.IsPaused()) return;
    //console.log(this.timer);
    if(this.timer > 0){
        this.timer -= dt;
        if(this.timer <= 0){
            this.isInvoking = true;
            this.playcanvasEvent.allowInvocation = true;
            this.playcanvasEvent.Invoke(this.arg1, this.arg2, this.arg3, this.arg4, this.arg5);
            this.playcanvasEvent.allowInvocation = false;
            this.isInvoking = false;
            
            this.arg1 = null;
            this.arg2 = null;
            this.arg3 = null;
            this.arg4 = null;
            this.arg5 = null;
        }
    }
    
};

PlayCanvasEventDelay.prototype.OnInvoke = function(arg1, arg2, arg3, arg4, arg5) {
    if(!this.isInvoking){
        this.arg1 = arg1;
        this.arg2 = arg2;
        this.arg3 = arg3;
        this.arg4 = arg4;
        this.arg5 = arg5;

        this.timer = this.delay;
    }
    
    
};

PlayCanvasEventDelay.prototype.OnDestroy = function() {
    this.arg1 = null;
    this.arg2 = null;
    this.arg3 = null;
    this.arg4 = null;
    this.arg5 = null;
    this.playcanvasEvent.off("Invoke", this.OnInvoke, this);
    
};

// CSSLoader.js
var CSSLoader = pc.createScript('cssLoader');

CSSLoader.attributes.add("cssFiles", {
    type: 'asset',
    title: "CSS Files",
    array: true,
    description: "CSS stylesheet"
});

CSSLoader.prototype.initialize = function() {
    for (var i = 0; i < this.cssFiles.length; i++) {
        if (!this.cssFiles[i].styleApplied) {
            this.cssFiles[i].styleApplied = true;
            
            var cssURL = this.cssFiles[i].getFileUrl();
            var link = document.createElement("link");
            this.cssFiles[i].link = link;
            link.type = "text/css";
            link.rel = "stylesheet";
            link.href = cssURL;
            document.head.appendChild(link);
            
            this.cssFiles[i].on('load', function() {
                cssURL = this.getFileUrl();
                this.link.href = cssURL;
            });
            
            this.app.assets.load(this.cssFiles[i]);
        }
    }
};

// CSSAtlasLoader.js
var CSSAtlasLoader = pc.createScript('cssAtlasLoader');

CSSAtlasLoader.attributes.add('sceneLoaderEntity', {
    type: 'entity',
    title: "Scene Loader",
    description: "Scene Loader entity"
});

CSSAtlasLoader.attributes.add('loadingScenes', {
    type: 'string',
    array: true,
    title: "Scene(s) to load with",
    description: "Scenes which we load these assets for"
});

CSSAtlasLoader.attributes.add('unloadingScenes', {
    type: 'string',
    array: true,
    title: "Scene(s) to unload for",
    description: "Scenes which we unload these assets for"
});


CSSAtlasLoader.attributes.add("mobileAtlas", {
    type: 'asset',
    title: "Mobile CSS & Atlas",
    array: true,
    description: "CSS atlas pair for mobile devices"
});

CSSAtlasLoader.attributes.add("tabletAtlas", {
    type: 'asset',
    title: "Tablet CSS & Atlas",
    array: true,
    description: "CSS atlas pair for tablet devices"
});





CSSAtlasLoader.prototype.initialize = function() {
    this.sceneLoader = this.sceneLoaderEntity.script.sceneLoader;
    
    var shouldLoad = false;
    for(var i = 0; i<this.loadingScenes.length; i++){
        var scene = this.loadingScenes[i] || LevelBundleScene[this.loadingScenes[i]];
        if(DoesArrayContain(SceneLoader.scenesToLoad, scene)){
            this.sceneLoader.AddAssetLoader(this);
            shouldLoad = true;
            break;
        }
    }
    
    
    if(!shouldLoad){
        return;
    }

    this.allAssetsToLoad = [];
    this.allAssetsToLoadCount = 0;
    
    
    var platform = Device.Instance().GetButtonSize();
    platform = platform.substring(0, platform.length - 1);
    var atlasPair = this[platform + "Atlas"];
    
    var cssFile = atlasPair[0];
    var atlasFile = atlasPair[1];
    
    if (!cssFile.styleApplied) {
        cssFile.styleApplied = true;
        
        var atlasURL = atlasFile.getFileUrl();
        var stylesheet = cssFile.resource.replace(new RegExp(atlasFile.name, 'g'), atlasURL);
        style = pc.createStyle(stylesheet || '');
        document.head.appendChild(style);

        cssFile.on('load', function() {
            var atlasURL = atlasFile.getFileUrl();
            var stylesheet = this.resource.replace(new RegExp(atlasFile.name, 'g'), atlasURL);
            style.innerHTML = stylesheet;
        });
        
        this.allAssetsToLoad.push(cssFile);
        this.allAssetsToLoad.push(atlasFile);
        this.allAssetsToLoadCount += 2;
    }
    
    //Load array of assets
    for(var i = 0; i<this.allAssetsToLoad.length; i++){
        if(!this.allAssetsToLoad[i].loaded){
            this.app.assets.load(this.allAssetsToLoad[i]);
            
        }
    }
    
    GameManager.Instance.AddAssetBundle(this.allAssetsToLoad, this.unloadingScenes, this.entity.name);
};


// ScaleManager.js
var ScaleManager = pc.createScript('scaleManager');

ScaleManager.Instance = null;

ScaleManager.Orientation = {
    Landscape: 0,
    Portrait: 1
};

// initialize code called once per entity
ScaleManager.prototype.initialize = function() {
    
    ScaleManager.Instance = this;
    
    this.orientation = ScaleManager.Orientation.Landscape;
    
    this.canvas = document.getElementById("application-canvas");
    
    this.canvas.addEventListener('touchstart', function(e) {
        e.preventDefault();
     });
    
    
    this.dimensions = new pc.Vec2();
    this.screenSize = new pc.Vec2();
 
    this.defaultWidth = 960;
    this.defaultHeight = 720;
    this.maxWidth = 1800;//960;
    
    this.isDesktop = Device.Instance().desktop;
    
    this.resolutionScale = this.isDesktop ? 1 : 1;
    
    this.screenAspectRatio = 1; //Actual screen aspect ratio
    this.aspectRatio = 1; //Final aspect ratio for game
    this.minAspectRatio = this.defaultWidth / this.defaultHeight;
    this.maxAspectRatio = this.maxWidth / this.defaultHeight;

    this.outOfAspectRatioBounds = false;
    this.maxHeight = this.defaultHeight;
       
    window.addEventListener("resize", function(){
        this.OnScreenResize();
        this.app.fire("resize");   
    }.bind(this), true);
    
    this.Resize();
    
    
    
    if(this.isDesktop || Device.Instance().deviceQuality == DeviceQuality.lowEndDevice){
        this.app.graphicsDevice.maxPixelRatio = 1;
    }
    
    //Prevent iOS 10 from zooming in on double tap
    var lastTouchEnd = 0;
    document.addEventListener('touchend', function (event) {
      var now = (new Date()).getTime();
      if (now - lastTouchEnd <= 300) {
        event.preventDefault();
      }
      lastTouchEnd = now;
    }, false);
};

// update code called every frame
ScaleManager.prototype.update = function(dt) {

};

ScaleManager.prototype.CalculateScreenDimensions = function()
{  
    var devicePixelRatio = GetDevicePixelRatio();
    
    var windowWidth = window.innerWidth * devicePixelRatio;
    var windowHeight = window.innerHeight * devicePixelRatio;    
    
    var actualHeight = windowHeight;
    var actualWidth = windowWidth;
    
    this.screenAspectRatio = actualWidth / actualHeight;
    
    this.aspectRatio = pc.math.clamp(this.screenAspectRatio, this.minAspectRatio, this.maxAspectRatio);


    this.dimensions.set(actualHeight * this.aspectRatio, actualHeight);
};

ScaleManager.prototype.OnScreenResize = function() {
    ScaleManager.Instance.Resize();
};

ScaleManager.prototype.Resize = function() {
    this.CalculateScreenDimensions();

    this.app.setCanvasResolution(pc.RESOLUTION_FIXED,this.dimensions.x * this.resolutionScale,this.dimensions.y * this.resolutionScale);
    
    var fillMode = pc.FILLMODE_KEEP_ASPECT;
    this.app.setCanvasFillMode(fillMode);
    
    
    this.canvas.style.marginTop = "auto";
    this.canvas.style.marginLeft = "auto";
    this.canvas.style.marginRight = "auto";
    this.canvas.style.marginBottom = "auto";
    
    var verticalPadding = window.innerHeight - parseInt(getComputedStyle(ScaleManager.Instance.canvas).height);
    this.screenSize.set((this.defaultHeight + verticalPadding) * this.screenAspectRatio, this.defaultHeight + verticalPadding);
    //this.canvasSize.set(parseInt(getComputedStyle(ScaleManager.Instance.canvas).width), parseInt(getComputedStyle(ScaleManager.Instance.canvas).height));
};

// MPStateMachine.js
MPStateMachine = function() {

	MPState = function() {
		this.UpdateMethod = MPStateMachine.prototype.EmptyMethod;
		this.LateUpdateMethod = MPStateMachine.prototype.EmptyMethod;
		this.FixedUpdateMethod = MPStateMachine.prototype.EmptyMethod;
		this.EnterStateMethod = MPStateMachine.prototype.EmptyMethod;
		this.ExitStateMethod = MPStateMachine.prototype.EmptyMethod;
	};

	this.state = new MPState();
	this.stateStack = [];
	this.lastState = null;
};

MPStateMachine.prototype.CurrentState = function() {
    return this.state.currentState;
};

MPStateMachine.prototype.LastState = function() {
    return this.lastState;
};

MPStateMachine.prototype.EmptyMethod = function() {
};

MPStateMachine.prototype.SetState = function(newState, config) {
	if (config === undefined) config = {};
    if(config.addToStack === undefined) config.addToStack = true;
    
	if (this.state.currentState && this.state.currentState == newState) {
		return;
	}

	this.state.ExitStateMethod();
	this.lastState = this.state.currentState;
    
	this.state.currentState = newState;
	this.InitialiseState();
    

	this.state.EnterStateMethod(newState, config);

	if (config.addToStack === true) {
		this.AddToStateStack(this.state.currentState);
	}
};

MPStateMachine.prototype.InitialiseState = function() {
	this.state.UpdateMethod = (this[this.state.currentState.toString() + "_Update"] || this.EmptyMethod).bind(this);
	this.state.LateUpdateMethod = (this[this.state.currentState.toString() + "_LateUpdate"] || this.EmptyMethod).bind(this);
	this.state.FixedUpdateMethod = (this[this.state.currentState.toString() + "_FixedUpdate"] || this.EmptyMethod).bind(this);
	this.state.EnterStateMethod = (this[this.state.currentState.toString() + "_EnterState"] || this.Default_EnterState).bind(this);
	this.state.ExitStateMethod = (this[this.state.currentState.toString() + "_ExitState"] || this.EmptyMethod).bind(this);
};

MPStateMachine.prototype.SetStateStackLength = function(length) {
    this.stateStack.length = Math.max(length, 2);
};

MPStateMachine.prototype.RollbackStateStack = function() {
	if ((this.stateStack[0] == this.state.currentState && !this.stateStack[1]) ||
		(this.stateStack[0] != this.state.currentState && !this.stateStack[0])) {
		return;
	}

	this.state.ExitStateMethod();
	this.lastState = this.state.currentState;

	if (this.stateStack[0] == this.state.currentState) {
		this.state.currentState = this.stateStack[1];
		this.RemoveFromStateStack(0);
	}
	else {
		this.state.currentState = this.stateStack[0];
	}

	this.InitialiseState();
	this.state.EnterStateMethod();
};

MPStateMachine.prototype.AddToStateStack = function(newState) {
	if (!newState) {
		return;
	}

	for (var i = this.stateStack.length - 1; i > 0; i--) {
		this.stateStack[i] = this.stateStack[i - 1];
	}

	this.stateStack[0] = newState;
};

MPStateMachine.prototype.RemoveFromStateStack = function(count) {	
    if (count <= 0) count = 1;
    
    for (var i = 0; i < this.stateStack.length; i++) {
        var newState = null;
        if (i + count < this.stateStack.length) {
            newState = this.stateStack[i + count];
        }
        else {
            newState = null;
        }
        
        this.stateStack[i] = newState;
    }
};

MPStateMachine.prototype.ClearStateStack = function() {
	for (var i = 0; i < this.stateStack.length; i++) {
		this.stateStack[i] = null;
	}
};

