// SceneLoader.js
var SceneLoader = pc.createScript('sceneLoader');

SceneLoader.attributes.add('chunkLoadingBarEntity', {type: 'entity'});


SceneLoader.scenesToLoad = null;
SceneLoader.scenesToStart = null;

SceneLoader.prototype.initialize = function() {    
    this.chunkLoadingBar = this.chunkLoadingBarEntity.script.chunkLoadingBar;
    
    this.loadingScene = false;
    this.scenesLoaded = [];
    
    this.rotationCount = 0;
    this.minRotatations = 3;
    this.loadEndWaitTime = 0.5;

    this.assetLoaders = [];
    this.loadedAssetCount = 0;
    this.totalAssetCount = 0;
    
    
    this.rootEntity = null;
    
    this.assetsToLoad = [];
    this.audioAssetsToLoad = [];
    
    this.isFirstUpdate = true;
};

SceneLoader.prototype.postInitialize = function() {
    this.chunkLoadingBar.SetLoadPercent(0);
    
    for(var i = 0; i<this.assetLoaders.length; i++){
        for(var j = 0; j<this.assetLoaders[i].assetsToLoad.length; j++){
            this.assetsToLoad[this.assetsToLoad.length] = this.assetLoaders[i].assetsToLoad[j];
        }
    }
    
    //Load assets
    for(var i = this.assetsToLoad.length - 1; i>=0; i--){
        if(!this.assetsToLoad[i]){
            //console.warn("Missing Asset on ", this.entity.name);
        }
        if(!this.assetsToLoad[i].loaded){
            this.LoadAsset(this.assetsToLoad[i], i);
        }
    }
    this.totalAssetCount = this.assetsToLoad.length + this.audioAssetsToLoad.length;
};

SceneLoader.prototype.LoadAsset = function(asset, index) {
    switch(asset.type){
        case "audio":{
            var key = asset.name;
            asset.key = key.replace(/\..+$/, '');
            AudioManager.Instance.LoadSoundAsset(asset);
            this.audioAssetsToLoad.push(asset);
            this.assetsToLoad.splice(index, 1);
            break;
        }
        default:{
            this.app.assets.load(asset);
            break;
        }
    }
    
};


SceneLoader.prototype.update = function(dt) {
    if(!this.entity.enabled) { return; }    
    
    var allAssetsLoaded = false;
    var assetCount = 0;
    var loadedAssetCount = 0;
    
    for(var i = this.assetsToLoad.length - 1; i >= 0; i--){
        if(this.assetsToLoad[i].loaded){
            
            this.assetsToLoad.splice(i, 1);
            
            //Don't count towards progress if assets are already in memory
            if(this.isFirstUpdate){
                this.totalAssetCount--;
            }
            else{
                this.loadedAssetCount++;
            }
            
        }
    }
    
    for(var i = this.audioAssetsToLoad.length - 1; i >= 0; i--){
        var isLoaded = AudioManager.Instance.HasSoundAssetLoaded(this.audioAssetsToLoad[i]);
        if(isLoaded){
            this.audioAssetsToLoad.splice(i, 1);
            
            //Don't count towards progress if assets are already in memory
            if(this.isFirstUpdate){
                this.totalAssetCount--;
            }
            else{
                this.loadedAssetCount++;
            }
        }
    }
    
    if(this.assetsToLoad.length === 0 && this.audioAssetsToLoad.length === 0){
        allAssetsLoaded = true;
    }
    
    var loadingPercent = this.totalAssetCount > 0 ? this.loadedAssetCount / this.totalAssetCount : 1;
    loadingPercent = Math.max(loadingPercent, 0.1);
    
    this.chunkLoadingBar.SetLoadPercent(allAssetsLoaded ? 1 : loadingPercent);
    
    
    if(window.innerWidth < window.innerHeight){
        this.loadEndWaitTime = 1;
    }
    
    if(!this.loadingScene && allAssetsLoaded){
        if(this.loadEndWaitTime > 0){
            this.loadEndWaitTime -= dt;
        }
        else{
            this.loadingScene = true;
            SceneManager.Instance.LoadScene(SceneLoader.scenesToStart[this.scenesLoaded.length],
                this.OnSceneLoaded, this, false, true);  
            
                      
        }
    }
    
    this.isFirstUpdate = false;
};

SceneLoader.prototype.AddAssetLoader = function(assetLoader) {
    this.assetLoaders[this.assetLoaders.length] = assetLoader;
};

SceneLoader.prototype.OnSceneLoaded = function(entity) {
    entity.enabled = false;
    
    this.scenesLoaded.push(entity);
    if(this.scenesLoaded.length >= SceneLoader.scenesToStart.length){
        for(var i = 0; i<this.scenesLoaded.length; i++){
            this.scenesLoaded[i].enabled = true;
        }
        
        this.app.fire("sceneLoaderComplete");
        this.entity.destroy();
    }
    else{
        SceneManager.Instance.LoadScene(SceneLoader.scenesToStart[this.scenesLoaded.length],
                this.OnSceneLoaded, this, false, true);  
    }
    
};


