// GameScene.js
var GameScene = pc.createScript('gameScene');

if (!MPScene)
      var MPScene = function() {};
GameScene.prototype = Object.create(MPScene.prototype);
GameScene.prototype.constructor = GameScene;

GameScene.State = Object.freeze({
    Tutorial:                   0,
    Game:                       1,
    Dead:                       2,
    GameOver:                   3,
    HitButton:                  4,
    GameComplete:               5
});

GameScene.levelID = "test";
GameScene.levelType = "campaign";

GameScene.attributes.add("tunnelManagerEntity", { type: 'entity' });
GameScene.attributes.add("playerEntity", { type: 'entity' });
GameScene.attributes.add("gameCameraEntity", { type: 'entity' });
GameScene.attributes.add("campaignGameOverPopupEntity", { type: 'entity' });
GameScene.attributes.add("endlessGameOverPopupEntity", { type: 'entity' });
GameScene.attributes.add("gameTutorialPopupEntity", { type: 'entity' });
GameScene.attributes.add("gameUIEntity", { type: 'entity' });
GameScene.attributes.add("pauseButtonEntity", { type: 'entity' });
GameScene.attributes.add("gameDataAsset", { type: 'asset', assetType: 'json' });

GameScene.prototype.initialize = function() {
    MPScene.prototype.initialize.call(this);   

    
    
    this.gameCamera = this.gameCameraEntity.script.gameCamera;
    this.tunnelManager = this.tunnelManagerEntity.script.tunnelManager;
    this.player = this.playerEntity.script.player;
    this.campaignGameOverPopup = this.campaignGameOverPopupEntity.script.campaignGameOverPopup;
    this.endlessGameOverPopup = this.endlessGameOverPopupEntity.script.endlessGameOverPopup;
    this.gameTutorialPopup = this.gameTutorialPopupEntity.script.gameTutorialPopup;
    this.gameUI = this.gameUIEntity.script.gameUI;
    
    var gameData = this.gameDataAsset.resource;
    this.levelsData = gameData.levels;
    this.levelData = null;

    for(var i = 0; i<this.levelsData.length; i++){
        if(this.levelsData[i].id == GameScene.levelID){
            this.levelData = this.levelsData[i][GameScene.levelType];
            break;
        }
    }
    
    this.isEndless = GameScene.levelType == "endless";
    
    this.state = null;
    
    this.hasPlayedBefore = false;
    this.enableGameUIOnEnable = false;
    
    this.gameCompleteTime = 0.75;
    this.gameCompleteTimer = 0;

    this.gameCompleteSceneTime = 2;
    this.gameCompleteSceneTimer = 0;
    
    this.pauseButton = this.pauseButtonEntity.script.MPDOMButton;
    this.pauseButton.on("click", this.Pause, this);
    
    this.debug = GameManager.Instance.config.debugMode;
    this.levelsSaveData = null;
    
    this.onWindowBlur = this.OnWindowBlur.bind(this);
    this.onWindowFocus = this.OnWindowFocus.bind(this);
    this.onVisibilityChange = this.OnVisibilityChange.bind(this);
    
    window.addEventListener("blur", this.onWindowBlur);
    window.addEventListener("focus", this.onWindowFocus);
    document.addEventListener("visibilitychange", this.onVisibilityChange); 
    
    this.LoadData(); 
};

GameScene.prototype.postInitialize = function() {
    MPScene.prototype.postInitialize.call(this);
    
    AudioManager.Instance.Play("music_game", Math.randomInt(0, 1) == 0 ? "music_ingame_01" : "music_ingame_02");
    
    if(!this.hasPlayedBefore){
        this.SetState(GameScene.State.Tutorial);
    }
    else{
        this.SetState(GameScene.State.Game);
    }
};

GameScene.prototype.OnSceneLoaded = function(data) {
    MPScene.prototype.OnSceneLoaded.call(this, data);
    
    this.player.invincible = data && data.invincible !== undefined ? data.invincible : false;
    
//     this.app.scene.fogStart = 5;
//     this.app.scene.fogEnd = 10;
};

GameScene.prototype.update = function(dt) {
    MPScene.prototype.update.call(this, dt);
    
    if(GameManager.Instance.IsPaused()) return;
    
    if(this.gameCompleteTimer > 0){
        this.gameCompleteTimer -= dt;
        
        if(this.gameCompleteTimer <= 0){
            this.SetState(GameScene.State.GameComplete);
        }
    }

    if(this.gameCompleteSceneTimer > 0){
        this.gameCompleteSceneTimer -= dt;
        
        if(this.gameCompleteSceneTimer <= 0){
            this.GoToGameCompleteScene();
        }
    }

};

GameScene.prototype.SetState = function(state) {
    
    var previousState = this.state;

    this.state = state;
    
    this.gameCamera.SetState(state);
    this.tunnelManager.SetState(state);
    this.player.SetState(state);
    
    switch(this.state){
        case GameScene.State.Tutorial:{
            this.OnEnterTutorialState();
            break;
        }
        case GameScene.State.Game:{
            this.OnEnterGameState();
            break;
        }
        case GameScene.State.Dead:{
            this.OnEnterDeadState();
            break;
        }
        case GameScene.State.GameOver:{
            this.OnEnterGameOverState();
            break;
        }
        case GameScene.State.HitButton:{
            this.OnEnterHitButtonState();
            break;
        }
        case GameScene.State.GameComplete:{
            this.OnEnterGameCompleteState();
            break;
        }
    }
};

GameScene.prototype.OnEnterTutorialState = function() {
    this.gameTutorialPopup.Show();
};


GameScene.prototype.OnEnterGameState = function() {
// this.gameCompletePopup.Show({unlockEndless: true, unlockNextLevel: true, nextLevelID: this.levelData.nextLevelID});
//     return;
    this.hasPlayedBefore = true;
    SaveDataManager.Instance.SetGameData("hasPlayedBefore", true);
    SaveDataManager.Instance.SaveToStorage();  

    this.levelStartID = MakeID();

    if(this.isEndless){
        Hydra.UpdateAccountData({data: { levelStartID: this.levelStartID }});
    }

    
    this.gameTutorialPopup.Hide();
    this.gameUI.Show();
};

GameScene.prototype.OnEnterDeadState = function() {

};

GameScene.prototype.OnEnterHitButtonState = function() {
    this.gameCompleteTimer = this.gameCompleteTime;

    AudioManager.Instance.StopAll("music_game");
};

GameScene.prototype.OnEnterGameOverState = function() {  
    AudioManager.Instance.StopAll("music_game");
    
    if(this.isEndless){
        var score = this.tunnelManager.distanceTravelled;

        var highscore = score;
        var oldHighscore = this.levelsSaveData[GameScene.levelID].endlessHighScore;
        if(oldHighscore != undefined && score < oldHighscore){
            highscore = oldHighscore;
        }
        
        this.levelsSaveData[GameScene.levelID].endlessHighScore = highscore;
        SaveDataManager.Instance.SetGameData("levels", this.levelsSaveData);
        SaveDataManager.Instance.SaveToStorage();

        this.endlessGameOverPopup.Show({score: score, highscore: highscore});
    }
    else{
        this.campaignGameOverPopup.Show();
    }

    this.gameUI.Hide();
};

GameScene.prototype.OnEnterRobotDestructionCutsceneState = function() {
    this.gameUI.Hide();

    var isLastLevel = this.levelsData[this.levelsData.length - 1].id == GameScene.levelID;
    var showFinalCutscene = false;

    if(isLastLevel && !this.hasPlayedFinalCutscene){
        showFinalCutscene = true;
    }

    this.robotDestructionCutscene.Show({ showFinalCutscene: showFinalCutscene });
};

GameScene.prototype.OnEnterFinalCutsceneState = function() {
    this.gameUI.Hide();

    this.finalCutscene.Show();
};


GameScene.prototype.OnEnterGameCompleteState = function() {
    this.gameCompleteSceneTimer = this.gameCompleteSceneTime;    
};

GameScene.prototype.Enable = function() {
    MPScene.prototype.Enable.call(this);
    
    if(this.enableGameUIOnEnable){
        this.gameUIEntity.enabled =  true;
    }

    this.enableGameUIOnEnable = false;

    AudioManager.Instance.ResumeLayer("sfx_game");
    AudioManager.Instance.ResumeLayer("music_game");
};

GameScene.prototype.Pause = function() {
    MPScene.prototype.Pause.call(this);
    
    this.enableGameUIOnEnable = true;
    this.gameUIEntity.enabled = false;

    AudioManager.Instance.PauseLayer("sfx_game");
    AudioManager.Instance.PauseLayer("music_game");
};

GameScene.prototype.LoadData = function() {
    var hasPlayedBefore = SaveDataManager.Instance.GetGameData("hasPlayedBefore");
    
    if(hasPlayedBefore !== undefined){
        this.hasPlayedBefore = hasPlayedBefore;
    }
    
    this.levelsSaveData = SaveDataManager.Instance.GetGameData("levels");
    
    if(!this.levelsSaveData){
        this.levelsSaveData = {};
    }
    
    if(!this.levelsSaveData[GameScene.levelID]){
        this.levelsSaveData[GameScene.levelID] = {};
    }

};


GameScene.prototype.Reload = function() {
    this.unloadAssetBundlesOnDestroy = false;
    
    GameManager.Instance.ClearPauseLayers();
    SceneManager.Instance.state.currentState = null;
    this.app.root.children[this.app.root.children.length - 1].destroy();
    
    SceneManager.Instance.ClearStateStack();
    
    SceneManager.Instance.SetState("GameScene", {preload: false});
};

GameScene.prototype.Exit = function(justCompletedLevel) {
    SceneManager.Instance.ClearStateStack();
    SceneManager.Instance.SetState("LevelSelectScreen", {justCompletedLevel: justCompletedLevel});
    GameManager.Instance.ClearPauseLayers();
};

GameScene.prototype.GoToGameCompleteScene = function() {
    SceneManager.Instance.ClearStateStack();
    SceneManager.Instance.SetState("GameCompleteScene");
    GameManager.Instance.ClearPauseLayers();
};

GameScene.prototype.OnWindowBlur = function() {
    if(this.state == GameScene.State.Game && !GameManager.Instance.IsPaused() && !this.debug){
        this.Pause();
    }
};

GameScene.prototype.OnWindowFocus = function() {

};

GameScene.prototype.OnVisibilityChange = function() {
    if(document.hidden || document.msHidden || document.webkitHidden || document.visibilityState == 'hidden'){
        this.OnWindowBlur();
    }
    else{
        this.OnWindowFocus();
    }

};

GameScene.prototype.OnDestroy = function() {
    MPScene.prototype.OnDestroy.call(this);
    
    window.removeEventListener("blur", this.onWindowBlur);
    window.removeEventListener("focus", this.onWindowFocus);
    document.removeEventListener("visibilitychange", this.onVisibilityChange); 
};

// GELText.js
var HtmlText = pc.createScript('htmlText');

HtmlText.attributes.add('cameraEntity', {type: 'entity', title: 'Camera'});
HtmlText.attributes.add('gelPanelEntity', {type: 'entity', title: 'Gel Panel (Optional)', description: "Optional - Will use world space position to calculate left/top if not assigned"});
HtmlText.attributes.add('text', {type: 'string', title: 'Text'});
HtmlText.attributes.add('color', {type: 'rgb', title: 'Color'});
HtmlText.attributes.add('fontSize', {type: 'number', title: 'Font Size', default: 5});
HtmlText.attributes.add('fontFace', {type: 'string', title: 'Font Family', default: "Arial"});
HtmlText.attributes.add('textAlign', {type: 'string', title: 'Text Align', default: 'center', 
enum: [
    { 'left': 'left'},
    { 'center': 'center'},
    { 'right': 'right'}
]});
HtmlText.attributes.add('textAnchor', {type: 'string', title: 'Anchor', default: 'center', 
enum: [
    { 'topLeft': 'topLeft'},
    { 'left': 'left'},
    { 'bottomLeft': 'bottomLeft'},
    { 'topcenter': 'topcenter'},
    { 'center': 'center'},
    { 'bottomcenter': 'bottomcenter'},
    { 'topright': 'topright'},
    { 'right': 'right'},
    { 'bottomright': 'bottomright'}
]});
HtmlText.attributes.add('staticWidth', {type: 'string', title: 'Static Width (px)', default: "none", description: "Forced Static Width in pixels, based on a canvas height of 1000px (will auto scale). Use for auto line breaking."});
HtmlText.attributes.add('lineHeight', {type: 'string', title: 'Style - Line Height (px)', default: "normal"});
HtmlText.attributes.add('shadow', {type: 'string', title: 'Style - Shadow', default: "none"});
HtmlText.attributes.add('textDecoration', {type: 'string', title: 'Style - Text Decoration', default: "none"});
HtmlText.attributes.add('textTransform', {type: 'string', title: 'Style - Text Transform', default: "none"});

// initialize code called once per entity
HtmlText.prototype.initialize = function() {
    // create DIV element
    this.element = document.createElement('div');
    this.element.className = 'textContainer';
    
    this.pixelPos = new pc.Vec2();
    this.anchor = new pc.Vec2(-50,-50);

    this.SetColour(this.color);
    this.SetText(this.text);
    this.SetTextAlign(this.textAlign);
    this.SetFontSize(this.fontSize);
    this.SetFontFace(this.fontFace); 
    this.SetTextAnchor(this.textAnchor);
    if(this.staticWidth !== "none" || this.width){
        this.SetWidth(this.staticWidth);
    }
    if(this.lineHeight !== "normal"){
        this.SetLineHeight(this.lineHeight);
    }
    if(this.shadow !== "none"){
        this.SetShadow(this.shadow);
    }
    if(this.textDecoration !== "none"){
        this.SetTextDecoration(this.textDecoration);
    }
    if(this.textTransform !== "none"){
        this.SetTextTransform(this.textTransform);
    }
    
    //Appending
    if(this.gelPanelEntity !== null){
        this.gelPanelEntity.script.gelPanel.panelElement.appendChild(this.element);
        //Fill panel
        this.element.style.top = "0%";
        this.element.style.width = "100%";
        this.element.style.height = "100%";
    }
    else{
        MPDOMManager.Instance.AppendToRoot(this.element); 
        //Set position
        this.PositionWorldToScreen();
    }
    
    
    //Events
    this.app.on("resize", this.OnScreenResize, this);
    this.on("state", function (enabled) {
        if (enabled) {
            this.Show();
        } else {
            this.Hide();
        }
    }, this);
    
    this.on("destroy", this.OnDestroy);
};

// update code called every frame
HtmlText.prototype.postUpdate = function(dt) {
};

HtmlText.prototype.Show = function() {
    if (!this.gelPanelEntity) {
        this.element.style.visibility = 'visible';
    }
};

HtmlText.prototype.Hide = function() {
    if (!this.gelPanelEntity) {
        this.element.style.visibility = 'hidden';
    }
};

HtmlText.prototype.PositionWorldToScreen = function() {
    var camera = this.cameraEntity ? this.cameraEntity.camera : this.app.root.findByName("Camera").camera;
    
    if(true){
        var screenPosition = camera.worldToScreen(this.entity.getPosition());

        var canvas = document.getElementById("application-canvas");
        var bounds = canvas.getBoundingClientRect();
        var canvasHeight = bounds.bottom - bounds.top;

        this.pixelPos.set(screenPosition.x, screenPosition.y);
        this.element.style.left = bounds.left + this.pixelPos.x + 'px';
        this.element.style.top =  bounds.top + this.pixelPos.y + 'px';
        
        if(this.width){
            var pixelWidth = parseInt(this.staticWidth);            
            this.SetWidth((pixelWidth * (canvasHeight / 900)) + "px");
        }
    }
    
};

HtmlText.prototype.SetText = function(newText) {
    if(!this.initialText){
        this.initialText = this.text;
    }
    this.text = newText;
    if(this.element)
        this.element.innerHTML = newText; 
};

HtmlText.prototype.AppendText = function(appendText) {
    this.SetText(this.text + appendText);
};

HtmlText.prototype.PrependText = function(prependText) {
    this.SetText(prependText + this.text);
};

HtmlText.prototype.ResetText = function() {
    if(this.initialText){
        this.SetText(this.initialText);
    }
};

HtmlText.prototype.SetTextAlign = function(newAlign) {
    this.textAlign = newAlign;   
    if(this.element)
        this.element.style.textAlign = newAlign;
};

HtmlText.prototype.SetTextAnchor = function(newAnchor) {    
    switch(newAnchor){
        case 'topLeft':{
            this.anchor.set(0, 0);
            break;
        }
        case 'left':{
            this.anchor.set(0, -50);
            break;
        }
        case 'bottomLeft':{
            this.anchor.set(0, -100);
            break;
        }
        case 'topcenter':{
            this.anchor.set(-50, 0);
            break;
        }
        case 'center':{
            this.anchor.set(-50, -50);
            break;
        }
        case 'bottomcenter':{
            this.anchor.set(-50, -100);
            break;
        }
        case 'topright':{
            this.anchor.set(-100, 0);
            break;
        }
        case 'right':{
            this.anchor.set(-100, -50);
            break;
        }
        case 'bottomright':{
            this.anchor.set(-100, -100);
            break;
        }
    }
    
    if(this.element){
        this.element.style.transform = "translate(" + this.anchor.x + "%" + "," + this.anchor.y + "%)";
    }     
};

HtmlText.prototype.SetLineHeight = function(lineHeight) {
    this.lineHeight = lineHeight;
    if(this.element)
        this.element.style.lineHeight = lineHeight;
};

HtmlText.prototype.SetWidth = function(width) {
    this.width = width;

    if(this.element){
        this.element.style.width = width;
        this.element.style.whiteSpace = "initial"; //Allow line wrapping
    }
        
};


HtmlText.prototype.SetColour = function(newColour) {
    this.color = newColour;
    var hex = this.color.toString();
    if(this.element)
        this.element.style.color = hex;
};

HtmlText.prototype.SetFontSize = function(fontSize) {
    this.fontSize = fontSize;
    if(this.element)
        this.element.style.fontSize = fontSize + 'vh';
};

HtmlText.prototype.SetFontFace = function(face) {
    this.fontFace = face;
    if(this.element)
        this.element.style.fontFamily = face;
};

HtmlText.prototype.SetShadow = function(shadow) {
    this.shadow = shadow;
    if(this.element)
        this.element.style.textShadow = shadow;
};

HtmlText.prototype.SetTextDecoration = function(newDecoration) {
    this.textDecoration = newDecoration;
    if(this.element)
        this.element.style.textDecoration = newDecoration; 
};

HtmlText.prototype.SetTextTransform = function(newTransform) {
    this.textTransform = newTransform;
    if(this.element)
        this.element.style.textTransform = newTransform; 
};

HtmlText.prototype.OnScreenResize = function() {
    setTimeout(this.PositionWorldToScreen.bind(this), 10);
};

HtmlText.prototype.OnDestroy = function() {    
    this.element.parentNode.removeChild(this.element);
    this.element = null;
    this.app.off("resize", this.OnScreenResize, this);
    this.off();
};

// PhysicsManager.js
var PhysicsManager = pc.createScript('physicsManager');

PhysicsManager.Instance = null;

// initialize code called once per entity
PhysicsManager.prototype.initialize = function() {
    PhysicsManager.Instance = this;
    this.p2World = this.entity.script.p2World;
    
    this.triggersWithContactEquations = [];
    
    this.raycastResult = new p2.RaycastResult();
    this.rayClosest = new p2.Ray({
        mode: p2.Ray.CLOSEST
    });
    
    this.debugStart = new pc.Vec3(0, 0, 0);
    this.debugEnd = new pc.Vec3(100, 0, 0);
    this.debugColor = new pc.Color(1, 0, 0);
    this.debugColor2 = new pc.Color(0, 1, 0);
    
    
};
    
PhysicsManager.prototype.postInitialize = function() {
    this.world = this.p2World.world;
    //this.world.on("preSolve", this.PreSolve, this);
};

//Clear collisions with this body - acts as sensor, while still allowing us to read contactEquations
PhysicsManager.prototype.PreSolve = function(e) {
    for(var i=0; i<e.contactEquations.length; i++){
        var c = e.contactEquations[i];
        if(!c.shapeA.solidTrigger && !c.shapeB.solidTrigger){
            for(var j = 0; j<this.triggersWithContactEquations.length; j++){
                if(c.shapeA == this.triggersWithContactEquations[j] || c.shapeB == this.triggersWithContactEquations[j]){
                    c.enabled = false;
                    break;
                }
            }
        }
        
    }
    for(var i=0; i<e.frictionEquations.length; i++){
        
        var c = e.frictionEquations[i];
        if(!c.shapeA.solidTrigger && !c.shapeB.solidTrigger){
            for(var j = 0; j<this.triggersWithContactEquations.length; j++){
                if(c.shapeA == this.triggersWithContactEquations[j] || c.shapeB == this.triggersWithContactEquations[j]){
                    c.enabled = false;
                    break;
                }
            }
        }
    }
    
    
};


// update code called every frame
PhysicsManager.prototype.update = function(dt) {

};

PhysicsManager.prototype.AddTriggerShapeWithContactEquations = function(shape) {
    this.triggersWithContactEquations.push(shape);
};

PhysicsManager.prototype.RemoveTriggerShapeWithContactEquations = function(shape) {
    var index = this.triggersWithContactEquations.indexOf(shape);
    if(index !== -1){ 
        this.triggersWithContactEquations.splice(index, 1);
    }
};

PhysicsManager.prototype.Raycast = function(from, to, group) {
    p2.vec2.copy(this.rayClosest.from, [from.x, -from.y]);
    p2.vec2.copy(this.rayClosest.to, [to.x, -to.y]);
    
    this.rayClosest.collisionGroup = group !== undefined ? parseInt(group, 2) : -1;
    this.rayClosest.collisionMask = this.rayClosest.collisionGroup;
    this.rayClosest.update();
    
    
    this.raycastResult.reset();
    this.world.raycast(this.raycastResult, this.rayClosest);
    
    if(GameManager.Instance.config.debugMode && this.p2World.debugDraw){
        this.debugStart.set(from.x, 0, from.y);
        this.debugEnd.set(to.x, 0, to.y);
        pc.app.renderLine(this.debugStart, this.debugEnd, this.debugColor);
        
        if(this.raycastResult.hasHit()){
            var hitPoint = [];
            this.raycastResult.getHitPoint(hitPoint, this.rayClosest);
            this.debugEnd.set(hitPoint[0], 0, -hitPoint[1]);
            pc.app.renderLine(this.debugStart, this.debugEnd, this.debugColor2);
            //console.log(this.raycastResult.body.entity.name)
        }
        
    }
    return this.raycastResult;
};


PhysicsManager.prototype.Pause = function() {
    this.p2World.paused = true;
};

PhysicsManager.prototype.Resume = function() {
    this.p2World.paused = false;
};
