// Tween.js
pc.extend(pc, function () {

    /**
     * @name pc.TweenManager
     * @description Handles updating tweens
     * @param {pc.Application} app  The application
     */
    var TweenManager = function (app) {
        this._app = app;
        this._tweens = [];
        this._add = []; // to be added
    };

    TweenManager.prototype = {
        add: function (tween) {
            this._add.push(tween);
            return tween;
        },

        update: function (dt) {
            var i = 0;
            var n = this._tweens.length;
            while (i < n) {
                if (this._tweens[i].update(dt)) {
                    i++;
                } else {
                    this._tweens.splice(i, 1);
                    n--;
                }
            }

            // add any tweens that were added mid-update
            if (this._add.length) {
                this._tweens = this._tweens.concat(this._add);
                this._add.length = 0;
            }
        }
    };

    /**
     * @name  pc.Tween
     * @param {Object} target The target property that will be tweened
     * @param {pc.TweenManager} manager The tween manager
     * @param {pc.Entity} entity The pc.Entity whose property we are tweening
     */
    var Tween = function (target, manager, entity) {
        pc.events.attach(this);

        this.manager = manager;

        if (entity) {
            this.entity = null; // if present the tween will dirty the transforms after modify the target
        }

        this.time = 0;

        this.complete = false;
        this.playing = false;
        this.stopped = true;
        this.pending = false;
        this.pausable = true;

        this.target = target;

        this.duration = 0;
        this._currentDelay = 0;
        this.timeScale = 1;
        this._reverse = false;

        this._delay = 0;
        this._yoyo = false;

        this._count = 0;
        this._numRepeats = 0;
        this._repeatDelay = 0;

        this._from = false; // indicates a "from" tween

        // for rotation tween
        this._slerp = false; // indicates a rotation tween
        this._fromQuat = new pc.Quat();
        this._toQuat = new pc.Quat();
        this._quat = new pc.Quat();

        this.easing = pc.EASE_LINEAR;

        this._sv = {}; // start values
        this._ev = {}; // end values
    };

    Tween.prototype = {
        // properties - js obj of values to update in target
        to: function (properties, duration, easing, delay, repeat, yoyo) {
            if (properties instanceof pc.Vec3) {
                this._properties = {
                    x: properties.x,
                    y: properties.y,
                    z: properties.z
                };
            } else if (properties instanceof pc.Color) {
                this._properties = {
                    r: properties.r,
                    g: properties.g,
                    b: properties.b,
                };
                if (properties.a !== undefined) {
                    this._properties.a = properties.a;
                }
            } else {
                this._properties = properties;
            }

            this.duration = duration;

            if (easing) this.easing = easing;
            if (delay) {
                this.delay(delay);
            }
            if (repeat) {
                this.repeat(repeat);
            }

            if (yoyo) {
                this.yoyo(yoyo);
            }

            return this;
        },

        from: function (properties, duration, easing, delay, repeat, yoyo) {
            if (properties instanceof pc.Vec3) {
                this._properties = {
                    x: properties.x,
                    y: properties.y,
                    z: properties.z
                };
            } else if (properties instanceof pc.Color) {
                this._properties = {
                    r: properties.r,
                    g: properties.g,
                    b: properties.b,
                };
                if (properties.a !== undefined) {
                    this._properties.a = properties.a;
                }
            } else {
                this._properties = properties;
            }

            this.duration = duration;

            if (easing) this.easing = easing;
            if (delay) {
                this.delay(delay);
            }
            if (repeat) {
                this.repeat(repeat);
            }

            if (yoyo) {
                this.yoyo(yoyo);
            }

            this._from = true;

            return this;
        },

        rotate: function (properties, duration, easing, delay, repeat, yoyo) {
            if (properties instanceof pc.Quat) {
                this._properties = {
                    x: properties.x,
                    y: properties.y,
                    z: properties.z,
                    w: properties.w
                };
            } else if (properties instanceof pc.Vec3) {
                this._properties = {
                    x: properties.x,
                    y: properties.y,
                    z: properties.z
                };
            } else if (properties instanceof pc.Color) {
                this._properties = {
                    r: properties.r,
                    g: properties.g,
                    b: properties.b,
                };
                if (properties.a !== undefined) {
                    this._properties.a = properties.a;
                }
            } else {
                this._properties = properties;
            }

            this.duration = duration;

            if (easing) this.easing = easing;
            if (delay) {
                this.delay(delay);
            }
            if (repeat) {
                this.repeat(repeat);
            }

            if (yoyo) {
                this.yoyo(yoyo);
            }

            this._slerp = true;

            return this;
        },

        start: function () {
            this.firstUpdate = true;
            this.playing = true;
            this.complete = false;
            this.stopped = false;
            this._count = 0;
            this.pending = (this._delay > 0);

            if (this._reverse && !this.pending) {
                this.time = this.duration;
            } else {
                this.time = 0;
            }

            if (this._from) {
                for (var prop in this._properties) {
                    this._sv[prop] = this._properties[prop];
                    this._ev[prop] = this.target[prop];
                }

                if (this._slerp) {
                    this._toQuat.setFromEulerAngles(this.target.x, this.target.y, this.target.z);

                    var _x = this._properties.x !== undefined ? this._properties.x : this.target.x;
                    var _y = this._properties.y !== undefined ? this._properties.y : this.target.y;
                    var _z = this._properties.z !== undefined ? this._properties.z : this.target.z;
                    this._fromQuat.setFromEulerAngles(_x, _y, _z);
                }
            } else {
                for (var prop in this._properties) {
                    this._sv[prop] = this.target[prop];
                    this._ev[prop] = this._properties[prop];
                }

                if (this._slerp) {
                    this._fromQuat.setFromEulerAngles(this.target.x, this.target.y, this.target.z);

                    var _x = this._properties.x !== undefined ? this._properties.x : this.target.x;
                    var _y = this._properties.y !== undefined ? this._properties.y : this.target.y;
                    var _z = this._properties.z !== undefined ? this._properties.z : this.target.z;
                    this._toQuat.setFromEulerAngles(_x, _y, _z);
                }
            }

            // set delay
            this._currentDelay = this._delay;

            // add to manager when started
            this.manager.add(this);

            return this;
        },

        pause: function () {
            this.playing = false;
        },

        resume: function () {
            this.playing = true;
        },

        stop: function () {
            this.playing = false;
            this.stopped = true;
        },

        delay: function (delay) {
            this._delay = delay;
            this.pending = true;

            return this;
        },

        repeat: function (num, delay) {
            this._count = 0;
            this._numRepeats = num;
            if (delay) {
                this._repeatDelay = delay;
            } else {
                this._repeatDelay = 0;
            }

            return this;
        },

        loop: function (loop) {
            if (loop) {
                this._count = 0;
                this._numRepeats = Infinity;
            } else {
                this._numRepeats = 0;
            }

            return this;
        },

        yoyo: function (yoyo) {

            this._yoyo = yoyo;
            return this;
        },

        reverse: function () {
            this._reverse = !this._reverse;

            return this;
        },

        chain: function () {
            var n = arguments.length;

            while(n--) {
                if (n > 0) {
                    arguments[n-1]._chained = arguments[n];
                } else {
                    this._chained = arguments[n];
                }
            }

            return this;
        },

        update: function (dt) {
            if (this.stopped) return false;

            if (!this.playing) return true;
            
            this.timeScale = this.pausable ? GameManager.Instance.timeScale : 1;

            if (!this._reverse || this.pending) {
                this.time += dt*this.timeScale;
            } else {
                this.time -= dt*this.timeScale;
            }

            
            // delay start if required
            var wasPending = this.pending;
            if (this.pending) {
                if (this.time > this._currentDelay) {
                    if (this._reverse) {
                        this.time = this.duration - (this.time - this._currentDelay);
                    } else {
                        this.time = this.time - this._currentDelay;
                    }
                    this.pending = false;
                } else {
                    return true;
                }
            }
            
            if(this.firstUpdate){
                this.firstUpdate = false;
                this.fire("start");
            }

            var _extra = 0;
            if ((!this._reverse && this.time > this.duration) || (this._reverse && this.time < 0)){
                this._count++;
                this.complete = true;
                this.playing = false;
                if (this._reverse) {
                    _extra = this.duration - this.time;
                    this.time = 0;
                } else {
                    _extra = this.time - this.duration;
                    this.time = this.duration;
                }
            }

            var elapsed = this.time / this.duration;

            // run easing
            var a = this.easing(elapsed);

            // increment property
            var s,e,d;
            for (var prop in this._properties) {
                s = this._sv[prop];
                e = this._ev[prop];

                this.target[prop] = s + (e - s) * a;
            }

            if (this._slerp) {
                this._quat.slerp(this._fromQuat, this._toQuat, a);
            }

            // if this is a entity property then we should dirty the transform
            if (this.entity) {
                this.entity._dirtifyLocal();
                if (this._slerp) {
                    this.entity.setLocalRotation(this._quat);
                }
            }

            this.fire("update", dt);

            if (this.complete) {
                var repeat = this._repeat(_extra);
                if (!repeat) {
                    this.fire("complete", _extra);
                    if (this._chained) this._chained.start();
                } else {
                    this.fire("loop");
                }

                return repeat;
            }

            return true;
        },

        _repeat: function (extra) {
            
            // test for repeat conditions
            if (this._count < this._numRepeats) {
                // do a repeat
                if (this._reverse) {
                    this.time = this.duration - extra;
                } else {
                    this.time = extra; // include overspill time
                }
                this.complete = false;
                this.playing = true;

                this._currentDelay = this._repeatDelay;
                this.pending = true;

                if (this._yoyo) {
                    // swap start/end properties
                    for (var prop in this._properties) {
                        tmp = this._sv[prop];
                        this._sv[prop] = this._ev[prop];
                        this._ev[prop] = tmp;
                    }

                    if (this._slerp) {
                        this._quat.copy(this._fromQuat);
                        this._fromQuat.copy(this._toQuat);
                        this._toQuat.copy(this._quat);
                    }
                }

                return true;
            }
            return false;
        },

    };


    /**
     * Easing methods
     */

    var Linear = function (k) {
        return k;
    };

    var QuadraticIn = function (k) {
        return k * k;
    };

    var QuadraticOut = function (k) {
        return k * (2 - k);
    };

    var QuadraticInOut = function (k) {
        if ((k *= 2) < 1) {
            return 0.5 * k * k;
        }
        return -0.5 * (--k * (k - 2) - 1);
    };

    var CubicIn = function (k) {
        return k * k * k;
    };

    var CubicOut = function (k) {
        return --k * k * k + 1;
    };

    var CubicInOut = function (k) {
        if ( ( k *= 2 ) < 1 ) return 0.5 * k * k * k;
        return 0.5 * ( ( k -= 2 ) * k * k + 2 );
    };

    var QuarticIn = function (k) {
            return k * k * k * k;
    };

    var QuarticOut = function (k) {
        return 1 - ( --k * k * k * k );
    };

    var QuarticInOut = function (k) {
        if ( ( k *= 2 ) < 1) return 0.5 * k * k * k * k;
        return - 0.5 * ( ( k -= 2 ) * k * k * k - 2 );
    };

    var QuinticIn = function (k) {
            return k * k * k * k * k;
    };

    var QuinticOut = function (k) {
            return --k * k * k * k * k + 1;
    };

    var QuinticInOut = function (k) {
        if ( ( k *= 2 ) < 1 ) return 0.5 * k * k * k * k * k;
        return 0.5 * ( ( k -= 2 ) * k * k * k * k + 2 );
    };

    var SineIn = function (k) {
        if (k === 0) return 0;
        if (k === 1) return 1;
        return 1 - Math.cos( k * Math.PI / 2 );
    };

    var SineOut = function (k) {
        if (k === 0) return 0;
        if (k === 1) return 1;
        return Math.sin( k * Math.PI / 2 );
    };

    var SineInOut = function (k) {
        if (k === 0) return 0;
        if (k === 1) return 1;
        return 0.5 * ( 1 - Math.cos( Math.PI * k ) );
    };

    var ExponentialIn = function (k) {
        return k === 0 ? 0 : Math.pow( 1024, k - 1 );
    };

    var ExponentialOut = function (k) {
        return k === 1 ? 1 : 1 - Math.pow( 2, - 10 * k );
    };

    var ExponentialInOut = function (k) {
        if ( k === 0 ) return 0;
        if ( k === 1 ) return 1;
        if ( ( k *= 2 ) < 1 ) return 0.5 * Math.pow( 1024, k - 1 );
        return 0.5 * ( - Math.pow( 2, - 10 * ( k - 1 ) ) + 2 );
    };

    var CircularIn = function (k) {
        return 1 - Math.sqrt( 1 - k * k );
    };

    var CircularOut = function (k) {
        return Math.sqrt( 1 - ( --k * k ) );
    };

    var CircularInOut = function (k) {
        if ( ( k *= 2 ) < 1) return - 0.5 * ( Math.sqrt( 1 - k * k) - 1);
        return 0.5 * ( Math.sqrt( 1 - ( k -= 2) * k) + 1);
    };

    var ElasticIn = function (k) {
        var s, a = 0.1, p = 0.4;
        if ( k === 0 ) return 0;
        if ( k === 1 ) return 1;
        if ( !a || a < 1 ) { a = 1; s = p / 4; }
        else s = p * Math.asin( 1 / a ) / ( 2 * Math.PI );
        return - ( a * Math.pow( 2, 10 * ( k -= 1 ) ) * Math.sin( ( k - s ) * ( 2 * Math.PI ) / p ) );
    };

    var ElasticOut = function (k) {
        var s, a = 0.1, p = 0.4;
        if ( k === 0 ) return 0;
        if ( k === 1 ) return 1;
        if ( !a || a < 1 ) { a = 1; s = p / 4; }
        else s = p * Math.asin( 1 / a ) / ( 2 * Math.PI );
        return ( a * Math.pow( 2, - 10 * k) * Math.sin( ( k - s ) * ( 2 * Math.PI ) / p ) + 1 );
    };

    var ElasticInOut = function (k) {
        var s, a = 0.1, p = 0.4;
        if ( k === 0 ) return 0;
        if ( k === 1 ) return 1;
        if ( !a || a < 1 ) { a = 1; s = p / 4; }
        else s = p * Math.asin( 1 / a ) / ( 2 * Math.PI );
        if ( ( k *= 2 ) < 1 ) return - 0.5 * ( a * Math.pow( 2, 10 * ( k -= 1 ) ) * Math.sin( ( k - s ) * ( 2 * Math.PI ) / p ) );
        return a * Math.pow( 2, -10 * ( k -= 1 ) ) * Math.sin( ( k - s ) * ( 2 * Math.PI ) / p ) * 0.5 + 1;
    };

    var BackIn = function (k) {
            var s = 1.70158;
            return k * k * ( ( s + 1 ) * k - s );
    };

    var BackOut = function (k) {
        var s = 1.70158;
        return --k * k * ( ( s + 1 ) * k + s ) + 1;
    };

    var BackInOut = function (k) {
        var s = 1.70158 * 1.525;
        if ( ( k *= 2 ) < 1 ) return 0.5 * ( k * k * ( ( s + 1 ) * k - s ) );
        return 0.5 * ( ( k -= 2 ) * k * ( ( s + 1 ) * k + s ) + 2 );
    };

    var BounceIn = function (k) {
        return 1 - BounceOut( 1 - k );
    };

    var BounceOut = function (k) {
        if ( k < ( 1 / 2.75 ) ) {
            return 7.5625 * k * k;
        } else if ( k < ( 2 / 2.75 ) ) {
            return 7.5625 * ( k -= ( 1.5 / 2.75 ) ) * k + 0.75;
        } else if ( k < ( 2.5 / 2.75 ) ) {
            return 7.5625 * ( k -= ( 2.25 / 2.75 ) ) * k + 0.9375;
        } else {
            return 7.5625 * ( k -= ( 2.625 / 2.75 ) ) * k + 0.984375;
        }
    };

    var BounceInOut = function (k) {
        if ( k < 0.5 ) return BounceIn( k * 2 ) * 0.5;
        return BounceOut( k * 2 - 1 ) * 0.5 + 0.5;
    };

    return {
        TweenManager: TweenManager,
        Tween: Tween,
        Linear: Linear,
        QuadraticIn: QuadraticIn,
        QuadraticOut: QuadraticOut,
        QuadraticInOut: QuadraticInOut,
        CubicIn: CubicIn,
        CubicOut: CubicOut,
        CubicInOut: CubicInOut,
        QuarticIn: QuarticIn,
        QuarticOut: QuarticOut,
        QuarticInOut: QuarticInOut,
        QuinticIn: QuinticIn,
        QuinticOut: QuinticOut,
        QuinticInOut: QuinticInOut,
        SineIn: SineIn,
        SineOut: SineOut,
        SineInOut: SineInOut,
        ExponentialIn: ExponentialIn,
        ExponentialOut: ExponentialOut,
        ExponentialInOut: ExponentialInOut,
        CircularIn: CircularIn,
        CircularOut: CircularOut,
        CircularInOut: CircularInOut,
        BackIn: BackIn,
        BackOut: BackOut,
        BackInOut: BackInOut,
        BounceIn: BounceIn,
        BounceOut: BounceOut,
        BounceInOut: BounceInOut,
        ElasticIn: ElasticIn,
        ElasticOut: ElasticOut,
        ElasticInOut: ElasticInOut
    };
}());

// Create a default tween manager on the application
(function () {
    var application = pc.Application.getApplication();
    if (application) {
        // create tween manager and update it
        application._tweenManager = new pc.TweenManager(application);
        application.on("update", function (dt) {
            application._tweenManager.update(dt);
        });

        // Add pc.Application#tween method
        pc.Application.prototype.tween = function (target) {
            return new pc.Tween(target, this._tweenManager);
        };

        // Add pc.Entity#tween method
        pc.Entity.prototype.tween = function (target) {
            var tween = this._app.tween(target);
            tween.entity = this;
            
            this.on('destroy', function () {
                tween.stop();
            });
            
            return tween;
        };
    }
})();

// PointerEvents.js
function PointerEvents (app) {
    this.app = app;
    
    this.isPointerDown = false;
    this.pointerScreenPosition = new pc.Vec2();
    
    if (Device.Instance().mobile) {
        this.app.touch.on('touchstart', this.OnTouchDown, this);
        this.app.touch.on('touchmove', this.OnTouchMove, this);
        this.app.touch.on('touchend', this.OnTouchUp, this);
    } 
    
    else {
        this.app.mouse.on('mousedown', this.OnMouseDown, this);
        this.app.mouse.on('mouseup', this.OnMouseUp, this);
        this.app.mouse.on('mousemove', this.OnMouseMove, this);
        
        document.addEventListener("mouseout", this.OnMouseExitCanvas.bind(this), true);
        document.addEventListener("mouseenter", this.OnMouseEnterCanvas.bind(this), true);
    }
    
    this.pointerIsOverCanvas = true;
    
    //Callbacks
    this.onPointerDown = null;
    this.onPointerUp = null;
    this.onPointerMove = null;
    this.callbackContext = null;
}
 
//---- Mouse/Touch Events ----//
PointerEvents.prototype.OnPointerDown = function (x, y) {
    if(!this.pointerIsOverCanvas) return; //Ignore UI presses
    
    this.isPointerDown = true;
    this.pointerScreenPosition.set(x, y);

    if(this.onPointerDown !== undefined && this.onPointerDown !== null){
        this.onPointerDown.call(this.callbackContext, this.pointerScreenPosition);
    }
};

PointerEvents.prototype.OnTouchDown = function (touchEvent) {
    var pos = this.GetMostRecentTouch(touchEvent);    
    this.OnPointerDown(pos.x, pos.y);
};

PointerEvents.prototype.OnMouseDown = function (e) {
    this.OnPointerDown(e.x, e.y);
};

//On Up
PointerEvents.prototype.OnPointerUp = function (x, y) {
    this.isPointerDown = false;

    if(this.onPointerUp !== undefined && this.onPointerUp !== null){
        this.onPointerUp.call(this.callbackContext, this.pointerScreenPosition);
    }
};

PointerEvents.prototype.OnTouchUp = function (touchEvent) {
    var pos = this.GetMostRecentTouch(touchEvent);
    this.OnPointerUp(pos.x, pos.y);
};

PointerEvents.prototype.OnMouseUp = function (e) {
    this.OnPointerUp(e.x, e.y);
};


//Move
PointerEvents.prototype.OnPointerMove = function (x, y) {
    this.pointerScreenPosition.set(x, y);
    
    if(this.onPointerMove !== undefined && this.onPointerMove !== null){
        this.onPointerMove.call(this.callbackContext, this.pointerScreenPosition);
    }
};

PointerEvents.prototype.OnMouseMove = function (e) {
    this.OnPointerMove(e.x, e.y);
};

PointerEvents.prototype.OnTouchMove = function (touchEvent) {
    var pos = this.GetMostRecentTouch(touchEvent);
    //Call pointer move
    this.OnPointerMove(pos.x, pos.y);    
};

PointerEvents.prototype.OnMouseEnterCanvas = function (e) {
    
    var fromCanvas = e.fromElement === ScaleManager.Instance.canvas;
    if(!fromCanvas){
        this.pointerIsOverCanvas = true;
    }
    
};

PointerEvents.prototype.OnMouseExitCanvas = function (e) {

    this.pointerIsOverCanvas = false;

     e = e ? e : window.event;
    var from = e.relatedTarget || e.toElement;
    if (!from || from.nodeName == "HTML") {
        // stop your drag event here
        if(this.isPointerDown && this.pointerScreenPosition){
            this.OnPointerUp(this.pointerScreenPosition.x, this.pointerScreenPosition.y);
        }
    }
};

//Utility
PointerEvents.prototype.GetMostRecentTouch = function (touchEvent) {
    var pos = null;
    var changedTouches = touchEvent.changedTouches;

    for (var i = 0; i < changedTouches.length; i++) {
        pos = changedTouches[i];
    }
    
    return pos; 
};

//---- ~Mouse/Touch Events ----//
PointerEvents.prototype.Destroy = function () {
    
    this.pointerScreenPosition = null;

    if (this.app.touch) {
        this.app.touch.off('touchstart', this.OnTouchDown, this);
        this.app.touch.off('touchmove', this.OnTouchMove, this);
        this.app.touch.off('touchend', this.OnTouchUp, this);
    } 

    if (this.app.mouse) {
        this.app.mouse.off('mousedown', this.OnMouseDown, this);
        this.app.mouse.off('mouseup', this.OnMouseUp, this);
        this.app.mouse.off('mousemove', this.OnMouseMove, this);
        document.removeEventListener("mouseout", this.OnMouseExitCanvas.bind(this), true);
        document.removeEventListener("mouseenter", this.OnMouseEnterCanvas.bind(this), true);
    }

    this.onPointerDown = null;
    this.onPointerUp = null;
    this.onPointerMove = null;
    this.callbackContext = null;
};

// SpinePriorityUpdater.js
var SpinePriorityUpdater = pc.createScript('spinePriorityUpdater');

// initialize code called once per entity
SpinePriorityUpdater.prototype.initialize = function() {
    this.spine = this.entity.script.spine;

};

SpinePriorityUpdater.prototype.postInitialize = function() {
    this.UpdatePriority();

};

SpinePriorityUpdater.prototype.UpdatePriority = function() {
    var z = this.entity.getPosition().z;
    var priority = z * 100;
    this.spine.SetPriority(priority);
};

// BillboardEntity.js
var BillboardEntity = pc.createScript('billboardEntity');

BillboardEntity.attributes.add('lockX', { type: 'boolean', default: false});
BillboardEntity.attributes.add('lockY', { type: 'boolean', default: false});
BillboardEntity.attributes.add('lockZ', { type: 'boolean', default: true});
BillboardEntity.attributes.add('offset', { type: 'vec3' });
BillboardEntity.attributes.add('maxAngleOffset', { type: 'number', default: 360});
BillboardEntity.attributes.add('updateBillboard', { type: 'boolean', default: false});

// initialize code called once per entity
BillboardEntity.prototype.initialize = function() {
    this.initialEulerAngles = this.entity.getEulerAngles().clone();
    this.up = new pc.Vec3(0,0,1);
};

BillboardEntity.prototype.postInitialize = function() {
   
    var cameraEntity = GameCamera.Instance.entity;
    var currentEulerAngles = cameraEntity.getEulerAngles();
    currentEulerAngles.x = this.lockX ? this.initialEulerAngles.x : currentEulerAngles.x;
    currentEulerAngles.y = this.lockY ? this.initialEulerAngles.y : currentEulerAngles.y;
    currentEulerAngles.z = this.lockZ ? this.initialEulerAngles.z : currentEulerAngles.z;

    this.entity.setEulerAngles(currentEulerAngles.x, currentEulerAngles.y, currentEulerAngles.z);
};

// update code called every frame
BillboardEntity.prototype.update = function(dt) {
    if(this.updateBillboard){
        var camera = GameCamera.Instance.entity.camera;
        this.entity.lookAt(camera.entity.getPosition(), this.up);

        this.entity.rotateLocal(-180 + this.offset.x, this.offset.y, this.offset.z);
        

        var currentEulerAngles = this.entity.getEulerAngles();
        currentEulerAngles.x = this.lockX ? this.initialEulerAngles.x : pc.math.clamp(currentEulerAngles.x, this.initialEulerAngles.x - this.maxAngleOffset, this.initialEulerAngles.x + this.maxAngleOffset);
        currentEulerAngles.y = this.lockY ? this.initialEulerAngles.y : pc.math.clamp(currentEulerAngles.y, this.initialEulerAngles.y - this.maxAngleOffset, this.initialEulerAngles.y + this.maxAngleOffset);
        currentEulerAngles.z = this.lockZ ? this.initialEulerAngles.z : pc.math.clamp(currentEulerAngles.z, this.initialEulerAngles.z - this.maxAngleOffset, this.initialEulerAngles.z + this.maxAngleOffset);

        this.entity.setEulerAngles(currentEulerAngles.x, currentEulerAngles.y, currentEulerAngles.z);
    }
    
};

