var FillBar = pc.createScript('fillBar');

FillBar.attributes.add('fillEntity', { type: 'entity'});
FillBar.attributes.add('maxWidth', { type: 'number', default: 100});

// initialize code called once per entity
FillBar.prototype.initialize = function() {
    this.fillElement = this.fillEntity.element;
    this.progress = 0;
    
    this.SetProgress(this.progress);
};

// update code called every frame
FillBar.prototype.update = function(dt) {
};

FillBar.prototype.SetProgress = function(progress) {
    this.progress = Math.min(progress, 1);
    this.fillElement.width = this.progress * this.maxWidth;
};

// ParticleSystemExtensions.js
var ParticleSystemExtensions = pc.createScript('particleSystemExtensions');

// initialize code called once per entity
ParticleSystemExtensions.prototype.initialize = function() {
    this.particlesystem = this.entity.particlesystem;
    
    this.rate = this.particlesystem.rate;
    this.rate2 = this.particlesystem.rate2;
    
    this.rateTimer = 0;
    
    this.particlesystem.on("play", this.OnPlay, this);
};

// update code called every frame
ParticleSystemExtensions.prototype.update = function(dt) {
    if(this.rateTimer > 0){
        this.rateTimer -= dt;
        if(this.rateTimer <= 0){
            this.particlesystem.rate = this.rate;
            this.particlesystem.rate2 = this.rate2;
        }
    }
};

ParticleSystemExtensions.prototype.OnPlay = function() {
    this.rateTimer = 0.01;
    this.particlesystem.rate = 0.01;
    this.particlesystem.rate2 = 0.01;
};

ParticleSystemExtensions.prototype.Play = function() {
    this.particlesystem.play();
};


var pcParticlePlay = pc.ParticleSystemComponent.prototype.play;
pc.ParticleSystemComponent.prototype.play = function(w) {
    this.fire("play");
    pcParticlePlay.call(this);
};

// SpineVertexSkew.js
var SpineVertexSkew = pc.createScript('spineVertexSkew');

SpineVertexSkew.attributes.add('vertex', {
    type: 'asset',
    assetType: 'shader',
    title: 'Vertex Shader'
});

SpineVertexSkew.attributes.add('fragment', {
    type: 'asset',
    assetType: 'shader',
    title: 'Fragment Shader'
});


// initialize code called once per entity
SpineVertexSkew.prototype.initialize = function() {    
    this.cameraEntity = this.app.root.findByName('Follow Camera');
};

SpineVertexSkew.prototype.postInitialize = function() {        
    var vs = this.vertex.resource;
    var fs = this.fragment.resource;
    
    for(var i = 0; i<this.entity.spine.spine._meshInstances.length; i++){
        this.entity.spine.spine._meshInstances[i].material.chunks.startVS = vs;
        this.entity.spine.spine._meshInstances[i].material.chunks.startPS = fs;
        this.entity.spine.spine._meshInstances[i].material.update();
    }
};

SpineVertexSkew.prototype.update = function(dt) {
    var width = this.app.graphicsDevice.width;
    var screenSpace = ((this.cameraEntity.camera.worldToScreen(this.entity.getPosition()).x / width) * 2.0) -1.0;
    var billboardRotation = this.cameraEntity.getRotation();
    var perspectiveSkew = new pc.Vec3(0.0,0.0,this.cameraEntity.camera.fov * -screenSpace);
    
    this.entity.setRotation(billboardRotation);    
};

// MPPIDCarousel.js
MPPIDCarousel = function() {
    this.pidController = new MPPIDController();
    this.proportionalGain = 20.0;
    this.integralGain = 0.04;
    this.derivativeGain = 6.0;

    this.touchCollider = null;

    this.dragHistory = [];
    this.dragHistory.length = 5;
    this.touchDragStart = pc.Vec2.ZERO;
    this.touchDragLast = pc.Vec2.ZERO;
    this.anchorDragStart = pc.Vec2.ZERO;
    this.entryDirection = new pc.Vec2(Math.cos(this.entryDirectionAngle * pc.math.DEG_TO_RAD),
        Math.sin(this.entryDirectionAngle * pc.math.DEG_TO_RAD));
    this.velocity = 0;
    this.lastIndex = 0;
    this.progress = 0;

    this.useMultiStep = false;
    this.allowDragging = true;
    
    if (this.parentCameraEntity) {
        this.parentCamera = this.parentCameraEntity.camera;
    }
    
    this.ResetEntryPositions();
};

MPPIDCarousel.prototype.constructor = MPPIDCarousel;

