MPPIDCarousel.prototype.update = function(dt) {

    this.selectedIndex = pc.math.clamp(this.selectedIndex, 0, this.GetLength() - 1 - this.maximumScrollableIndexOffset);

    this.UpdateVelocity(dt);
    if (this.wrapEntries) {
        this.UpdateWrapping(dt);
    }

    this.UpdateIndex(dt);
    this.PostUpdate(dt);
};

