// MPDOMPanel.js
var MPDOMPanel = pc.createScript('MPDOMPanel');

MPDOMPanel.attributes.add("domClass", {
    type: 'string',
    title: "DOM Class",
    default: "dom_panel",
    description: "DOM Class for Panel"
});

// initialize code called once per entity
MPDOMPanel.prototype.initialize = function() {
    this.on("destroy", this.Destroy, this);   
    
    this.ConfigureClass();
    
    this.scaler = this.entity.script.create("MPDOMScaler");
    this.scaler.on("scaleUpdate", this.UpdateOffset, this);
    
    this.UpdateOffset();
    
    window.addEventListener("resize", this.OnScreenResize.bind(this), true);
};

MPDOMPanel.prototype.ConfigureClass = function() {
    
    var buttonSize = MPDOMClasses.GetButtonSize();
    
    //Only update if button size has changed
    if(this.buttonSize != buttonSize){
        this.buttonSize = buttonSize;
        
        var domClass = MPDOMClasses.GetClassConfig(this.domClass) || {};
        var platformClass = domClass[MPDOMClasses.GetButtonSize()] || { "tablet": {}, "mobile": {} };
        var x = platformClass.x || 0.5;
        var y = platformClass.y || 0.5;
        var offsetX = platformClass.offsetX || 0;
        var offsetY = platformClass.offsetY || 0;
        this.offsetX = offsetX;
        this.offsetY = offsetY;    
        this.spacingX = platformClass.spacingX || 0;
        if(this.entity.element){
            this.entity.element.anchor.set(x, 1 - y, x, 1 - y);
        }
        
        this.entity.setLocalPosition(this.offsetX, -this.offsetY, 0);
    
        //Spacing
        if(this.entity.layoutgroup){
            this.entity.layoutgroup.spacing.set(this.spacingX, 0);
            this.entity.layoutgroup.padding.set(0, 0, this.offsetX, -this.offsetY);
        }
        
        
    }
    
};

MPDOMPanel.prototype.UpdateOffset = function() {
    this.entity.setLocalPosition(this.offsetX * this.scaler.scale, -this.offsetY * this.scaler.scale, 0);
};

MPDOMPanel.prototype.OnScreenResize = function() {
    this.ConfigureClass();
    this.UpdateOffset();
};

MPDOMPanel.prototype.Destroy = function() {
    window.removeEventListener("resize", this.OnScreenResize.bind(this), true);
};

// MPDOMClasses.js
var MPDOMClasses = function(){
    
};

MPDOMClasses.LoadData = function(domClassesAsset) {
    MPDOMClasses.data = domClassesAsset.resource;
    
    
};

MPDOMClasses.GetButtonSize = function(){
    //Button sizes
    var buttonSize = "tablet";
    var mq = window.matchMedia("(min-width: 770px)");
    if (!mq.matches) {
        buttonSize = "mobile";
    }
    return buttonSize;
};

MPDOMClasses.GetClassConfig = function(input) {
    var terms = input.split(" ");
    var listSize = terms.length;
    var results = [ terms.slice(0) ];

    // Get combinations of terms
    for (var i = 1; i < listSize; i++) {
        results[i] = [];
        for (var j = 0; j < listSize; j++) {
            for (var k = j; k <= listSize; k++) {
                if (k + i >= listSize) continue;
                var combination = terms[j];
                for (var l = 1; l <= i; l++) {
                    combination += " " + terms[k + l];
                }
                results[i].push(combination);
            }
        }
    }

    // Get all related classes
    var classes = [];
    listSize = results.length;
    for (var i = 0; i < listSize; i++) {
        var depthSize = results[i].length;
        for (var j = 0; j < depthSize; j++) {
            for (var prop in MPDOMClasses.data) {
                if (prop == results[i][j]) {
                    classes.push(MPDOMClasses.data[prop]);
                }
            }
        }
    }

    // Combine into a config
    var config = {};
    listSize = classes.length;
    for (var i = 0; i < listSize; i++) {
        MPDOMClasses.ObjectExtend(config, classes[i]);
    }

    return config;
};

MPDOMClasses.ObjectExtend = function() {
    for(var i=1; i<arguments.length; i++)
        for(var key in arguments[i])
            if(arguments[i].hasOwnProperty(key)) {
                if (typeof arguments[0][key] === 'object'
                    && typeof arguments[i][key] === 'object')
                        MPDOMClasses.ObjectExtend(arguments[0][key], arguments[i][key]);
                else
                    arguments[0][key] = arguments[i][key];
            }
    return arguments[0];
};

// MPDOMButton.js
var MPDOMButton = pc.createScript('MPDOMButton');

MPDOMButton.attributes.add("buttonEntity", { type: 'entity', title: "Button Entity" });
MPDOMButton.attributes.add("enableOnInitialize", { type: 'boolean', title: "Enable On Initialize", default: true });
MPDOMButton.attributes.add("createButtonElement", { type: 'boolean', title: "Create Button Element", default: true });
MPDOMButton.attributes.add("domClassName", { type: 'string', title: "DOM Class Name", default: "dom_button std" });
MPDOMButton.attributes.add('screenReaderID', { type: 'string', title: "Screen Reader ID"});
MPDOMButton.attributes.add('preventUseWhenOnlyValidButtonSet', { type: 'boolean'});

MPDOMButton.onlyValidButton = null;

// initialize code called once per entity
MPDOMButton.prototype.initialize = function() {
    this.on("destroy", this.Destroy, this); 
    
    this.entity.MPDOMButton = this;
    
    this.hasPanelParent = this.entity.parent.script && this.entity.parent.script.MPDOMPanel !== undefined;
    
    this.ConfigureClass();
    
    this._onScreenResize = this.OnScreenResize.bind(this);
    
    window.addEventListener("resize", this._onScreenResize, true);
    
    if(this.createButtonElement){
        this.CreateButtonElement();
    }

    this.isOver = false;   
    
    this.buttonEntity.button.active = false;
    this.hasEnabledFirstTime = false;
    
    this.desktop = Device.Instance().desktop;
    
    this._onBlur = this.OnBlur.bind(this);
    this._onInputOver = this.OnInputOver.bind(this);
    this._onInputOut = this.OnInputOut.bind(this);
    this._onInputDown = this.OnInputDown.bind(this);
    this._onInputUp = this.OnInputUp.bind(this);
    this._onClick = this.OnClick.bind(this);
    
    
    
};

MPDOMButton.prototype.postInitialize = function() {
    if(this.enableOnInitialize){
        this.Enable();
    }
    else{
        this.Disable();
    }
};

MPDOMButton.prototype.update = function() {

};

MPDOMButton.prototype.IsValidForUse = function() {
    return !this.preventUseWhenOnlyValidButtonSet || MPDOMButton.onlyValidButton === null || MPDOMButton.onlyValidButton == this.entity.name;
};

MPDOMButton.prototype.OnInputOver = function(e) {
    if(!this.IsValidForUse()) return;
    
    if(!this.isOver){
        this.isOver = true;    
        document.body.style.cursor = "pointer";

        this.fire("over", e);
    }
    
};

MPDOMButton.prototype.OnInputOut = function(e) {    
    if(this.isOver){
        this.isOver = false;    
        document.body.style.cursor = "default";

        this.fire("out", e);
    }
};

MPDOMButton.prototype.OnInputDown = function(e) {
    if(e.preventDefault)
        e.preventDefault();

    if(!this.IsValidForUse()) return;
    
    this.fire("down", e);
    
    if(this.buttonElement)
        this.buttonElement.style.outline = 0; //Removes blue outline
    
    
};

MPDOMButton.prototype.OnInputUp = function(e) {
    if(!this.IsValidForUse()) return;
    
    this.fire("up", e);
    
    if(!this.desktop){
        //Fixes bug where first press of button on mobile stays depressed (due to "focus" firing after up)
        setTimeout(this.OnInputOut.bind(this), 100);
    }
};

MPDOMButton.prototype.OnBlur = function() {
    if(this.buttonElement)
        this.buttonElement.style.outline = ""; //Adds back blue outline
};

MPDOMButton.prototype.OnClick = function() {
    if(!this.IsValidForUse()) return;

    document.body.style.cursor = "default";
    GameManager.Instance.GoFullscreen();
    setTimeout(this.OnClickComplete.bind(this), 1);
};

MPDOMButton.prototype.OnClickComplete = function() {
    this.fire("click");
};


MPDOMButton.prototype.CreateButtonElement = function() {
    this.buttonElement = document.createElement('button');
    
    this.buttonElement.style.backgroundColor = "transparent";
    //this.buttonElement.style.backgroundColor = "rgba(0, 0, 0, 0.3)";//Use to view position for debugging
    this.buttonElement.style.borderStyle = "none";
    this.buttonElement.style.display = "inline";
    this.buttonElement.style.position = "absolute";
    this.buttonElement.style.msTransform  = "translate(-50%, 50%)";
    this.buttonElement.style.webkitTransform  = "translate(-50%, 50%)";
    this.buttonElement.style.transform = "translate(-50%, 50%)";
    this.buttonElement.style.padding = "0px";
    
    
    this.buttonElement.style.webkitTapHighlightColor = 'rgba(0, 0, 0, 0)';
    this.buttonElement.style.border = 'none';
    this.buttonElement.style.margin = 'auto';
    this.buttonElement.style.display = 'inline-block';
    this.buttonElement.style.cursor = 'pointer';
    //this.buttonElement.style.outline = 0; //Removes blue outline
    
    this.buttonElement.id = this.screenReaderID;
    this.buttonElement.accessibleTitle = this.screenReaderID;
    this.buttonElement.setAttribute("aria-label", this.screenReaderID);
    
    this.PositionElement();

    
    //Fix element's in layout groups not being positioned properly at start
    setTimeout(this.PositionElement.bind(this), 20);
};

MPDOMButton.prototype.OnScreenResize = function(){
    this.ConfigureClass();
    this.PositionElement();
    setTimeout(this.PositionElement.bind(this), 1);
};

MPDOMButton.prototype.ConfigureClass = function(){
    // Config params 
    var buttonSize = MPDOMClasses.GetButtonSize();
    
    //Only update if button size has changed
    if(this.buttonSize != buttonSize){
        this.buttonSize = buttonSize;
        
        this.domClass = MPDOMClasses.GetClassConfig(this.domClassName);
        this.platformClass = this.domClass[buttonSize];
        
        if(this.platformClass){
            this.entity.element.width = this.platformClass.buttonWidth;
            this.entity.element.height = this.platformClass.buttonHeight;
            this.buttonEntity.element.width = this.platformClass.spriteWidth;
            this.buttonEntity.element.height = this.platformClass.spriteHeight;
            this.buttonEntity.button.hitPadding.set((this.platformClass.buttonWidth - this.platformClass.spriteWidth) * 0.5, (this.platformClass.buttonHeight - this.platformClass.spriteHeight) * 0.5, 
                                                    (this.platformClass.buttonWidth - this.platformClass.spriteWidth) * 0.5, (this.platformClass.buttonHeight - this.platformClass.spriteHeight) * 0.5);
            
            //Handle scaling ourselves if no panel as parent
            if(!this.hasPanelParent && !this.scaler){
                this.scaler = this.entity.script.create("MPDOMScaler");
            }
        }
        
        this.fire("updatedClass");    
    }
};

MPDOMButton.prototype.SetSprite = function(asset, resize) {
    if(asset && this.buttonEntity.element){
        this.buttonEntity.element.spriteAsset = asset;

        if(resize){
            ResizeElementToMatchSprite(this.buttonEntity.element);
        }
    }
    
};


MPDOMButton.prototype.PositionElement = function() {
    if(this.buttonElement){
        //Work out position                
        var dimensionX = ScaleManager.Instance.screenSize.x;// * ScaleManager.Instance.screenAspectRatio;
        var dimensionY = ScaleManager.Instance.screenSize.y;
        
        var width = (this.entity.element.width / dimensionX) * 100;
        var height = (this.entity.element.height / dimensionY) * 100;

        //Scale element based on any scaling
        if(this.hasPanelParent){
            var panelScale = this.entity.parent.getLocalScale();
            width *= panelScale.x;
            height *= panelScale.y;
        }
        else{
            var scale = this.entity.getLocalScale();
            width *= scale.x;
            height *= scale.y;
        }

        this.buttonElement.style.width = width  + "%";
        this.buttonElement.style.height = height + "%";
        var position = this.entity.getPosition();
        var screenPosition = this.entity.element.screen.getPosition();

        var left = ((((position.x - screenPosition.x) * 100) + (dimensionX * 0.5)) / dimensionX) * 100;
        var bottom = ((((position.y - screenPosition.y) * 100) + (dimensionY * 0.5)) / dimensionY) * 100;
        
        this.buttonElement.style.left = left + '%';
        this.buttonElement.style.bottom =  bottom + '%';
    }

};


MPDOMButton.prototype.Enable = function() {
    if(!this.hasEnabledFirstTime){
        this.hasEnabledFirstTime = true;
        
        this.on('state', this.OnStateChanged, this);
    }

    if(!this.buttonEntity.button.active){
        this.buttonEntity.button.active = true;
        
        if(this.buttonElement){
            
            this.buttonElement.addEventListener("focus", this._onInputOver);
            this.buttonElement.addEventListener("focusout", this._onInputOut);
            
            this.buttonElement.addEventListener("blur", this._onBlur);
            
            this.buttonElement.addEventListener("touchstart", this._onInputOver);
            this.buttonElement.addEventListener("touchend", this._onInputOut);
            this.buttonElement.addEventListener("touchcancel", this._onInputOut);
            
            this.buttonElement.addEventListener("touchstart", this._onInputDown);
            this.buttonElement.addEventListener("touchend", this._onInputUp);
            this.buttonElement.addEventListener("touchcancel", this._onInputUp);
            
            this.buttonElement.addEventListener("touchleave", this._onInputOut);
            
            if(Device.Instance().desktop){
                this.buttonElement.addEventListener("click", this._onClick);
                this.buttonElement.addEventListener("mouseover", this._onInputOver);
                this.buttonElement.addEventListener("mouseout", this._onInputOut);
                this.buttonElement.addEventListener("mousedown", this._onInputDown);
                this.buttonElement.addEventListener("mouseup", this._onInputUp);
            }
            else{
                this.buttonElement.addEventListener("touchend", this._onClick);
            }
            
            setTimeout(this.PositionElement.bind(this), 20);
            
        }
        else{
            this.buttonEntity.button.on("touchstart", this._onInputOver);
            this.buttonEntity.button.on("touchend", this._onInputOut);
            this.buttonEntity.button.on("touchcancel", this._onInputOut);
            
            this.buttonEntity.button.on("touchstart", this._onInputDown);
            this.buttonEntity.button.on("touchend", this._onInputUp);
            this.buttonEntity.button.on("touchcancel", this._onInputUp);
            
            this.buttonEntity.button.on("touchleave", this._onInputOut);
            
            if(Device.Instance().desktop){
                this.buttonEntity.button.on("click", this._onClick);
                this.buttonEntity.button.on("mouseover", this._onInputOver);
                this.buttonEntity.button.on("mouseout", this._onInputOut);
                this.buttonEntity.button.on("mousedown", this._onInputDown);
                this.buttonEntity.button.on("mouseup", this._onInputUp);
            }
            else{
                this.buttonEntity.button.on("touchend", this._onClick);
            }
            this.buttonEntity.button.on("hoverstart", this._onInputOver);
            this.buttonEntity.button.on("hoverend", this._onInputOut);
        }
        

        this.buttonEntity.button._isHovering = false;

        if(this.buttonElement){
            if(!this.buttonElement.parentNode){
                MPDOMManager.Instance.AppendToRoot(this.buttonElement);
            }
        }
        
        this.fire("enable");    
    }

};

MPDOMButton.prototype.OnStateChanged = function(state) {
    if(state){
        this.Enable();
    }
    else{
        this.Disable();
    }
};


MPDOMButton.prototype.Disable = function() {
    if(this.buttonEntity.button.active){
        this.buttonEntity.button.active = false;
        this.isOver = false;

        if(this.buttonElement){
            if(this.buttonElement.parentNode){
                this.buttonElement.parentNode.removeChild(this.buttonElement);
                this.buttonElement.parentNode = null;
            }
        }
        
        if(this.buttonElement){
            //Focus hover states
            this.buttonElement.removeEventListener("focus", this._onInputOver);
            this.buttonElement.removeEventListener("focusout", this._onInputOut);
            
            this.buttonElement.removeEventListener("blur", this._onBlur);
            
            this.buttonElement.removeEventListener("touchstart", this._onInputOver);
            this.buttonElement.removeEventListener("touchend", this._onInputOut);
            this.buttonElement.removeEventListener("touchcancel", this._onInputOut);
            this.buttonElement.removeEventListener("touchleave", this._onInputOut);
            
            this.buttonElement.removeEventListener("touchstart", this._onInputDown);
            this.buttonElement.removeEventListener("touchend", this._onInputUp);
            this.buttonElement.removeEventListener("touchcancel", this._onInputUp);
            
            if(Device.Instance().desktop){
                this.buttonElement.removeEventListener("click", this._onClick);
                this.buttonElement.removeEventListener("mouseover", this._onInputOver);
                this.buttonElement.removeEventListener("mouseout", this._onInputOut);
                this.buttonElement.removeEventListener("mousedown", this._onInputDown);
                this.buttonElement.removeEventListener("mouseup", this._onInputUp);
            }
            else{
                this.buttonElement.removeEventListener("touchend", this._onClick);
            }
        
        }
        else{
            this.buttonEntity.button.off("touchstart", this._onInputOver);
            this.buttonEntity.button.off("touchend", this._onInputOut);
            this.buttonEntity.button.off("touchcancel", this._onInputOut);
            
            this.buttonEntity.button.off("touchstart", this._onInputDown);
            this.buttonEntity.button.off("touchend", this._onInputUp);
            this.buttonEntity.button.off("touchcancel", this._onInputUp);
            
            this.buttonEntity.button.off("touchleave", this._onInputOut);
            
            if(Device.Instance().desktop){
                this.buttonEntity.button.off("click", this._onClick);
                this.buttonEntity.button.off("mouseover", this._onInputOver);
                this.buttonEntity.button.off("mouseout", this._onInputOut);
                this.buttonEntity.button.off("mousedown", this._onInputDown);
                this.buttonEntity.button.off("mouseup", this._onInputUp);
            }
            else{
                this.buttonEntity.button.off("touchend", this._onClick);
            }
            this.buttonEntity.button.off("hoverstart", this._onInputOver);
            this.buttonEntity.button.off("hoverend", this._onInputOut);
        }
        
        this.fire("disable");    
    }

};

MPDOMButton.prototype.Show = function() {
    this.buttonEntity.enabled = true;    
};

MPDOMButton.prototype.Hide = function() {
    this.buttonEntity.enabled = false;    
};

MPDOMButton.prototype.Destroy = function() {
    window.removeEventListener("resize", this._onScreenResize, true);
    
    this.Disable();
};

// ScreenMatchAspectRatio.js
var ScreenMatchAspectRatio = pc.createScript('ScreenMatchAspectRatio');

// initialize code called once per entity
ScreenMatchAspectRatio.prototype.initialize = function() {
    
};

ScreenMatchAspectRatio.prototype.initialize = function() {
    this.Resize();
    
    this._resize = this.Resize.bind(this);
    window.addEventListener("resize", this._resize, true);
    this.on("destroy", this.Destroy);
};

ScreenMatchAspectRatio.prototype.Resize = function() {
    var res = ScaleManager.Instance.dimensions;
    var aspectRatio = res.x / res.y;
    
    var screenRes = this.entity.screen.resolution;
    screenRes.x = screenRes.y * aspectRatio;
    this.entity.screen.resolution = screenRes;
};

ScreenMatchAspectRatio.prototype.Destroy = function() {
    window.removeEventListener("resize", this._resize, true);
};

// MPDOMScaler.js
var MPDOMScaler = pc.createScript('MPDOMScaler');

MPDOMScaler.prototype.initialize = function(){     
    this.on("destroy", this.Destroy, this); 
    
    this.scale = 1;
    
    this.UpdateScale();
    
    window.addEventListener("resize", this.UpdateScale.bind(this), true);
};

MPDOMScaler.prototype.UpdateScale = function() {
    var windowHeight = window.innerHeight;
    var defaultHeight = ScaleManager.Instance.defaultHeight;

    this.scale = defaultHeight / windowHeight;

    this.entity.setLocalScale(this.scale, this.scale, this.scale);


    
    this.fire("scaleUpdate", this.scale);    
};

MPDOMScaler.prototype.Destroy = function() {
    window.removeEventListener("resize", this.UpdateScale.bind(this), true);
};

// MaskShader.js
var MaskShader = pc.createScript('maskShader');

MaskShader.attributes.add('fragmentShader', {type: 'asset',assetType: 'shader',title: 'Fragment Shader', default: 40570489});
MaskShader.attributes.add('fragmentTextShader', {type: 'asset',assetType: 'shader',title: 'Fragment Text Shader', default: 40569320});
MaskShader.attributes.add('maskEntity', {type: 'entity'});
MaskShader.attributes.add('screenEntity', {type: 'entity'});
MaskShader.attributes.add('softClipWidth', {type: 'number', default: 0});
MaskShader.attributes.add('softClipHeight', {type: 'number', default: 0});

// initialize code called once per entity
MaskShader.prototype.initialize = function() {    
    this.on('state', this.OnStateChanged, this);
       
};

MaskShader.prototype.postInitialize = function() {        
    this.screen = this.screenEntity.screen;
    
    this.maskElement = this.maskEntity.element;
    
    this.maskScreenLeft = 0;
    this.maskScreenRight = 0;
    this.maskScreenTop = 0;
    this.maskScreenBottom = 0;
    
    this.materials = [];

    this.CreateShader();
};

MaskShader.prototype.InitMaterial = function(parent) {    
    var material = CloneMaterial(parent);
    parent.material = material;
    this.materials.push(material);
    return material;
};


MaskShader.prototype.update = function() {    
    this.UpdateShader(this.maskElement);
    
};

MaskShader.prototype.CreateShader  = function() {    
    if(this.entity.model){
        this.CreateModelShader();
    }
    else if(this.entity.element){
        this.CreateElementShader();
    }
};

MaskShader.prototype.CreateElementShader  = function() {    
    
    var material = null;
    
    if (this.entity.element._text) {
        material = this.InitMaterial(this.entity.element._text._model.meshInstances[0]);
        material.chunks.opacityPS = this.fragmentTextShader.resource;
    }
    else {
        material = this.InitMaterial(this.entity.element);
        material.chunks.opacityPS = this.fragmentShader.resource;
        material.emissive.set(this.entity.element.color.r, this.entity.element.color.g, this.entity.element.color.b, 1);
    }

    material.setParameter('baseOpacity', this.entity.element.opacity);
    
    this.FinalizeShader(material);
};

MaskShader.prototype.CreateModelShader  = function() { 
    for(var i = 0; i<this.entity.model.meshInstances.length; i++){
        var baseOpacity = this.entity.model.meshInstances[i].material.opacity;
        var material = this.InitMaterial(this.entity.model.meshInstances[i]);
        if(material.blendType == pc.BLEND_NONE){
            material.blendType = pc.BLEND_NORMAL;
        }
        material.chunks.opacityPS = this.fragmentShader.resource;
        material.setParameter('baseOpacity', baseOpacity);

        this.FinalizeShader(material);
    }
    
};

MaskShader.prototype.FinalizeShader  = function(material) {    
    material.setParameter('useTextureMaskRect', false);
    material.setParameter('useTextureMask', true);
    
    if(this.maskEntity.element.material && this.maskEntity.element.material.opacityMap && this.maskEntity.element.material.opacityMap.width > 1){
        material.setParameter('texture_maskMap', this.maskEntity.element.material.opacityMap);
    }
    else if(this.maskEntity.element.texture){
        material.setParameter('texture_maskMap', this.maskEntity.element.texture);
    }
    else if(this.maskEntity.element.sprite){
        
        var frameKey = this.maskEntity.element.sprite.frameKeys[0];
        var rect = this.maskEntity.element.sprite.atlas.frames[frameKey].rect;
        material.setParameter('useTextureMaskRect', true);
        material.setParameter('texture_maskMap', this.maskEntity.element.sprite.atlas.texture);
        material.setParameter('texture_maskRect', [rect.x, rect.y, rect.x + rect.z, rect.y + rect.w]);

        material.setParameter('texture_maskSize', [this.maskEntity.element.sprite.atlas.texture.width, this.maskEntity.element.sprite.atlas.texture.height]);
    }
    else{
        material.setParameter('useTextureMask', false);
    }
    this.UpdateShader(this.maskElement);
    material.update();
};

MaskShader.prototype.OnStateChanged = function(state) {
    if(state){
        
        //Check if we need to recreate the text shader
        if (this.entity.element && this.entity.element._text) {
            if(this.entity.element._text._model.meshInstances[0].material._chunks.opacityPS === undefined){
                this.CreateElementShader();
            }

        }
        
        this.UpdateShader(this.maskElement);
    }
    else{
       
    }
};

MaskShader.prototype.UpdateShader  = function(element) {    
    
    var dimensionX = ScaleManager.Instance.defaultHeight * ScaleManager.Instance.screenAspectRatio;
    var dimensionY = ScaleManager.Instance.defaultHeight;
    
    var scale = (pc.app.graphicsDevice.height / this.screen.referenceResolution.y);
    this.maskScreenLeft = this.maskEntity.element.screenCorners[0].x * scale;
    this.maskScreenRight = this.maskEntity.element.screenCorners[1].x * scale;
    this.maskScreenTop = this.maskEntity.element.screenCorners[2].y * scale;
    this.maskScreenBottom = this.maskEntity.element.screenCorners[0].y * scale;
    
    for(var i = 0; i<this.materials.length; i++){
        var material = this.materials[i];
        material.setParameter('maskLeft', this.maskScreenLeft);
        material.setParameter('maskRight', this.maskScreenRight);
        material.setParameter('maskBottom', this.maskScreenBottom);
        material.setParameter('maskTop', this.maskScreenTop);
        material.setParameter('softClipWidth', this.softClipWidth * scale);
        material.setParameter('softClipHeight', this.softClipHeight * scale);
    }
    

    
};


// MPDOMToggleButton.js
var MPDOMToggleButton = pc.createScript('MPDOMToggleButton');

