var MPDOMAudioButton = pc.createScript('MPDOMAudioButton');

if (!MPDOMToggleButton)
      var MPDOMToggleButton = function() {};
MPDOMAudioButton.prototype = Object.create(MPDOMToggleButton.prototype);
MPDOMAudioButton.prototype.constructor = MPDOMAudioButton;

MPDOMAudioButton.attributes.add("buttonEntity", { type: 'entity', title: "Button Entity" });
MPDOMAudioButton.attributes.add("enableOnInitialize", { type: 'boolean', title: "Enable On Initialize", default: true });
MPDOMAudioButton.attributes.add("createButtonElement", { type: 'boolean', title: "Create Button Element", default: true });
MPDOMAudioButton.attributes.add("domClassName", { type: 'string', title: "DOM Class Name", default: "dom_button std" });
MPDOMAudioButton.attributes.add('screenReaderID', { type: 'string', title: "Screen Reader ID"});


// initialize code called once per entity
MPDOMAudioButton.prototype.initialize = function() {
    this.toggle = AudioManager.Instance.audioEnabled;
    
    MPDOMToggleButton.prototype.initialize.call(this);
    
    this.on("enable", this.OnEnable);
};

// update code called every frame
MPDOMAudioButton.prototype.OnToggle = function() {
    MPDOMToggleButton.prototype.OnToggle.call(this);
    AudioManager.Instance.ToggleAudioEnabled();
};

MPDOMAudioButton.prototype.OnEnable = function() {
    this.toggle = AudioManager.Instance.audioEnabled;
    this.fire("toggle");
};

// MPDOMButtonSound.js
var MPDOMButtonSound = pc.createScript('MPDOMButtonSound');

MPDOMButtonSound.attributes.add("mpDomButtonEntity", { type: 'entity', title: "MPDOMButton Entity" });
MPDOMButtonSound.attributes.add("soundLayer", { type: "string" });
MPDOMButtonSound.attributes.add("soundName", { type: "string" });
MPDOMButtonSound.attributes.add("soundVolume", { type: "number", default: 1 });
MPDOMButtonSound.attributes.add("eventName", { type: 'string',
    enum: [
        { 'click': "click" },
        { 'over': "over" },
        { 'out': "out" }
    ],
    default: 'click'
});

// initialize code called once per entity
MPDOMButtonSound.prototype.initialize = function() {
    this.MPDOMButton = this.mpDomButtonEntity ? this.mpDomButtonEntity.MPDOMButton : this.entity.MPDOMButton;
    this.MPDOMButton.on(this.eventName, this.OnEvent, this);
};

// update code called every frame
MPDOMButtonSound.prototype.update = function(dt) {
    
};

MPDOMButtonSound.prototype.OnEvent = function() {
    AudioManager.Instance.Play(this.soundLayer, this.soundName, {volume: this.soundVolume});
};

// CameraManager.js
var CameraManager = pc.createScript('cameraManager');

CameraManager.attributes.add('worldCameraEntity', {type: 'entity'});
CameraManager.attributes.add('uiCameraEntity', {type: 'entity'});

CameraManager.Instance = null;
// initialize code called once per entity
CameraManager.prototype.initialize = function() {    
    CameraManager.Instance = this;
    
    this.worldCamera = this.worldCameraEntity.camera;
    this.uiCamera = this.uiCameraEntity.camera;
    
    this.cameraMoveTween = this.worldCameraEntity.tween(this.worldCameraEntity.getLocalPosition());
    this.cameraRotateTween = this.worldCameraEntity.tween(this.worldCameraEntity.getLocalEulerAngles());
    
    
    this.defaultCameraTransform = this.worldCameraEntity;
    
    this.defaultFov = this.worldCamera.fov;
    
    //Layers
    this.cameraTransforms = [];
    
    //this.SetCameraTransform(this.defaultCameraTransform);
    this.on("destroy", this.OnDestroy);
};

// update code called every frame
CameraManager.prototype.update = function(dt) {
};


CameraManager.prototype.AddCameraTransform = function(cameraTransform, lerpTime, lerpEaseType) {
    for(var i = 0; i<this.cameraTransforms.length; i++){
        if(this.cameraTransforms[i] == cameraTransform){
            return;
        }
    }
    this.cameraTransforms.push(cameraTransform);

    this.SetCameraTransform(cameraTransform.entity, lerpTime, lerpEaseType);
    
    if(cameraTransform.forceFov){
        this.worldCamera.fov = cameraTransform.entity.camera.fov;
    }
};

CameraManager.prototype.RemoveCameraTransform = function(cameraTransform, lerpTime, lerpEaseType) {
    for(var i = 0; i<this.cameraTransforms.length; i++){
        if(this.cameraTransforms[i] == cameraTransform){
            this.cameraTransforms.splice(i, 1);
            break;
        }
    }
    
    
    if(this.cameraTransforms.length > 0){
        this.SetCameraTransform(this.cameraTransforms[this.cameraTransforms.length - 1].entity, lerpTime, lerpEaseType);
    }
    else{
        this.SetCameraTransform(this.defaultCameraTransform, lerpTime, lerpEaseType);
    }
};

CameraManager.prototype.OverwritePreviousCameraTransform = function(cameraTransform, lerpTime, lerpEaseType) {
    for(var i = 0; i<this.cameraTransforms.length; i++){
        if(this.cameraTransforms[i] == cameraTransform){
            return;
        }
    }
    
    this.cameraTransforms.splice(this.cameraTransforms.length - 1);
    this.AddCameraTransform(cameraTransform, lerpTime, lerpEaseType);
};

CameraManager.prototype.SetCameraTransform = function(transformEntity, lerpTime, lerpEaseType) {
    lerpTime = lerpTime ? lerpTime : 0;
    lerpEaseType = lerpEaseType !== undefined ? lerpEaseType : pc.SineInOut;
    
    var currentWorldPosition = this.worldCameraEntity.getPosition().clone();  
    var currentEulerAngles = this.worldCameraEntity.getEulerAngles().clone();
    
    if(transformEntity.script && transformEntity.script.cameraTransform && transformEntity.script.cameraTransform.forceFov){
        this.worldCamera.fov = transformEntity.camera.fov;
    }
    else{
        this.worldCamera.fov = this.defaultFov;
    }
    
    
    this.worldCameraEntity.reparent(transformEntity);
    this.worldCameraEntity.setLocalPosition(0, 0, 0);
    this.worldCameraEntity.setLocalEulerAngles(0, 0, 0);
    
    this.cameraMoveTween.stop();
    this.cameraRotateTween.stop();
    
    if(lerpTime > 0){
        this.worldCameraEntity.setPosition(currentWorldPosition);
        this.worldCameraEntity.setEulerAngles(currentEulerAngles);
        
        this.cameraMoveTween = this.worldCameraEntity.tween(this.worldCameraEntity.getLocalPosition());
        this.cameraMoveTween.pausable = false;
        this.cameraMoveTween.to({x: 0, y: 0, z: 0}, lerpTime, lerpEaseType);
        this.cameraMoveTween.start();
        
        
        this.cameraRotateTween = this.worldCameraEntity.tween(this.worldCameraEntity.getLocalEulerAngles());
        this.cameraRotateTween.pausable = false;
        this.cameraRotateTween.rotate({x: 0, y: 0, z: 0}, lerpTime, lerpEaseType);
        this.cameraRotateTween.start();        
    }
};

CameraManager.prototype.Shake = function() {
    
};

CameraManager.prototype.OnDestroy = function() {
    CameraManager.Instance = null;
    this.cameraMoveTween.off();
    this.cameraMoveTween.stop();
};


// spine.js
var Spine = pc.createScript("spine");

Spine.attributes.add("atlas", { type: "asset", assetType: "text" });
Spine.attributes.add("skeleton", { type: "asset", assetType: "json" });
Spine.attributes.add("textures", { type: "asset", array: true, assetType: "texture" });
Spine.attributes.add("overrideOpacityTextures", { type: "asset", array: true, assetType: "texture" });
Spine.attributes.add("priority", {type: "number", default: 1});
Spine.attributes.add("startAnimation", {type: "string"});
Spine.attributes.add("startLoop", {type: "boolean", default: true});
Spine.attributes.add("useAmbientLighting", {type: "boolean", default: true});
Spine.attributes.add("emissiveTint", {type: "rgb"});
Spine.attributes.add("layers", { type: "string", array: true, default: ["World"] });
Spine.attributes.add("skin", { type: "string", default: "default" });
Spine.attributes.add("pausable", { type: "boolean", default: true });

Spine.prototype.initialize = function () {
    
    if (this.atlas && this.textures && this.skeleton) {
        // If all assets are present, add the spine component to the entity

        this.entity.addComponent("spine", {
            atlasAsset: this.atlas.id,
            textureAssets: this.textures.map(function (a) {
                return a.id;
            }),
            overrideOpacityTextureAssets: this.overrideOpacityTextures.map(function (a) {
                return a.id;
            }),
            skeletonAsset: this.skeleton.id
        });

        if (this.entity.spine) {
            this.priority = this.priority ? this.priority : 0;
            this.entity.spine.spine.priority = this.priority;
        }

        var layers = [];
        for(var i = 0; i<this.layers.length; i++){
            layers.push(this.app.scene.layers.getLayerByName(this.layers[i]).id);
        }

        this.entity.spine.spine.layers = layers;
    }

    this.on('attr:priority', function (val) {
        if (this.entity.spine) {
            this.entity.spine.spine.priority = val;
        }
    }, this);
    
    this.on('attr:useAmbientLighting', this.UpdateMaterials, this);
    this.on('attr:emissiveTint', this.UpdateMaterials, this);
    
    this.SetSkin(this.skin);
    
    this.materialCount = 1;
    
    this.UpdateMaterials();
    
    this.delegateObj = {
        start: this.OnStart.bind(this),
        complete: this.OnComplete.bind(this),
        event: this.OnEvent.bind(this),
        interrupt: this.OnInterrupt.bind(this),
    };
    this.entity.spine.state.addListener(this.delegateObj);
    
    if(this.startAnimation){
        this.PlayAnimation(0, this.startAnimation, this.startLoop);
    }
};


Spine.prototype.postInitialize = function () {
    
    
    
};

Spine.prototype.update = function (dt) {
    if(GameManager.Instance){
        this.entity.spine.speed = this.pausable ? GameManager.Instance.timeScale : 1;
    }
    
    var size = Object.keys(this.entity.spine.spine._materials).length;
    if(size > this.materialCount){
        
        this.UpdateMaterials();
        this.materialCount = size;
    }
    
    this.SetPriority(this.entity.getPosition().z);
};

Spine.prototype.SetAssets = function (atlasAsset, textureAssets, skeletonAsset) {

    this.entity.spine.atlasAsset = atlasAsset.id;
    this.entity.spine.textureAssets = textureAssets.map(function (a) {
        return a.id;
    });
    this.entity.spine.skeletonAsset = skeletonAsset.id;
};

Spine.prototype.UpdateMaterials = function () {
    
    var materialCount = 0;
    //Material settings
    for(var i = 0; i<this.textures.length; i++){
        var material = this.entity.spine.spine._materials[this.textures[i].name];
        if(!material) continue;
        
        if(!this.useAmbientLighting){
            material.ambient.set(0,0,0,1);
            material.ambientTint = true;
        }
        else{

            material.ambientTint = false;
        }

        material.emissiveTint = true;
        material.emissive.set(this.emissiveTint.r,this.emissiveTint.g,this.emissiveTint.b,1);
        
        material.useLighting = false;
        material.update();
    }
};

Spine.prototype.PlayAnimation = function (trackIndex, animationName, loop) {
    this.entity.spine.state.setAnimation(trackIndex, animationName, loop); 
};

Spine.prototype.SetPriority = function (priority) {
    this.priority = priority;
    if (this.entity.spine) {
        this.entity.spine.spine.priority = priority;
    }
};

Spine.prototype.SetTint = function (r, g, b) {
    this.emissiveTint.set(r, g, b, 1);
    
    for(var i = 0; i<this.textures.length; i++){
        var material = this.entity.spine.spine._materials[this.textures[i].name];
        if(material){
            material.emissiveTint = true;
            material.emissive.set(this.emissiveTint.r,this.emissiveTint.g,this.emissiveTint.b, this.emissiveTint.a);
            material.update();
        }
    }
};

Spine.prototype.SetSkin = function (skinName) {
    var skin = this.entity.spine.skeleton.data.findSkin(skinName);
    if(skin){
        this.entity.spine.skeleton.setSkinByName(skinName);
    }
};

Spine.prototype.OnStart = function(track){
    this.fire('start', track);
};

Spine.prototype.OnComplete = function(track){
    this.fire('complete', track);
};

Spine.prototype.OnEvent = function(track,event){
    this.fire('event', track, event);
};

Spine.prototype.OnInterrupt = function(track,event){
    this.fire('interrupt', track, event);
};

