// Sequence.js
var Sequence = pc.createScript('sequence');

Sequence.attributes.add('eventsEntity', {type: 'entity'});
Sequence.attributes.add('totalTime', {type: 'number', default: 5});
Sequence.attributes.add('pauseForDialog', {type: 'boolean', default: false});

// initialize code called once per entity
Sequence.prototype.initialize = function() {
    this.isPlaying = false;
    this.isPaused = false;
    
    this.events = [];
    
    if(this.eventsEntity){
        for(var i = 0; i<this.eventsEntity.children.length; i++){
            if(this.eventsEntity.children[i].enabled){
                this.events.push(this.eventsEntity.children[i].script.sequenceEvent);
            }
            
        }
    }
    
    this.timer = 0;
    this.eventIndex = 0;
    
    if(this.pauseForDialog){
        this.app.on("player:startDialog", this.OnPlayerStartDialog, this);
        this.app.on("player:endDialog", this.OnPlayerEndDialog, this);
        
        this.app.on("player:showGameCompletePopup", this.OnPlayerStartDialog, this);
        this.app.on("player:hideGameCompletePopup", this.OnPlayerEndDialog, this);
    }
    
    
    this.on("destroy", this.OnDestroy);
};

// update code called every frame
Sequence.prototype.postUpdate = function(dt) {
    if(GameManager.Instance.IsPaused()) return;
    
    if(this.isPlaying){
        this.timer += dt;
        for(var i = this.eventIndex; i<this.events.length; i++){
            if(this.timer >= this.events[i].sequenceTime){
                this.events[i].Fire();
                this.eventIndex++;
            }
            else{
                break;
            }
        }

        if(this.timer >= this.totalTime){
            this.playCount++;
            this.OnComplete();
            
            if(this.onCompleteEvent){
                this.onCompleteEvent.Invoke();
            }
        }
    }
};

Sequence.prototype.Play = function() {
    this.timer = 0;
    this.eventIndex = 0;
    this.isPlaying = true;
    this.isPaused = false;
};

Sequence.prototype.Pause = function() {
    this.isPlaying = false;
    this.isPaused = true;
};

Sequence.prototype.Resume = function() {
    this.isPlaying = true;
    this.isPaused = false;
};

Sequence.prototype.Stop = function() {
    this.isPlaying = false;
    this.isPaused = false;
};

Sequence.prototype.OnComplete = function() {
    this.Stop();
};



Sequence.prototype.OnPlayerStartDialog = function() {
    if(this.isPlaying && this.pauseForDialog){
        this.Pause();
    }
};

Sequence.prototype.OnPlayerEndDialog = function() {
    if(!this.isPlaying && this.isPaused && this.pauseForDialog){
        this.Resume();
    }
};

Sequence.prototype.OnDestroy = function() {    
    if(this.pauseForDialog){
        this.app.off("player:startDialog", this.OnPlayerStartDialog, this);
        this.app.off("player:endDialog", this.OnPlayerEndDialog, this);
        
        this.app.off("player:showGameCompletePopup", this.OnPlayerStartDialog, this);
        this.app.off("player:hideGameCompletePopup", this.OnPlayerEndDialog, this);
    }

};

// SequenceEvent.js
var SequenceEvent = pc.createScript('sequenceEvent');

SequenceEvent.attributes.add('sequenceTime', {type: 'number', default: 0});
SequenceEvent.attributes.add('eventEntity', {type: 'entity'});
SequenceEvent.attributes.add('eventValue', {type: 'string'});

// initialize code called once per entity
SequenceEvent.prototype.initialize = function() {
    if(!this.eventEntity){
        this.eventEntity = this.entity;
    }
};

SequenceEvent.prototype.postInitialize = function() {
    this.event = this.eventEntity.playCanvasEvent;
    
    this.eventValue = StringToValue(this.eventValue);
    
};

// update code called every frame
SequenceEvent.prototype.Fire = function() {  
    this.event.Invoke(this.eventValue);
};

// CameraTransform.js
var CameraTransform = pc.createScript('cameraTransform');

CameraTransform.attributes.add('cameraLerpTime', {type: 'number', default: 1});
CameraTransform.attributes.add('cameraLerpEase', {type: 'string', default: "SineInOut"});
CameraTransform.attributes.add('forceFov', {type: 'boolean', default: false});
CameraTransform.attributes.add('cameraLerpBackTime', {type: 'number', default: 0});
CameraTransform.attributes.add('cameraLerpBackEase', {type: 'string', default: "SineInOut"});

// initialize code called once per entity
CameraTransform.prototype.initialize = function() {
    this.on("destroy", this.OnDestroy);
    
    this.cameraLerpEase = pc[this.cameraLerpEase];
    this.cameraLerpBackEase = pc[this.cameraLerpBackEase];
    
    this.active = false;
    
    this.app.on("camera:setActive:" + this.entity.name, this.SetActive, this);
};

CameraTransform.prototype.SetActive = function(active, overwrite) {    
    if(active === undefined) active = true;
    if(active){
        this.active = true;
        
        if(overwrite){
            CameraManager.Instance.OverwritePreviousCameraTransform(this, this.cameraLerpBackTime, this.cameraLerpBackEase);
        }
        else{
            CameraManager.Instance.AddCameraTransform(this, this.cameraLerpTime, this.cameraLerpEase);
        }

        
    }
    else{
        this.active = false;

        if(CameraManager.Instance){
            CameraManager.Instance.RemoveCameraTransform(this, this.cameraLerpBackTime, this.cameraLerpBackEase);
        }        
    }
};

CameraTransform.prototype.SetInactive = function() {    
    this.SetActive(false);
};

CameraTransform.prototype.SetCameraLerpTime = function(time) {       
    this.cameraLerpTime = time;
};

CameraTransform.prototype.SetCameraLerpBackTime = function(time) {       
    this.cameraLerpBackTime = time;
};

    
CameraTransform.prototype.OnDestroy = function() {
    this.app.off("camera:setActive:" + this.entity.name, this.SetActive, this);
    
    if(this.active && CameraManager.Instance){
        CameraManager.Instance.RemoveCameraTransform(this, 0);
    }
};

