// FlagManager.js
var FlagManager = pc.createScript('flagManager');

FlagManager.flags = {};

FlagManager.debugInitFlags = {};

// initialize code called once per entity
FlagManager.prototype.initialize = function() {
    this.app.on("saveGameData", FlagManager.SaveData, this);
    
    FlagManager.flags = {};
    FlagManager.LoadData();
    
    if(Object.keys(FlagManager.debugInitFlags).length > 0){
        FlagManager.flags = Object.assign(FlagManager.flags, FlagManager.debugInitFlags);
    }
    FlagManager.debugInitFlags = {};
    
    this.on("destroy", this.OnDestroy);
};

FlagManager.GetFlag = function(id) {
    if(FlagManager.flags[id] !== undefined){
        return FlagManager.flags[id];
    }
    return null;
};

FlagManager.SetFlag = function(id, value) {
    FlagManager.flags[id] = value;
    pc.app.fire("flagManager:setFlag:"+ id, value);
};

FlagManager.LoadData = function() {
    var saveData = SaveDataManager.Instance.GetGameData("FlagManager");
    
    if(saveData){
        FlagManager.flags = saveData;
    }
};

FlagManager.SaveData = function() {
    var saveData = FlagManager.flags;

    SaveDataManager.Instance.SetGameData("FlagManager", saveData);
};

FlagManager.prototype.OnDestroy = function() {    
    this.app.off("saveGameData", this.SaveData, this);
};

// ElementFillParent.js
var ElementFillParent = pc.createScript('elementFillParent');

ElementFillParent.attributes.add("fillWidth", { type: 'boolean', default: true });
ElementFillParent.attributes.add("fillHeight", { type: 'boolean', default: true });
ElementFillParent.attributes.add("padding", { type: 'vec2' });

// initialize code called once per entity
ElementFillParent.prototype.initialize = function() {
    this.parentElement = this.entity.parent.element;
    this.parentScreen = this.entity.parent.screen;
    
    this.Fill();
};

ElementFillParent.prototype.postInitialize = function() {
    this.Fill();
};

// update code called every frame
ElementFillParent.prototype.update = function(dt) {
    this.Fill();
};

ElementFillParent.prototype.Fill = function() {
   if(this.parentElement){
        if(this.fillWidth)
            this.entity.element.width = this.parentElement.width - this.padding.x;
        if(this.fillHeight)
            this.entity.element.height = this.parentElement.height - this.padding.y;
        
    }
    else if(this.parentScreen){
        if(this.fillWidth)
            this.entity.element.width = this.parentScreen.resolution.x - this.padding.x;
        if(this.fillHeight)
            this.entity.element.height = this.parentScreen.resolution.y - this.padding.y;
    }
};

