// FlagEntityEnabler.js
var FlagEntityEnabler = pc.createScript('flagEntityEnabler');

FlagEntityEnabler.attributes.add('flagID', {type: 'string'});
FlagEntityEnabler.attributes.add('entityToEnable', {type: 'entity'});
FlagEntityEnabler.attributes.add('enabledWhenValueIs', {type: 'string', array: true, default: ["true"]});
FlagEntityEnabler.attributes.add('disabledWhenValueIs', {type: 'string', array: true, default: ["false"]});
FlagEntityEnabler.attributes.add('listenForChanges', {type: 'boolean', default: false});


FlagEntityEnabler.ActionWhenNoMatch = Object.freeze({
    Nothing: 0,
    Enable: 1,
    Disable: 2
});

var attrEnum = [];
for(var key in FlagEntityEnabler.ActionWhenNoMatch){ var obj = {}; obj[key] = FlagEntityEnabler.ActionWhenNoMatch[key]; attrEnum.push(obj); }

FlagEntityEnabler.attributes.add('actionWhenNoMatch', {type: 'number', enum: attrEnum });

// initialize code called once per entity
FlagEntityEnabler.prototype.initialize = function() {
    
    for(var i = 0; i<this.enabledWhenValueIs.length; i++){
        this.enabledWhenValueIs[i] = StringToValue(this.enabledWhenValueIs[i]);
    }
    for(var i = 0; i<this.disabledWhenValueIs.length; i++){
        this.disabledWhenValueIs[i] = StringToValue(this.disabledWhenValueIs[i]);
    }
    
    
    if(!this.entityToEnable){
        this.entityToEnable = this.entity;
    }
    var currentFlagValue = FlagManager.GetFlag(this.flagID); 
    this.CheckForMatches(currentFlagValue);
    

    if(this.listenForChanges){
        this.app.on("flagManager:setFlag:" + this.flagID, this.CheckForMatches, this);
    }
    this.on("destroy", this.OnDestroy);
};

// update code called every frame
FlagEntityEnabler.prototype.update = function(dt) {

};

FlagEntityEnabler.prototype.CheckForMatches = function(value) {
    for(var i = 0; i<this.enabledWhenValueIs.length; i++){
        if(value == this.enabledWhenValueIs[i]){
            this.entityToEnable.enabled = true;
            return;
        }
    }
    for(var i = 0; i<this.disabledWhenValueIs.length; i++){
        if(value == this.disabledWhenValueIs[i]){
            this.entityToEnable.enabled = false;
            return;
        }
    }
    
    switch(this.actionWhenNoMatch){
        case FlagEntityEnabler.ActionWhenNoMatch.Enable:{
            this.entityToEnable.enabled = true;
            break;
        }
        case FlagEntityEnabler.ActionWhenNoMatch.Disable:{
            this.entityToEnable.enabled = false;
            break;
        }
    }
};

FlagEntityEnabler.prototype.OnDestroy = function() {
    this.app.off("flagManager:setFlag:" + this.flagID, this.CheckForMatches, this);
};

