var DeviceOrientationChecker = pc.createScript('deviceOrientationChecker');

DeviceOrientationChecker.attributes.add("rotateImageAsset", {type: 'asset'});


// initialize code called once per entity
DeviceOrientationChecker.prototype.initialize = function() {
    this.isValidOrientation = false;

    this.rotateElement = document.createElement('div');
    this.rotateElement.id = 'rotate-screen';
    this.rotateElement.className = 'hidden';
    this.rotateElement.innerHTML = 'please rotate your device';
    this.rotateElement.style.textIndent = '-100%';
    this.rotateElement.style.backgroundColor = '#000';
    this.rotateElement.style.backgroundImage = "url('" + this.rotateImageAsset.getFileUrl() + "')";
    
    var containerDiv = MPHelper.GetContainerDiv();
    containerDiv.appendChild(this.rotateElement); 


    this.onValidOrientation = null;

    window.addEventListener("resize", this.OnResize.bind(this));
    window.addEventListener("orientationchange", this.CheckOrientation.bind(this));
    
    this.CheckOrientation();
};

// update code called every frame
DeviceOrientationChecker.prototype.update = function(dt) {
    
};

DeviceOrientationChecker.prototype.CheckOrientation = function() {
    this.isValidOrientation = window.innerWidth > window.innerHeight;

    this.rotateElement.className = this.isValidOrientation ? 'hidden' : 'visible';
    if(this.isValidOrientation){
        
    }
    else{

    }
};

DeviceOrientationChecker.prototype.OnResize = function() {
    this.Resize();
    setTimeout(function(){
        this.Resize();
    }.bind(this),50);

};

DeviceOrientationChecker.prototype.Resize = function() {
    var windowWidth = window.innerWidth;
    var windowHeight = window.innerHeight;
    this.rotateElement.style.width = windowWidth + "px";
    this.rotateElement.style.height = windowHeight + "px";

    this.CheckOrientation();
};

// MPDOMButtonFrames.js
var MPDOMButtonFrames = pc.createScript('MPDOMButtonFrames');

MPDOMButtonFrames.attributes.add("unselectedFrameTablet", { type: 'asset', title: "Unselected Frame (Tablet)" });
MPDOMButtonFrames.attributes.add("selectedFrameTablet", { type: 'asset', title: "Selected Frame (Tablet)" });
MPDOMButtonFrames.attributes.add("disabledFrameTablet", { type: 'asset', title: "Disabled Frame (Tablet)" });
MPDOMButtonFrames.attributes.add("unselectedFrameMobile", { type: 'asset', title: "Unselected Frame (Mobile)" });
MPDOMButtonFrames.attributes.add("selectedFrameMobile", { type: 'asset', title: "Selected Frame (Mobile)" });
MPDOMButtonFrames.attributes.add("disabledFrameMobile", { type: 'asset', title: "Disabled Frame (Mobile)" });


// initialize code called once per entity
MPDOMButtonFrames.prototype.initialize = function() {
    this.MPDOMButton = this.entity.MPDOMButton;

    this.MPDOMButton.on("updatedClass", this.UpdateFrames, this);
    this.MPDOMButton.on("over", this.UpdateFrames, this);
    this.MPDOMButton.on("out", this.UpdateFrames, this);
    //this.MPDOMButton.on("state", this.UpdateFrames, this);
    this.MPDOMButton.on("enable", this.UpdateFrames, this);
    this.MPDOMButton.on("disable", this.UpdateFrames, this);
    this.UpdateFrames();
    
    
    this.unselectedFrame = null;
    this.selectedFrame = null;
    this.disabledFrame = null;
    
    switch(this.MPDOMButton.buttonSize){
        case "mobile":{
            this.unselectedFrame = this.unselectedFrameMobile ? this.unselectedFrameMobile : this.unselectedFrameTablet;
            this.selectedFrame = this.selectedFrameMobile ? this.selectedFrameMobile : this.selectedFrameTablet;
            this.disabledFrame = this.disabledFrameMobile ? this.disabledFrameMobile : this.disabledFrameTablet;
            break;
        }
        case "tablet":{
            this.unselectedFrame = this.unselectedFrameTablet;
            this.selectedFrame = this.selectedFrameTablet;
            this.disabledFrame = this.disabledFrameTablet;
            break;
        }
    }

    this.isUpdatingFrames = false;
    
    
};

// update code called every frame
MPDOMButtonFrames.prototype.update = function(dt) {

};

MPDOMButtonFrames.prototype.UpdateFrames = function() {
    if(this.isUpdatingFrames) return;
    
    this.MPDOMButton = this.entity.MPDOMButton;

    this.isUpdatingFrames = true;
    
    this.MPDOMButton.off("out", this.UpdateFrames, this);
    
    if(this.MPDOMButton.buttonEntity.button.active){
        if(this.MPDOMButton.isOver){
            this.MPDOMButton.SetSprite(this.selectedFrame, true);
        }
        else{
            this.MPDOMButton.SetSprite(this.unselectedFrame, true);
        }
        
    }
    else{
        this.MPDOMButton.SetSprite(this.disabledFrame, true);
    }    
    
    
    this.MPDOMButton.on("out", this.UpdateFrames, this);
    this.isUpdatingFrames = false;
};

// MPDOMToggleButtonFrames.js
var MPDOMToggleButtonFrames = pc.createScript('MPDOMToggleButtonFrames');

if (!MPDOMButtonFrames)
      var MPDOMButtonFrames = function() {};
MPDOMToggleButtonFrames.prototype = Object.create(MPDOMButtonFrames.prototype);
MPDOMToggleButtonFrames.prototype.constructor = MPDOMToggleButtonFrames;

MPDOMToggleButtonFrames.attributes.add("unselectedToggleOnFrameTablet", { type: 'asset' });
MPDOMToggleButtonFrames.attributes.add("selectedToggleOnFrameTablet", { type: 'asset' });
MPDOMToggleButtonFrames.attributes.add("disabledToggleOnFrameTablet", { type: 'asset' });
MPDOMToggleButtonFrames.attributes.add("unselectedToggleOnFrameMobile", { type: 'asset' });
MPDOMToggleButtonFrames.attributes.add("selectedToggleOnFrameMobile", { type: 'asset' });
MPDOMToggleButtonFrames.attributes.add("disabledToggleOnFrameMobile", { type: 'asset' });

MPDOMToggleButtonFrames.attributes.add("unselectedToggleOffFrameTablet", { type: 'asset' });
MPDOMToggleButtonFrames.attributes.add("selectedToggleOffFrameTablet", { type: 'asset' });
MPDOMToggleButtonFrames.attributes.add("disabledToggleOffFrameTablet", { type: 'asset' });
MPDOMToggleButtonFrames.attributes.add("unselectedToggleOffFrameMobile", { type: 'asset' });
MPDOMToggleButtonFrames.attributes.add("selectedToggleOffFrameMobile", { type: 'asset' });
MPDOMToggleButtonFrames.attributes.add("disabledToggleOffFrameMobile", { type: 'asset' });

// initialize code called once per entity
MPDOMToggleButtonFrames.prototype.initialize = function() {
    MPDOMButtonFrames.prototype.initialize.call(this);

    this.MPDOMButton.on("toggle", this.UpdateToggleFrames, this);
    
    switch(this.MPDOMButton.buttonSize){
        case "mobile":{
            this.unselectedToggleOnFrame = this.unselectedToggleOnFrameMobile ? this.unselectedToggleOnFrameMobile : this.unselectedToggleOnFrameTablet;
            this.selectedToggleOnFrame = this.selectedToggleOnFrameMobile ? this.selectedToggleOnFrameMobile : this.selectedToggleOnFrameTablet;
            this.disabledToggleOnFrame = this.disabledToggleOnFrameMobile ? this.disabledToggleOnFrameMobile : this.disabledToggleOnFrameTablet;
            
            this.unselectedToggleOffFrame = this.unselectedToggleOffFrameMobile ? this.unselectedToggleOffFrameMobile : this.unselectedToggleOffFrameTablet;
            this.selectedToggleOffFrame = this.selectedToggleOffFrameMobile ? this.selectedToggleOffFrameMobile : this.selectedToggleOffFrameTablet;
            this.disabledToggleOffFrame = this.disabledToggleOffFrameMobile ? this.disabledToggleOffFrameMobile : this.disabledToggleOffFrameTablet;
            break;
        }
        case "tablet":{
            this.unselectedToggleOnFrame = this.unselectedToggleOnFrameTablet;
            this.selectedToggleOnFrame = this.selectedToggleOnFrameTablet;
            this.disabledToggleOnFrame = this.disabledToggleOnFrameTablet;
            
            this.unselectedToggleOffFrame = this.unselectedToggleOffFrameTablet;
            this.selectedToggleOffFrame = this.selectedToggleOffFrameTablet;
            this.disabledToggleOffFrame = this.disabledToggleOffFrameTablet;
            break;
        }
    }
    
    this.UpdateToggleFrames();
};

// update code called every frame
MPDOMToggleButtonFrames.prototype.update = function(dt) {
    MPDOMButtonFrames.prototype.update.call(this, dt);
};

MPDOMToggleButtonFrames.prototype.UpdateToggleFrames = function() {
    if(this.MPDOMButton.toggle){
        this.unselectedFrame = this.unselectedToggleOnFrame;
        this.selectedFrame = this.selectedToggleOnFrame;
        this.disabledFrame = this.disabledToggleOnFrame;
    }
    else{
        this.unselectedFrame = this.unselectedToggleOffFrame;
        this.selectedFrame = this.selectedToggleOffFrame;
        this.disabledFrame = this.disabledToggleOffFrame;
    }
    
    
    this.UpdateFrames();
};


