// CameraShake.js
var CameraShake = pc.createScript('cameraShake');

CameraShake.attributes.add("shakeInterval", {type: "number", default: 0.1, title: "Camera Shake Interval"});
CameraShake.attributes.add("maxShakeDistance", {type: "number", default: 0.1, title: "Max Shake Distance"});
CameraShake.attributes.add("duration", {type: "number", default: 1, title: "Duration"});


// initialize code called once per entity
CameraShake.prototype.initialize = function() {
    this.time = this.duration;
    this.timeSinceLastShake = 0;
    
};

// update code called every frame
CameraShake.prototype.update = function(dt) {
    this.time += dt;
    
    if (this.time < this.duration || this.duration == -1) {
        this.timeSinceLastShake += dt;

        if (this.timeSinceLastShake >= this.shakeInterval) {
            // Use this to reduce the maximum shake distance over the duration of the effect
            var v = 1 - pc.math.clamp(this.time / this.duration, 0, 1);

            // Find a point in a disc to offset the camera by
            // Taken from http://stackoverflow.com/questions/5837572/generate-a-random-point-within-a-circle-uniformly
            var t = 2 * Math.PI * pc.math.random(0, 1);
            var u = pc.math.random(0, this.maxShakeDistance) * v + pc.math.random(0, this.maxShakeDistance) * v;
            var r = u > 1 ? 2-u : u; 

            var x = r * Math.cos(t);
            var y = r * Math.sin(t);
            
            var z = this.entity.getLocalPosition().z;
            this.entity.setLocalPosition(x, y, z);     
            this.timeSinceLastShake -= this.shakeInterval; 
        }    
    }
};

CameraShake.prototype.Start = function (shakeInterval, maxShakeDistance, duration) {
    this.time = 0;   
    this.shakeInterval = shakeInterval;
    this.maxShakeDistance = maxShakeDistance;
    this.duration = duration;
};

CameraShake.prototype.Stop = function () {
    this.duration = this.shakeInterval;
};


// SplashScreen.js
var SplashScreen = pc.createScript('splashScreen');

if (!MPScene)
      var MPScene = function() {};
SplashScreen.prototype = Object.create(MPScene.prototype);
SplashScreen.prototype.constructor = SplashScreen;

SplashScreen.attributes.add('splashImageEntity', {type: 'entity'});

// initialize code called once per entity
SplashScreen.prototype.initialize = function() {
    MPScene.prototype.initialize.call(this);

    this.proceedToMainMenu = false;
    
    this.splashImage = this.splashImageEntity.element;
    
    this.splashImage.opacity = 0;
    this.splashImageEntity.setLocalScale(0.5, 0.5, 1);
    
    this.scaleTween = this.splashImageEntity.tween(this.splashImageEntity.getLocalScale());
    this.scaleTween.to({x: 1, y: 1, z: 1}, 1.66, pc.SineOut);
    this.scaleTween.start();
    
    this.fadeTween = this.splashImageEntity.tween(this.splashImage);
    this.fadeTween.to({opacity: 1}, 1.66, pc.SineOut);
    this.fadeTween.on("complete", this.OnFadeInTweenComplete, this);
    this.fadeTween.start();

    this.hasPlayedIntro = SaveDataManager.Instance.GetGameData("hasPlayedIntro");
};

// update code called every frame
SplashScreen.prototype.update = function(dt) {
    if(this.proceedToMainMenu){
        if(this.hasPlayedIntro){
            SceneManager.Instance.SetState("MainMenu");
        }
        else{
            SceneManager.Instance.SetState("IntroScreen");
        }
        
        this.proceedToMainMenu = false;
    }
    
};

SplashScreen.prototype.OnFadeInTweenComplete = function() {
    this.fadeTween = this.splashImageEntity.tween(this.splashImage);
    this.fadeTween.to({opacity: 0}, 1, pc.SineIn, 0.66);
    this.fadeTween.on("complete", this.OnFadeOutTweenComplete, this);
    this.fadeTween.start();
};

SplashScreen.prototype.OnFadeOutTweenComplete = function() {
    this.proceedToMainMenu = true;
};

