MPHelper.ClearData = function() {
    var settings = pc.gmi.getAllSettings();
    var gameData = settings.gameData;
    gameData = undefined;
};

MPHelper.GetContainerDiv = function() {
    if (pc.gmi === null || pc.gmi === undefined) {
        return document.body;
    }

    return document.getElementById(pc.gmi.gameContainerId);
};

MPHelper.GetGameDir = function() {
    if (pc.gmi === null || pc.gmi === undefined) {
        return '';
    }

    return  pc.gmi.gameDir;
};

MPHelper.GetEnvironment = function() {
    if (pc.gmi === null || pc.gmi === undefined) {
        return 'dev';
    }

    return pc.gmi.environment;
};

MPHelper.LoadData = function(id) {
    if(pc.gmi){
        id = id.toString();
        var settings = pc.gmi.getAllSettings();
        var gameData = settings.gameData;
        if(gameData && gameData[id] !== null && gameData[id] !== undefined) {
            return (gameData[id]);
        }
        return null;
    }
    else{
        
        try {
            if(window.localStorage){
                var data = window.localStorage.getItem(id);
                var t = 0; 
                for(var x in localStorage){ 
                    if(localStorage[x].length){
                        t += (((localStorage[x].length * 2))); 
                    }
                    
                } 
                console.log("Local Storage Size: " + t/1024+ " KB");
                return JSON.parse(data);
            }
            
        }
        catch(e){}
        return null;
    }
};


MPHelper.SaveData = function(id, data) {
    if(pc.gmi){
        pc.gmi.setGameData(id, CloneArray(data));
    }
    else{

        try {
            window.localStorage.setItem(id, JSON.stringify(data));
        } catch (e) {
            // console.error("Failed to save data, check console");
            // console.log(CloneObject(data, true));
            // console.log(e);
            // console.break();
        }
    }
};



