// ScrollRect.js
var ScrollRect = pc.createScript('scrollRect');

ScrollRect.attributes.add('scrollEntity', { type: 'entity' , title: "Scroll Entity"});
ScrollRect.attributes.add('scrollAxis', {type: 'number', title: 'ScrollAxis', 
    enum:[
        { 'Horizontal': 1 },
        { 'Vertical': 2 },
        { 'HorizontalAndVertical': 3 },
    ],
    default: 2
});

// initialize code called once per entity
ScrollRect.prototype.initialize = function() {
    this.scrollVelocity = new pc.Vec2(0,0);
    this.scrollEntityStartPosition = this.scrollEntity.getLocalPosition().clone();
    
    this.lockX = this.scrollAxis == 2;
    this.lockY = this.scrollAxis == 1;
    
    
    this.oldTargetX = 0;
    this.oldTargetY = 0;
    this.targetX = 0;
    this.targetY = 0;
    
    
    this.isPointerOnRect = false;
    this.isMouseDown = false; 
    this.isTouchDown = false;
    
    this.mouseDownFunction = this.OnMouseDown.bind(this);
    this.mouseUpFunction = this.OnMouseUp.bind(this);
    this.mouseMoveFunction = this.OnMouseMove.bind(this);
    
    this.touchDownFunction = this.OnTouchDown.bind(this);
    this.touchUpFunction = this.OnTouchUp.bind(this);
    this.touchMoveFunction = this.OnTouchMove.bind(this);
    
    this.on("enable", this.OnEnable);
    this.on("disable", this.OnDisable);    
    this.on("destroy", this.OnDestroy);
};

// update code called every frame
ScrollRect.prototype.update = function(dt) {
    
    
    if(this.isPointerOnRect && (this.targetX && this.targetY) && (this.targetX !== this.oldTargetX || this.targetY !== this.oldTargetY)){
        if(!this.lockX){
            this.scrollVelocity.x = (this.targetX - this.oldTargetX)  * (1000 / window.innerWidth);
        }
        if(!this.lockY){
            this.scrollVelocity.y = -(this.targetY - this.oldTargetY) * (1000 / window.innerHeight);
        }
    }
    else{
        var deceleration = 1 - (10 * dt);
        //Slow down velocity
        if(this.scrollVelocity.x !== 0){
            this.scrollVelocity.x *= deceleration;
            if(Math.abs(this.scrollVelocity.x) < 0.1){
                this.scrollVelocity.x = 0;
            }
        }
        
        if(this.scrollVelocity.y !== 0){
            this.scrollVelocity.y *= deceleration;
            if(Math.abs(this.scrollVelocity.y) < 0.1){
                this.scrollVelocity.y = 0;
            }
        }
        
    }
    
    if(this.scrollVelocity.x !== 0 || this.scrollVelocity.y !== 0){
        this.ScrollEntity(dt);
    }
    
    this.oldTargetX = this.targetX;
    this.oldTargetY = this.targetY;
};

ScrollRect.prototype.ScrollEntity = function(dt) {
    this.scrollEntity.translate(this.scrollVelocity.x * 0.12 * dt, this.scrollVelocity.y * 0.12 * dt, 0);
};


ScrollRect.prototype.OnEnable = function() {
    this.scrollVelocity.set(0,0);
    this.scrollEntity.setLocalPosition(this.scrollEntityStartPosition.x, this.scrollEntityStartPosition.y, this.scrollEntityStartPosition.z);
    
    window.addEventListener('mousedown', this.mouseDownFunction, true);
    window.addEventListener('mouseup', this.mouseUpFunction, true);
    window.addEventListener('mousemove', this.mouseMoveFunction, true);
    document.addEventListener("mouseout", this.mouseUpFunction, true);
    
    window.addEventListener('touchstart', this.touchDownFunction, true);
    window.addEventListener('touchend', this.touchUpFunction, true);
    window.addEventListener('touchmove', this.touchMoveFunction, true);
};

ScrollRect.prototype.OnDisable = function() {
    this.isMouseDown = false;
    this.isTouchDown = false;
    
    window.removeEventListener('mousedown', this.mouseDownFunction, true);
    window.removeEventListener('mouseup', this.mouseUpFunction, true);
    window.removeEventListener('mousemove', this.mouseMoveFunction, true);
    document.removeEventListener("mouseout", this.mouseUpFunction, true);
    
    window.removeEventListener('touchstart', this.touchDownFunction, true);
    window.removeEventListener('touchend', this.touchUpFunction, true);
    window.removeEventListener('touchmove', this.touchMoveFunction, true);
    
};

ScrollRect.prototype.OnMouseDown = function(event) {    
    this.isMouseDown = true;
    this.UpdatePointer(event);

    this.oldTargetX = this.targetX;
    this.oldTargetY = this.targetY;
};

ScrollRect.prototype.OnMouseMove = function(event) {   
    if(this.isMouseDown && this.isPointerOnRect){
        this.UpdatePointer(event);
    }
    
};

ScrollRect.prototype.OnMouseUp = function(event) { 
    this.isMouseDown = false;
};



ScrollRect.prototype.OnTouchDown = function(event) {   
    this.isTouchDown = true;
    this.UpdatePointer(event.touches[0]);

    this.oldTargetX = this.targetX;
    this.oldTargetY = this.targetY;
};

ScrollRect.prototype.OnTouchMove = function(event) {   
    if(this.isTouchDown && this.isPointerOnRect){
        this.UpdatePointer(event.touches[0]);
    }
    
};

ScrollRect.prototype.UpdatePointer = function(event) {    
    this.CalcMouseCoords(event);
    this.CalcPointerOnRect();
};

ScrollRect.prototype.OnTouchUp = function(event) { 
    this.isTouchDown = false;
};

ScrollRect.prototype.OnDestroy = function() {
    this.OnDisable();
};

ScrollRect.prototype.CalcPointerOnRect = function() {
    this.isPointerOnRect = false;
    
    var cameras = pc.app.systems.camera.cameras;
    for (var i = cameras.length - 1; i >= 0; i--) {
        var camera = cameras[i];

        this.isPointerOnRect = CheckElement2d(touch.x, touch.y, this.entity.element, camera);//pc.app.elementInput._checkElement2d(this.targetX, this.targetY, this.entity.element, camera);
        
        if(this.isPointerOnRect)
            break;
    }
};


ScrollRect.prototype.CalcMouseCoords = function (event) {
    var rect = pc.app.elementInput._target.getBoundingClientRect();
    var left = Math.floor(rect.left);
    var top = Math.floor(rect.top);

    // mouse is outside of canvas
    if (event.clientX < left ||
        event.clientX >= left + pc.app.elementInput._target.clientWidth ||
        event.clientY < top ||
        event.clientY >= top + pc.app.elementInput._target.clientHeight) {

        this.targetX = null;
        this.targetY = null;
    } else {
        // calculate coords and scale them to the graphicsDevice size
        this.targetX = (event.clientX - left);
        this.targetY = (event.clientY - top);
    }
};


