var AssetLoader = pc.createScript('assetLoader');

AssetLoader.attributes.add('sceneLoaderEntity', {
    type: 'entity',
    title: "Scene Loader",
    description: "Scene Loader entity"
});

AssetLoader.attributes.add('loadingScenes', {
    type: 'string',
    array: true,
    title: "Scene(s) to load with",
    description: "Scenes which we load these assets for"
});

AssetLoader.attributes.add('unloadingScenes', {
    type: 'string',
    array: true,
    title: "Scene(s) to unload for",
    description: "Scenes which we unload these assets for"
});

AssetLoader.attributes.add('languages', {
    type: 'string',
    array: true,
    title: "Languages(s) to load for",
    description: "Leave empty to load for all languages"
});

AssetLoader.attributes.add('assetsToLoad', {
    type: 'asset',
    array: true,
    title: "Assets to Load",
    description: "Array of assets we'll be loading"
});


AssetLoader.prototype.initialize = function() {
    this.sceneLoader = this.sceneLoaderEntity.script.sceneLoader;
    
    if(this.languages.length > 0){
        var lang = this.app.i18n.locale;
        var languageMatches = false;
        for(var i = 0; i<this.languages.length; i++){
            if(lang == this.languages[i]){
                languageMatches = true;
                break;
            }
        }

        if(!languageMatches){
            return;
        }
    }

    if(this.ShouldLoad()){
        this.sceneLoader.AddAssetLoader(this);
        GameManager.Instance.AddAssetBundle(this.assetsToLoad, this.unloadingScenes, this.entity.name);
        return;
    }    
    
};

AssetLoader.prototype.ShouldLoad = function() {
    for(var i = 0; i<this.loadingScenes.length; i++){
        var scene = this.loadingScenes[i] || LevelBundleScene[this.loadingScenes[i]];
        if(DoesArrayContain(SceneLoader.scenesToLoad, scene)){
            return true;
        }
    }    
    
};

