// AddAudioLayer.js
var AddAudioLayer = pc.createScript('addAudioLayer');

AddAudioLayer.attributes.add("layer", { type: "string" });
AddAudioLayer.attributes.add("subtitles", { type: "boolean" });
AddAudioLayer.attributes.add("volume", { type: "number", min: 0, max: 2, default: 1 });
AddAudioLayer.attributes.add("overlap", { type: "boolean", default: true, description: "Can each individual sound overlap/play multiple of itself at once?" });
AddAudioLayer.attributes.add("loop", { type: "boolean", default: false });
AddAudioLayer.attributes.add("solo", { type: "boolean", default: false, description: "Should only 1 sound play on this layer at a time? Playing a sound will stop others" });
AddAudioLayer.attributes.add("sounds", { type: "asset", array: true , title: "Sounds"});

AddAudioLayer.attributes.add("destroy", { type: "boolean", default: true });

AddAudioLayer.prototype.initialize = function() {
    //if(Device.Instance().deviceQuality <= 1) return;
    
    var layer = AudioManager.Instance.AddAudioLayer(this.layer, this.sounds,{
        subtitles: this.subtitles, 
        overlap: this.overlap,
        volume: this.volume,
        loop: this.loop,
        solo: this.solo
    });
    
    this.on('attr:volume', this.OnAttributeVolumeChanged, this);

    this.on("destroy", this.OnDestroy, this);
};

AddAudioLayer.prototype.OnDestroy = function() {
    if (this.destroy) {
        AudioManager.Instance.RemoveAudioFromLayer(this.layer, this.sounds);
    }
};

AddAudioLayer.prototype.OnAttributeVolumeChanged = function(value, prev) {
    var layer = AudioManager.Instance.GetLayer(this.layer);
    
    if(layer){
        layer.SetVolume(value);
    }
};

