// AudioManager.js
var AudioManager = pc.createScript("audioManager");

AudioManager.prototype.initialize = function() {
    AudioManager.Instance = this;
    
    this.audioEnabled = true; 
    
    this.audioLayers = [];
    
    this.howlCache = {};
    this.useHowler = true;
    
    if(!this.useHowler){
        this.entity.addComponent("sound");
        this.sound = this.entity.sound;
        this.sound.positional = false;
    }

    this.onWindowBlur = this.OnWindowBlur.bind(this);
    this.onWindowFocus = this.OnWindowFocus.bind(this);
    this.onVisibilityChange = this.OnVisibilityChange.bind(this);
    
    window.addEventListener("blur", this.onWindowBlur);
    window.addEventListener("focus", this.onWindowFocus);
    document.addEventListener("visibilitychange", this.onVisibilityChange);    
};

AudioManager.prototype.postInitialize = function() {
    this.LoadData();
};


AudioManager.prototype.update = function(dt) {
    if(!this.useHowler){
        this.sound.volume = this.audioEnabled ? 1 : 0;
    }
    else{
        if(Howler._muted && this.audioEnabled){
            Howler.mute(false);
        }
    }
};

AudioManager.prototype.ToggleAudioEnabled = function() {
    this.audioEnabled = !this.audioEnabled;
    if(this.useHowler){
       Howler.mute(!this.audioEnabled);
    }
    else{
        this.sound.volume = this.audioEnabled ? 1 : 0;
    }
    this.SaveData();
};

AudioManager.prototype.AddAudioLayer = function(layerName, sounds, config) {
    var layer = this.GetLayer(layerName);
    
    if(!layer){
        config.useHowler = this.useHowler;
        config.soundComponent = this.sound;
        
        layer = new AudioLayer(layerName, config);
        this.audioLayers.push(layer);
    }
    
    layer.AddSounds(sounds);
    
    return layer;
};


AudioManager.prototype.RemoveAudioFromLayer = function(layerKey, sounds) {
    var layer = this.GetLayer(layerKey);
    if (!layer) return;
    
    layer.RemoveSounds(sounds);

    if(layer.sounds.length === 0){
        this.DestroyLayer(layerKey);
    }
};


AudioManager.prototype.Play = function(layerKey, soundKey, config) {
    var layer = this.GetLayer(layerKey);

    if (!layer) return;

    return layer.Play(soundKey, config);
};

AudioManager.prototype.Stop = function(layerKey, soundKey, config) {
    var layer = this.GetLayer(layerKey);

    if (!layer) return;

    return layer.Stop(soundKey, config);
};

AudioManager.prototype.StopAll = function(layerKey) {
    var layer = this.GetLayer(layerKey);

    if (!layer) return;

    return layer.StopAll();
};

AudioManager.prototype.GetLayer = function(layerKey) {
    for (var i = 0; i < this.audioLayers.length; i++) {
        var layer = this.audioLayers[i];
        if (layer.name == layerKey) return layer;
    }
    
    return null;
};

AudioManager.prototype.PauseLayer = function(layerKey) {
    var layer = this.GetLayer(layerKey);
    if (!layer) return;
    
    layer.Pause();
};

AudioManager.prototype.ResumeLayer = function(layerKey) {
    var layer = this.GetLayer(layerKey);
    if (!layer) return;
    
    layer.Resume();
};

AudioManager.prototype.DestroyLayer = function(layerKey) {    
    var layer = this.GetLayer(layerKey);
    if (!layer) return;
    
    layer.Destroy();
    
    var indexOf = this.audioLayers.indexOf(layer);
    this.audioLayers.splice(indexOf, 1);
};


AudioManager.prototype.LoadSoundAsset = function(asset) {
    
    if(this.useHowler){
        var prefix = pc.app.assets.prefix ? pc.app.assets.prefix : "";
        var audioAsset = {
            key: asset.key,
            url: prefix + asset.file.url
        };
        this.LoadHowlSound(audioAsset);
    }
    else{
        this.app.assets.load(asset);
    }
};

AudioManager.prototype.LoadHowlSound = function(file) {
    if(!this.howlCache[file.key]){
            
        this.howlCache[file.key] = new Howl({
            src: file.url
        });    
        
        this.howlCache[file.key].name = file.key;
    }

    return this.howlCache[file.key];
};

AudioManager.prototype.HasSoundAssetLoaded = function(asset) {
    if(this.useHowler){
        return this.howlCache[asset.key].state() == "loaded";
    }
    else{
        return asset.loaded;
    }
};



AudioManager.prototype.UnloadSoundAsset = function(asset) {
    if(this.useHowler){
        this.UnloadHowlSound({key: asset.key});
    }
    else{
        asset.unload();
    }
};

AudioManager.prototype.UnloadHowlSound = function(file) {
    if(this.howlCache[file.key]){
            
        //this.howlCache[file.key].unload();
       
        this.howlCache[file.key].stop();
        this.howlCache[file.key] = null;
    }
};

AudioManager.prototype.OnWindowBlur = function() {
    if(this.useHowler){
       Howler.mute(true);
    }
    
};

AudioManager.prototype.OnWindowFocus = function() {
    if(this.useHowler){
       Howler.mute(!this.audioEnabled);
    }
    
};

AudioManager.prototype.OnVisibilityChange = function() {
    if(document.visibilityState == 'hidden'){
        this.OnWindowBlur();
    }
    else{
        this.OnWindowFocus();
    }

};

AudioManager.prototype.LoadData = function() {
    this.audioEnabled = MPHelper.GetAudio();   
    if(this.useHowler){
       Howler.mute(!this.audioEnabled);
    }
};

AudioManager.prototype.SaveData = function() {
    MPHelper.SetAudio(this.audioEnabled);
};




