var CameraViewportMatch = pc.createScript('cameraViewportMatch');

// initialize code called once per entity
CameraViewportMatch.prototype.initialize = function() {
    this.camera = this.entity.camera;
    
    this.rect = new pc.Vec4();
    
    this._resize = this.ResizeRect.bind(this);
    window.addEventListener("resize", this._resize, true);
    this.on("destroy", this.Destroy);
    
    this.ResizeRect();
};

// update code called every frame
CameraViewportMatch.prototype.update = function(dt) {
    
};

CameraViewportMatch.prototype.ResizeRect = function() {
    var aspectScalar = Math.min(ScaleManager.Instance.aspectRatio / ScaleManager.Instance.screenAspectRatio, 1);
    var x = pc.math.lerp(1-aspectScalar, 0, 0.5);
    this.rect.set(x, 0, aspectScalar, 1);
    this.camera.rect = this.rect;
};

CameraViewportMatch.prototype.Destroy = function() {
    window.removeEventListener("resize", this._resize, true);
};

