GetWorldVolume = function(emitterPosition, dropoffDistance){
    if(dropoffDistance === undefined) dropoffDistance = 7;
    
    var listenerPosition = Player.Position;//CameraManager.Instance.GetActiveCameraEntity().getPosition();// Player.Position.clone();
    
    
    var distance = Math.distanceV3(emitterPosition, listenerPosition);
    var volume = 1 - Math.min(1, distance / (dropoffDistance * dropoffDistance));
    
    return volume;
};

ScreenToUI = function(screenPosition){
    screenPosition.x -= (pc.app.graphicsDevice.canvas.width / GetDevicePixelRatio()) * 0.5;
    screenPosition.y -= (pc.app.graphicsDevice.canvas.height / GetDevicePixelRatio()) * 0.5;

    var scalar = ScaleManager.Instance.defaultHeight / window.innerHeight;

    screenPosition.x *= scalar;
    screenPosition.y *= -scalar;
    return screenPosition;
};

GetDevicePixelRatio = function(){
    var devicePixelRatio = window.devicePixelRatio;
    if(Device.Instance().desktop && Device.Instance().macOS){
        devicePixelRatio = 1;
    }
    return devicePixelRatio;
};

Math.toDegrees = function(radians) {
    return radians * (180.0 / 3.14);
};

Math.toRadians = function(degrees) {
    return degrees * (3.14 / 180.0);
};

Math.GetDifferenceInLoopedRange = function(min, max, a, b) {
    var normalRange = Math.abs(a-b);

    var lowerVar = a < b ? a : b;
    var higherVar = a < b ? b : a;
    var loopedRange = Math.abs(max - higherVar) + Math.abs(min - lowerVar);
    return Math.min(normalRange, loopedRange);
};

Math.ClampInLooped = function (min, max, value){
    var offsetFromMin = value - min;
    var difference = max - min;
    return min + mod(offsetFromMin, difference);
};

Math.IsValueBetween = function (a, b, vcalue){
    var lowerVar = a < b ? a : b;
    var higherVar = a < b ? b : a;
    return value >= lowerVar && value <= higherVar;
};

Math.dist=function(x1,y1,x2,y2){ 
  if(!x2) x2=0; 
  if(!y2) y2=0;
  return Math.sqrt((x2-x1)*(x2-x1)+(y2-y1)*(y2-y1)); 
};

Math.distSqr=function(x1,y1,x2,y2){ 
  if(!x2) x2=0; 
  if(!y2) y2=0;
  return ((x2-x1)*(x2-x1)+(y2-y1)*(y2-y1)); 
};

Math.distanceV3 = function(a, b) {
    var vector = {x: a.x - b.x, y: a.y - b.y, z: a.z - b.z};
    return Math.sqrt(vector.x * vector.x + vector.y * vector.y + vector.z * vector.z);
};

Math.randomInt = function(min, max) {
  min = Math.ceil(min);
  max = Math.floor(max);
  return Math.floor(Math.random() * (max - min + 1)) + min;
};

IsPointOnScreen = function (screenPos){
    if(screenPos.x >= 0 && screenPos.y >= 0 && screenPos.x <= window.innerWidth && screenPos.y <= window.innerHeight){
        return true;
    }
    
    return false;
};

mod = function(n,m){
    return ((n % m) + m) % m;
};

PingPong = function(t, length)
{
    t = Repeat(t, length * 2.0);
    return length - Math.abs(t - length);
};

Repeat = function(t, length)
{
    return t - Math.floor(t / length) * length;
};

ShuffleArray = function(array) {
    var currentIndex = array.length, temporaryValue, randomIndex ;

    while (0 !== currentIndex) {
        randomIndex = Math.floor(Math.random() * currentIndex);
        currentIndex -= 1;

        temporaryValue = array[currentIndex];
        array[currentIndex] = array[randomIndex];
        array[randomIndex] = temporaryValue;
    }
};

IsNumber = function(n) {
  return !isNaN(parseFloat(n)) && isFinite(n);
};

ResizeElementToMatchTexture = function(element) {
    element.width = element.texture.width;
    element.height = element.texture.height;
};

ResizeElementToMatchSprite = function(element) {
    var rect = element.sprite.atlas.frames[element.sprite.frameKeys[0]].rect;
    element.width = rect.z;
    element.height = rect.w;
};

RotateVec2 = function(vec2, degrees) {
    var sin = Math.sin(degrees * pc.math.DEG_TO_RAD);
    var cos = Math.cos(degrees * pc.math.DEG_TO_RAD);
         
    var tx = vec2.x;
    var ty = vec2.y;

    vec2.x = (cos * tx) - (sin * ty);
    vec2.y = (sin * tx) + (cos * ty);
    return vec2;
};

GetRealEulerY = function(euler) {

    if(euler.x === 180 || euler.x === -180){
        var offset = 90 - euler.y;
        euler.y = 90 + offset;
    }

    return euler.y;

};

