DoesArrayContain = function(a, obj) {
    for (var i = 0; i < a.length; i++) {
        if (a[i] === obj) {
            return true;
        }
    }
    return false;
};

GetLoadedAssets = function(full, filter) {
    // Get a list of loaded assets, using [filter] if provided.
    var loaded = pc.app.assets.filter(function(asset) {
        if (!asset.loaded) return false;
        
        if (filter) {
            if (filter.constructor === Array) {
                for (var i = 0; i < filter.length; i++) {
                    if (asset.type == filter[i])
                        return true;
                }

                return false;
            }
            else {
                return asset.type == filter;
            }
        }
    });
    
    // Create a copy of this list and initialise [previousLoaded] if needed.
    var newLoaded = loaded.slice(0);
    pc.previousLoaded = pc.previousLoaded || [];
    var previousLoaded = pc.previousLoaded;
    
    // Filter the copied list such that only different (i.e. new) files remain.
    for (var i = 0; i < newLoaded.length; i++) {
        for (var j = 0; j < previousLoaded.length; j++) {
            if (newLoaded[i].name == previousLoaded[j].name) {
                newLoaded.splice(i, 1);
                continue;
            }
        }
    }
    
    // Show the raw lists, with the full objects + properties.
    if (full) {
        console.log("[Get Loaded Assets]\nLoaded:\n", loaded, "\nNew assets:\n", newLoaded.toString());
    }
    // Show abriged versions of the lists; with index, type and name.
    else {
        var loadedNames = [];
        for (var i = 0; i < loaded.length; i++) {
            loadedNames.push("[" + (i + 1) + " / " + loaded.length + "] (" + loaded[i].type + ") " + loaded[i].name);
        }

        var newLoadedNames = [];
        for (var i = 0; i < newLoaded.length; i++) {
            newLoadedNames.push("[" + (i + 1) + " / " + newLoaded.length + "] (" + newLoaded[i].type + ") " + newLoaded[i].name);
        }
        
        console.log("[Get Loaded Assets]\nLoaded:\n", loadedNames, "\nNew assets:\n", newLoadedNames);
    }
    
    // Update the [previousLoaded] value for the next time we call this function.
    pc.previousLoaded.length = 0;
    pc.previousLoaded = loaded;
};

GetOffsetAngle = function (entity, other){
    var entityPosition = entity.getPosition();
    var otherPosition = other.getPosition();
    var xOffset = otherPosition.x - entityPosition.x;
    var zOffset = otherPosition.z - entityPosition.z;
    
    return Math.toDegrees(Math.atan2(-zOffset, xOffset)) - 90;
};

IsEntityFacingOther = function (entity, other, angle, eulerRange){
    eulerRange = eulerRange | 100;
    
    var offsetEulerAngle = Math.ClampInLooped(-180, 180, GetOffsetAngle(entity, other));
    var angleDifference = Math.GetDifferenceInLoopedRange(-180, 180, offsetEulerAngle, angle);    
    return angleDifference < eulerRange;
};




pc.Picker.prototype.getSelection = function(x, y, width, height) {
    var device = this.device;
    if (typeof x === "object") {
      var rect = x;
      x = rect.x;
      y = rect.y;
      width = rect.width;
      height = rect.height;
    } else {
      y = this._pickBufferTarget.height - (y + (height || 1));
    }
    width = width || 1;
    height = height || 1;
    var prevRenderTarget = device.renderTarget;
    device.setRenderTarget(this._pickBufferTarget);
    device.updateBegin();
    var pixels = new Uint8Array(4 * width * height);
    device.readPixels(x, y, width, height, pixels);
    device.updateEnd();
    device.setRenderTarget(prevRenderTarget);
    var selection = [];
    for (var i = 0;i < width * height;i++) {
      var r = pixels[4 * i + 0];
      var g = pixels[4 * i + 1];
      var b = pixels[4 * i + 2];
      var index = r << 16 | g << 8 | b;
      if (index !== 16777215) {
        var selectedMeshInstance = this.drawCalls[index];
        if (selection.indexOf(selectedMeshInstance) === -1) {
          selection.push(selectedMeshInstance);
        }
      }
    }
    return selection;
  };

pc.ElementComponent.prototype._calculateLocalAnchors = function() {
    var resx = 1000;
    var resy = 1000;
    var parent = this.entity._parent;
    if (parent && parent.element) {
      resx = parent.element.width;
      resy = parent.element.height;
    } else {
      if (this.screen && this.screen.screen) {
          
        var res = this.screen.screen.resolution;
        var scale = this.screen.screen.scale;
        resx = res.x / scale;
        resy = res.y / scale;
      }
    }
    this._localAnchor.set(this._anchor.x * resx, this._anchor.y * resy, this._anchor.z * resx, this._anchor.w * resy);
  };

CloneObject = function(obj, deep) {
    var newObj;

    if (obj instanceof Date) {
        newObj = new Date(obj);
    }
    else if (!deep && obj instanceof Array) {
        newObj = obj.slice(0);
    }
    else {
        newObj = {};
        for (i in obj) {
            if (i == 'clone') continue;
            if (deep && typeof obj[i] == "object") {
                newObj[i] = CloneObject(obj[i]);
            } else {
                newObj[i] = obj[i];
            }
        } 
    }
    return newObj;
};

CloneArray = function(array) {
    return JSON.parse(JSON.stringify(array));
};


HtmlToElementPosition = function(htmlElement, screen) {
    var clientRect = htmlElement.getBoundingClientRect();
    var scale = (screen.referenceResolution.y / window.innerHeight);

    var xPos = (clientRect.x - (window.innerWidth * 0.5) + (clientRect.width * 0.5)) * scale;
    var yPos = (-(clientRect.y - (window.innerHeight * 0.5) + (clientRect.height * 0.5))) * scale;

    return new pc.Vec2(xPos, yPos);
};

TouchToElementPosition = function(touch, screen) {
    var scale = (screen.referenceResolution.y / window.innerHeight);
    touch.x -= window.innerWidth * 0.5;
    touch.y -= window.innerHeight * 0.5;
    touch.x *= scale;
    touch.y *= -scale;

    return touch;
};

StringToValue = function(stringValue) {
    var trueEventValue = stringValue;
    var floatValue = parseFloat(trueEventValue);
    
    if(trueEventValue == "True" || trueEventValue == "true"){
        trueEventValue = true;
    }
    else if(trueEventValue == "False" || trueEventValue == "false"){
        trueEventValue = false;
    }
    else if(trueEventValue == "null"){
        trueEventValue = null;
    }
    else if(trueEventValue == "undefined"){
        trueEventValue = undefined;
    }
    else if(!isNaN(floatValue)){
        trueEventValue = floatValue;
    }
    
    return trueEventValue;
};

function zeroPad(num, places) {
  var zero = places - num.toString().length + 1;
  return Array(+(zero > 0 && zero)).join("0") + num;
}



//Own method of checking if touch is on element. Slightly modified version of element-input's checkElement2D as resized PC screens didn't function properly 
CheckElement2d = function (x, y, element, camera) {
    var wh = (pc.app.graphicsDevice.width / pc.app.graphicsDevice.height);
    var sw = wh * ScaleManager.Instance.defaultHeight;
    var sh = ScaleManager.Instance.defaultHeight;
    
    var cameraWidth = camera.rect.z * sw;
    var cameraHeight = camera.rect.w * sh;
    var cameraLeft = camera.rect.x * sw;
    var cameraRight = cameraLeft + cameraWidth;
    // camera bottom (origin is bottom left of window)
    var cameraBottom = (1 - camera.rect.y) * sh;
    var cameraTop = cameraBottom - cameraHeight;

    var _x = x * sw / pc.app.elementInput._target.clientWidth;
    var _y = y * sh / pc.app.elementInput._target.clientHeight;

    var vecA = new pc.Vec3();
    var vecB = new pc.Vec3();
    
    // check window coords are within camera rect
    if (_x >= cameraLeft && _x <= cameraRight &&
        _y <= cameraBottom && _y >= cameraTop) {
        
        // limit window coords to camera rect coords
        _x = sw * (_x - cameraLeft) / cameraWidth;
        _y = sh * (_y - cameraTop) / cameraHeight;

        // reverse _y
        _y = sh - _y;
        
        if(!element || !element.screenCorners) return false;
        var screenCorners = element.screenCorners;
        vecA.set(_x, _y, 1);
        vecB.set(_x, _y, -1);

        if (intersectLineQuad(vecA, vecB, screenCorners)) {
            return true;
        }
    }
    
    return false;
};

var vecA = new pc.Vec3();
var vecB = new pc.Vec3();

var _pq = new pc.Vec3();
var _pa = new pc.Vec3();
var _pb = new pc.Vec3();
var _pc = new pc.Vec3();
var _pd = new pc.Vec3();
var _m = new pc.Vec3();
var _sct = new pc.Vec3();

// Given line pq and ccw corners of a quad, return whether the line
// intersects it. (from Real-Time Collision Detection book)
var intersectLineQuad = function (p, q, corners) {
    _pq.sub2(q, p);
    _pa.sub2(corners[0], p);
    _pb.sub2(corners[1], p);
    _pc.sub2(corners[2], p);

    // Determine which triangle to test against by testing against diagonal first
    _m.cross(_pc, _pq);
    var v = _pa.dot(_m);
    if (v >= 0) {
        // Test intersection against triangle abc
        if (-_pb.dot(_m) < 0)
            return false;

        if (scalarTriple(_pq, _pb, _pa) < 0)
            return false;
    } else {
        // Test intersection against triangle dac
        _pd.sub2(corners[3], p);
        if (_pd.dot(_m) < 0)
            return false;

        if (scalarTriple(_pq, _pa, _pd) < 0)
            return false;
    }

    return true;
};

// pi x p2 * p3
var scalarTriple = function (p1, p2, p3) {
    return _sct.cross(p1, p2).dot(p3);
};

var scalarTriple = function (p1, p2, p3) {
    return _sct.cross(p1, p2).dot(p3);
};

