// GameManager.js
var GameManager = pc.createScript('gameManager');

GameManager.attributes.add('cloudConfigFile', {
    type: 'asset',
    title: "Config File",
    description: "Editor/Cloud version of config file"
});


GameManager.Instance = null;

GameManager.prototype.initialize = function() {
    GameManager.Instance = this;

    this.timeScale = 1;
    this.queuedEntitiesToDestroy = [];
    
    this.pauseLayers = [];
    
    
    //Disable right click menu
    this.app.mouse.disableContextMenu();
    
    //Load config file
    this.LoadConfig();
    this.waitingForConfig = true;
    
    
    this.loadedAssetBundles = [];
    
    this.isFirstClick = true;
    this.defaultTimescale = 1;
    
    
    //Prevent scrolling window with keyboard
    window.addEventListener("keydown", function(e) {
        // space and arrow keys
        if([32, 37, 38, 39, 40].indexOf(e.keyCode) > -1) {
            e.preventDefault();
        }
    }, false);
    
    //Fix chrome audio bug
    var app = this.app;
    var resumeContext = function () {
        if(app.systems.sound.manager.context){
            app.systems.sound.manager.context.resume(); 
        }
        window.removeEventListener('mousedown', resumeContext);
        window.removeEventListener('touchend', resumeContext);
    };
    
    window.addEventListener('mousedown', resumeContext);
    window.addEventListener('touchend', resumeContext);
    
    
    

};



GameManager.prototype.update = function(dt) {    
    if(this.queuedEntitiesToDestroy.length > 0){
        for(var i = this.queuedEntitiesToDestroy.length - 1; i >= 0; i--){
            this.queuedEntitiesToDestroy[i].destroy();
            this.queuedEntitiesToDestroy.splice(i, 1);
        }
    }
    
    var timeScale = this.defaultTimescale;

    
    if(this.waitingForConfig){
        if(this.config){
            this.waitingForConfig = false;
            this.OnConfigLoaded();
        }
    }  
    else{
        if(this.config.debugMode){
            //Debug timescale setting
            timeScale *= this.app.keyboard.isPressed(pc.KEY_SHIFT) ? 5 : 1;

            // if(this.app.keyboard.isPressed(pc.KEY_P)){
            //     this.defaultTimescale = 0;
            //     timeScale = 0;
            // }
        }
    }
    
    this.app.timeScale = window.innerWidth > window.innerHeight ? timeScale : 0;
    
};

GameManager.prototype.IsPaused = function(tag) {
    if(tag && this.pauseLayers.length > 0){
        for(var i = 0; i<this.pauseLayers[this.pauseLayers.length - 1].excludedTags.length; i++){
            if(this.pauseLayers[this.pauseLayers.length - 1].excludedTags == tag){
               return false;
            }
        }
    }
    
    return this.pauseLayers.length > 0;
};

GameManager.prototype.PauseAll = function(id) {
    this.PauseAllExcluding(id, []);
};

GameManager.prototype.PauseAllExcluding = function(id, excluding) {
    this.pauseLayers.push(new PauseLayer(id, excluding));
    
    this.app.fire("pause");
    this.timeScale = 0;
    
    PhysicsManager.Instance.p2World.paused = true;
};

GameManager.prototype.Resume = function(id) {
    if(id){
        for(var i = 0; i<this.pauseLayers.length; i++){
            if(this.pauseLayers[i].id == id){
                this.pauseLayers.splice(i, 1);
                break;
            }
        }
    }
    
    if(this.pauseLayers.length === 0){
        this.app.fire("resume");
        this.timeScale = 1;
        PhysicsManager.Instance.p2World.paused = false;
    }
};

GameManager.prototype.ClearPauseLayers = function() {
    this.pauseLayers = [];
    this.Resume();
};

GameManager.prototype.QueueDestroyEntity = function(entity) {
    this.queuedEntitiesToDestroy.push(entity);
};

GameManager.prototype.GoFullscreen = function() {
    if(!Device.Instance().desktop){
        this.app.enableFullscreen(document.body, function () {}, function () {});
    }    
};

GameManager.prototype.LoadConfig = function() {

    //Try and load local game_config. if running in playcanvas, will fallback to cloud config
    var localConfigPath = MPHelper.GetGameDir() + "game_config.json";

    var xhr = new XMLHttpRequest();
    xhr.onreadystatechange = function()
    {
        if (xhr.readyState === XMLHttpRequest.DONE) {
            if (xhr.status === 200) {
                GameManager.Instance.config = JSON.parse(xhr.responseText);
                GameManager.Instance.SetupOfflineMode();
            } else {
                console.log("Loading cloud config...");
                this.config = this.cloudConfigFile.resource;
            }
        }
    }.bind(this);
    xhr.open("GET", localConfigPath, true);
    xhr.send();
    
};

GameManager.prototype.OnConfigLoaded = function() {
    if(this.config.debugMode){
        this.entity.parent.findByName("FpsCounter").enabled = true;
    }
    if(this.config.clearData){
        SaveDataManager.Instance.ClearData(true);
    }
    
    PhysicsManager.Instance.p2World.debugDraw = this.config.debugRenderPhysics ? true : false;
    
    this.app.i18n.locale = this.config.language;
};


GameManager.prototype.GetGameDir = function() {
    return MPHelper ? MPHelper.GetGameDir() : '';    
};

GameManager.prototype.AddAssetBundle = function(assetArray, unloadScenes, name) {
    var assetBundle = {
        name: name,
        assets: assetArray,
        unloadScenes: unloadScenes
    };
    this.loadedAssetBundles[this.loadedAssetBundles.length] = assetBundle;
};

GameManager.prototype.UnloadAssetBundles = function(unloadID) {
    var remainingAssetBundles = [];    
    
    for(var i = 0; i < this.loadedAssetBundles.length; i++){
        var unloaded = false;
        for(var j = 0; j < this.loadedAssetBundles[i].unloadScenes.length; j++){
            //If ID matches one of the scene ID's we should unload this asset bundle for
            if(this.loadedAssetBundles[i].unloadScenes[j] == unloadID){
                console.log("Unloaded Asset Bundle: " + this.loadedAssetBundles[i].name);
                for(var k = this.loadedAssetBundles[i].assets.length - 1; k >= 0; k--){
                    
                    this.UnloadAsset(this.loadedAssetBundles[i].assets[k]);
                    //console.log("Unloaded Asset: " + this.loadedAssetBundles[i].assets[k].name, this.loadedAssetBundles[i].assets[k]);
                    
                }
                unloaded = true;
                
                break;
            }
        }
        
        if(!unloaded){
            remainingAssetBundles[remainingAssetBundles.length] = this.loadedAssetBundles[i];
        }
    }
    
    this.loadedAssetBundles = [];
    for(var i = 0; i < remainingAssetBundles.length; i++){
        this.loadedAssetBundles[i] = remainingAssetBundles[i];
    }
};

GameManager.prototype.UnloadAsset = function(asset) {
    //console.log("Unloading Asset: " + asset.name);
    switch(asset.type){
        case "audio":{
            AudioManager.Instance.UnloadSoundAsset(asset);
            break;
        }
        default:{
            asset.unload();
            break;
        }
    }
};

GameManager.prototype.SetupOfflineMode = function() {
    if (GameManager.Instance.config.offline) {
        if('serviceWorker' in navigator) {
            navigator.serviceWorker.register('service-worker.js', { scope: './' })
                .then(function(registration) {
                    console.log('Service Worker Registered');
                });

            navigator.serviceWorker.ready.then(function(registration) {
                console.log('Service Worker Ready');
            });
        }
    }
};

GameManager.prototype.SendStatsEvent = function(nameKey, valueType, additionalParams) {
    if (MPHelper) {
        MPHelper.SendStatsEvent(nameKey, valueType, additionalParams);
    }
};

//Use this for callbacks from objects
GameManager.prototype.SendGenericStatsEvent = function(nameKey, valueType) {
    this.SendStatsEvent(nameKey, valueType, {
        "settings_status": GameManager.Instance.GetSettingsStatus()
    });
};

GameManager.prototype.GetSettingsStatus = function() {
    var settings = [
        "audio:" + AudioManager.Instance.audioEnabled,
        "motion:" + AccessibilityManager.Instance.motionFXEnabled,
        "subtitles:" + AccessibilityManager.Instance.subtitlesEnabled
    ];
    
    return settings.toString();
};




// AccessibilityManager.js
var AccessibilityManager = pc.createScript('accessibilityManager');

AccessibilityManager.attributes.add('subtitlesJson', {type: 'asset', assetType: 'json', title: "Subtitles"});

AccessibilityManager.Instance = null;

AccessibilityManager.prototype.initialize = function() {
    AccessibilityManager.Instance = this;
    this.div = document.createElement("div");
    this.div.id = 'subtitles';
    this.div.style.zIndex = 20;
    
    var containerDiv = MPHelper.GetContainerDiv();
    containerDiv.appendChild(this.div); 
    
    this.div.className += 'subtitles';
    this.language = "english";

    this.entries = [];

    this.visibleTime = 0.0;
    this.visibleTimer = 0.0;
    this.textVisible = false;
    
    var localStorageSubtitlesEnabled = MPHelper.GetSubtitles(); 
    this.subtitlesEnabled = localStorageSubtitlesEnabled; 
    
    var localStorageMotionEnabled = MPHelper.GetMotion(); 
    this.motionFXEnabled = localStorageMotionEnabled; 
    
    
    this.vibrationEnabled = true;
};

AccessibilityManager.prototype.update = function(dt) {
    var textChanged = false;
    for(var i = this.entries.length - 1; i >= 0; i--) {

        this.entries[i].timer += dt;

        if(this.entries[i].timer > this.entries[i].time) {
            this.entries.splice(i, 1);
            textChanged = true;
        }
    }

    if(textChanged) {
        this.SetText();
    }
};

AccessibilityManager.prototype.GetSubtitleText = function(id) {
    return this.subtitlesJson.resource[this.language][id];
};

AccessibilityManager.prototype.RemoveEntry = function(id) {
    if(id === undefined || !this.subtitlesEnabled){
        return;
    }
    
    var text = this.GetSubtitleText(id) || id;
    if(text === undefined || text === null) {
        return;
    }
    
    var textChanged = false;
    var multiLine = text.split("\n");
    for(var i = 0; i < multiLine.length; i++) {
        for(var j = this.entries.length - 1; j >= 0; j--) {
            if(this.entries[j].text === multiLine[i]) {
                this.entries.splice(j, 1);
                textChanged = true;
            }
        }
    }

    if(textChanged) {
        this.SetText();
    }
};

AccessibilityManager.prototype.Clear = function() {
    this.entries.length = 0;
    this.SetText();
};

AccessibilityManager.prototype.ShowSubtitle = function(id, time) {
    if(id === undefined || !this.subtitlesEnabled){
        return;
    }
    
    var text = this.GetSubtitleText(id);
    if(text === null || text === undefined) return;
    
    if(time === 0) {
        var split = text.split(" ");
        time = split.length * 0.4;
    }

    var multiLine = text.split("\n");
    if (multiLine.length <= 1) {
        time += 1;

        this.visibleTimer = 0.0;
        this.visibleTime += time;

        this.entries.push(
            {
                "text": text,
                "time": time,
                "timer" : 0,
            }
        );
    }
    else {
        var lastTime = 0.0;
        for (var i = 0; i < multiLine.length; i++) {
            var multiTime = time * (multiLine[i].length / text.length);

            this.entries.push(
                {
                    "text": multiLine[i],
                    "time": multiTime,
                    "timer": lastTime,
                }
            );

            lastTime -= multiTime;
        }

        this.visibleTimer = 0.0;
        this.visibleTime += time + 1;
    }

    if (this.entries.length > 3) {
        for (var j = this.entries.length; j > 3; j--) {
            this.entries.shift();
        }
    }

    this.SetText();
};

AccessibilityManager.prototype.SetText = function() {
    var newText = "";

    var existingTextEntries = [];
    for(var i = 0; i < this.entries.length; i++) {

        if (this.entries[i].timer < 0) {
            continue;
        }

        var stringDuplicate = false;
        for(var a = 0; a < existingTextEntries.length; a++) {

            if(existingTextEntries[a] === this.entries[i].text) {
                stringDuplicate = true;
            }
        }

        if(stringDuplicate) {
            continue;
        }

        if(i !== 0) {
            newText += "<br/>";
        }

        newText += this.entries[i].text;
        existingTextEntries.push(this.entries[i].text);
    }

    this.div.innerHTML = newText;
};

AccessibilityManager.prototype.ToggleSubtitlesEnabled = function() {
    this.subtitlesEnabled = !this.subtitlesEnabled;
    MPHelper.SetSubtitles(this.subtitlesEnabled);
};

AccessibilityManager.prototype.ToggleMotionFXEnabled = function() {
    this.motionFXEnabled = !this.motionFXEnabled;
    MPHelper.SetMotion(this.motionFXEnabled);
};

AccessibilityManager.prototype.UpdateSubtitlesStatus = function() {
    this.subtitlesEnabled = MPHelper.GetSubtitles();   
};

AccessibilityManager.prototype.UpdateMotionStatus = function() {
    this.motionFXEnabled = MPHelper.GetMotion();   
};

// ScreenManager.js

SceneManager = function() {};
SceneManager.prototype = Object.create(MPStateMachine.prototype);
SceneManager.prototype.constructor = SceneManager;

SceneManager.Instance = null;

SceneManager.prototype.initialize = function() {
    MPStateMachine.call(this);
    this.SetStateStackLength(5);
    
    SceneManager.Instance = this;
    
    this.loadedScene = null;
    this.loadingScene = false;
    this.loadedSceneEntity = null;
    
    this.sceneToLoadData = null;
};

SceneManager.prototype.GetSceneUrl = function(sceneID) {
    return this.app.scenes.find(sceneID).url;
};

SceneManager.prototype.LoadScene = function(sceneToLoad, callback, context, fade, additive) {
    if (fade) {
        GameManager.Instance.FadeIn(function(){  
            
            this.LoadSceneHierarchy(sceneToLoad, function(){
                if (callback) {
                    callback.call(context);
                }
                GameManager.Instance.FadeOut();
            }, this, additive);
        }, this);
    }
    else {
        this.LoadSceneHierarchy(sceneToLoad, callback, context, additive);
    }
};

SceneManager.prototype.LoadPreloaderScene = function(scenesToLoad, scenesToStart, callback, context, fade, additive) {
    if (this.loadingScene) return;
    
    SceneLoader.scenesToLoad = scenesToLoad;
    SceneLoader.scenesToStart = scenesToStart;

    if (fade !== undefined && fade){
        GameManager.Instance.FadeIn(function(){            
            
            this.LoadSceneHierarchy(this.GetSceneUrl("SceneLoader"), function(){
                if (callback) {
                    callback.call(context);
                }
                GameManager.Instance.FadeOut();
            }, this, additive);
        }, this);
    }
    else{
        this.LoadSceneHierarchy("SceneLoader", callback, context, additive);
    }
};

SceneManager.prototype.LoadSceneHierarchy = function(sceneToLoad, callback, context, additive) {
    if (this.loadingScene) return;
    
    this.loadingScene = true;
    this.loadedScene = sceneToLoad;
    if (!additive) {        
        for (var i = 0; i < this.app.root.children.length; i++) {
            var scene = this.app.root.children[i];
            if (!scene.dontDestroyOnLoad) {
                scene.destroy();
                this.app.root.children.slice(i, 0);
                i--;
            }
        }
    }
    
    var sceneUrl = this.GetSceneUrl(sceneToLoad);
    
    this.app.scenes.loadSceneHierarchy(sceneUrl, function(err, entity) {
        if (!err) {
            entity.sceneId = sceneToLoad;
            
            this.app.scenes.loadSceneSettings(sceneUrl, function(err){}); //Applies scene settings
            
            if (entity.screen) entity.screen.Enable();
            SceneManager.Instance.loadingScene = false;
            
            if(callback && context){
                callback.call(context, entity);
            }
            
            if(entity.scene) entity.scene.OnSceneLoaded(this.sceneToLoadData);
            
            this.PrintAppRoot();                     
        }
    }.bind(this));
};

SceneManager.prototype.PrintAppRoot = function() {
    if(!GameManager.Instance.config.debugMode) return;
    
    var screens = [];
    for (var i = 0; i < this.app.root.children.length; i++)
        screens.push(this.app.root.children[i].name);
    
    console.warn("App Root: \n<" + screens.toString() + ">");
};

SceneManager.prototype.SetState = function(newState, config) {
    if(config === undefined) config = {};
    if(config.addToStack === undefined) config.addToStack = true;
    
    this.sceneToLoadData = config;
    
    
    MPStateMachine.prototype.SetState.call(this,newState, config);
    
    this.PrintStateStack();
};

SceneManager.prototype.RollbackStateStack = function() {
    MPStateMachine.prototype.RollbackStateStack.call(this);
    this.PrintStateStack();
    this.app.root.children[this.app.root.children.length - 1].enabled = false;
    this.app.root.children[this.app.root.children.length - 1].enabled = true;
};

SceneManager.prototype.AddEntityToLatestScene = function(entity) {    
    this.app.root.children[this.app.root.children.length - 1].addChild(entity);
};


SceneManager.prototype.RemoveFromStateStack = function(count) {
    MPStateMachine.prototype.RemoveFromStateStack.call(this, count);
    this.PrintStateStack();
};

SceneManager.prototype.ClearStateStack = function() {
    MPStateMachine.prototype.ClearStateStack.call(this);
    this.PrintStateStack();
};

SceneManager.prototype.PrintStateStack = function() {
    if(!GameManager.Instance.config || !GameManager.Instance.config.debugMode) return;
    console.warn("State Stack: \n[" + this.stateStack.toString() + "]");
};

SceneManager.prototype.ShowScreen = function(id, config) {
    if(!config) config = {};
    if(config.preload === undefined) config.preload = false;
    if(config.startScene === undefined) config.startScene = id;
    if(config.fade === undefined) config.fade = false;
    if(config.additive === undefined) config.additive = false;

    var sceneExists = this.EnableExistingScreen(id);
    if (!sceneExists) {
        if (config.preload) {
            SceneManager.Instance.LoadPreloaderScene([id], [config.startScene], null, this, config.fade, config.additive);
        }
        else {
            SceneManager.Instance.LoadScene(id, null, this, config.fade, config.additive);
        }
        
        
    }
};


SceneManager.prototype.EnableExistingScreen = function(id) {
    for (var i = 0; i < this.app.root.children.length; i++) {
        var scene = this.app.root.children[i];
        if (scene.sceneId == id) {
            
            if (scene.screen)
                scene.screen.Enable();
            return true;
        }
        else if (scene.screen)
            scene.screen.Disable();
    }
    
    return false;
};

SceneManager.prototype.Default_EnterState = function(id, config) {
    this.ShowScreen(id, config);
};


SceneManager.prototype.MainMenu_EnterState = function(id, config) {   
    if(config && config.preload == undefined) config.preload = true;
    this.ShowScreen(id, config);
};

SceneManager.prototype.LevelSelectScreen_EnterState = function(id, config) {    
    if(config && config.preload == undefined) config.preload = true;
    this.ShowScreen(id, config);
};

SceneManager.prototype.IntroScreen_EnterState = function(id, config) {    
    if(config && config.preload == undefined) config.preload = true;
    this.ShowScreen(id, config);
};

SceneManager.prototype.GameScene_EnterState = function(id, config) {    
    if(config && config.preload == undefined) config.preload = true;
    this.ShowScreen(id, config);
};

SceneManager.prototype.GameCompleteScene_EnterState = function(id, config) {    
    if(config && config.preload == undefined) config.preload = true;
    this.ShowScreen(id, config);
};

SceneManager.prototype.CharacterSelectScreen_EnterState = function(id, config) {    
    if(config && config.preload == undefined) config.preload = true;
    this.ShowScreen(id, config);
};

SceneManager.prototype.PauseScene_EnterState = function(id, config) {    
    this.ShowScreen(id, {
        additive: true
    });
};


// SaveDataManager.js
var SaveDataManager = pc.createScript('saveDataManager');

SaveDataManager.Instance = null;
// initialize code called once per entity
SaveDataManager.prototype.initialize = function() {
    SaveDataManager.Instance = this;
    
    this.saveID = "dcshg";
    this.saveVersion = 1.01;
    
    this.CreateSaveData();  
    
    this.LoadFromStorage();

    if(!this.saveData.saveVersion || this.saveData.saveVersion < this.saveVersion){
        this.ClearData(true);
    }
};

SaveDataManager.prototype.CreateSaveData = function() {
    this.saveData = {
        saveVersion: this.saveVersion,
        game: {
        },
        settings: {
            audio: true
        }
    };

};

SaveDataManager.prototype.GetData = function(root, id) {
    if(id.entity)
        id = this.ScriptToID(id);

    return root[id];
};

SaveDataManager.prototype.SetData = function(root, id, value) {
    if(id.entity)
        id = this.ScriptToID(id);

    root[id] = value;
};

SaveDataManager.prototype.SetGameData = function(id, value) {
    this.SetData(this.saveData.game, id, value);
};

SaveDataManager.prototype.GetGameData = function(id) {
    return this.GetData(this.saveData.game, id);
};

SaveDataManager.prototype.SetSettingsData = function(id, value) {
    this.SetData(this.saveData.settings, id, value);
};

SaveDataManager.prototype.GetSettingsData = function(id) {
    return this.GetData(this.saveData.settings, id);
};


SaveDataManager.prototype.LoadFromStorage = function() {
    var saveData = MPHelper.LoadData(this.saveID);
    
    if(saveData){
        this.saveData = {};
        this.saveData.saveVersion = saveData.saveVersion;
        this.saveData.game = saveData.game;
        this.saveData.settings = saveData.settings;
    }
};

SaveDataManager.prototype.SaveToStorage = function() {
    MPHelper.SaveData(this.saveID, this.saveData);    
};


SaveDataManager.prototype.ScriptToID = function(script) {
    //Unique id based on entity guid and script name
    return script.entity._guid + "_" + script.__scriptType.__name;
};

SaveDataManager.prototype.ClearGameData = function() {
    this.saveData.game = {};
    this.SaveToStorage();
};

SaveDataManager.prototype.ClearData = function(clearLocalStorage) {
    //Clear out type of data
    this.CreateSaveData();
    
    if(clearLocalStorage){
        //Completely empty storage then refill it with remaining data
        window.localStorage.clear();
        this.SaveToStorage();
    }
    else{
        //Reload old data from storage
        this.LoadFromStorage();
    }
    
};

