TextFit.prototype.UpdateTextFit = function() {
    this.textElement.fontSize = this.defaultFontSize;
    var scalar = Math.min(this.textElement.width / this.textElement.textWidth, this.textElement.height / this.textElement.textHeight);

    if(scalar < 1){
        this.textElement.fontSize = this.textElement.fontSize * scalar;
    }
};

