PathPoint.attributes.add('locked', {type: 'boolean', default: false});

// initialize code called once per entity
PathPoint.prototype.initialize = function() {
    
};

// update code called every frame
PathPoint.prototype.update = function(dt) {
    
};

PathPoint.prototype.Unlock = function() {
    this.locked = false;
};

// CameraAspectRatioFixer.js
var CameraAspectRatioFixer = pc.createScript('cameraAspectRatioFixer');

// initialize code called once per entity
CameraAspectRatioFixer.prototype.initialize = function() {
    this.oldDimensions = new pc.Vec2(ScaleManager.Instance.dimensions.x, ScaleManager.Instance.dimensions.y);
    this.FixAspect();
    
};

// update code called every frame
CameraAspectRatioFixer.prototype.update = function(dt) {
    if(ScaleManager.Instance.dimensions.x !== this.oldDimensions.x || ScaleManager.Instance.dimensions.y !== this.oldDimensions.y){
        this.FixAspect();
    }
};

CameraAspectRatioFixer.prototype.FixAspect = function() {
    if(ScaleManager.Instance.dimensions.x > ScaleManager.Instance.dimensions.y * 2){
        var ratio = ScaleManager.Instance.dimensions.x / ScaleManager.Instance.dimensions.y;
        var ratioOffset = ratio - 2;
        var fov = 45 - (ratioOffset * 18);
        this.entity.camera.fov = fov;
    }
    else{
        this.entity.camera.fov = 45;
    }
    
    this.oldDimensions.set(ScaleManager.Instance.dimensions.x, ScaleManager.Instance.dimensions.y);
};

