// ContentSizeFitter.js
var ContentSizeFitter = pc.createScript('contentSizeFitter');

// initialize code called once per entity
ContentSizeFitter.prototype.initialize = function() {
    
};

ContentSizeFitter.prototype.postInitialize = function() {
    this.RelcalculateSizing();
};

// update code called every frame
ContentSizeFitter.prototype.update = function(dt) {
    this.RelcalculateSizing();
};

ContentSizeFitter.prototype.RelcalculateSizing = function() {
    var left = 99999;
    var right = -99999;
    var top = 99999;
    var bottom = -99999;
    for(var i = 0; i<this.entity.children.length; i++){
        var element = this.entity.children[i].element;
        if(element){
            
            for(var j = 0; j<element.screenCorners.length; j++){
                left = Math.min(element.screenCorners[j].x, left);
                right = Math.max(element.screenCorners[j].x, right);
                top = Math.min(element.screenCorners[j].y, top);
                bottom = Math.max(element.screenCorners[j].y, bottom);
            }
        }
    }
    
    
    var width = Math.abs(left - right);// * scale;
    var height = Math.abs(top - bottom);// * scale;
    
    if(this.entity.layoutgroup){
        width += this.entity.layoutgroup.padding.x + this.entity.layoutgroup.padding.z;
        height += this.entity.layoutgroup.padding.y + this.entity.layoutgroup.padding.w;
    }
    
    this.entity.element.width = width;
    this.entity.element.height = height;
};

// DebugMenuOption.js
var DebugMenuOption = pc.createScript('debugMenuOption');

DebugMenuOption.attributes.add("previousButtonEntity", { type: 'entity' });
DebugMenuOption.attributes.add("nextButtonEntity", { type: 'entity' });
DebugMenuOption.attributes.add("optionTextEntity", { type: 'entity' });

// initialize code called once per entity
DebugMenuOption.prototype.initialize = function() {
    this.entity.debugMenuOption = this;
    
    this.previousButtonEntity.script.MPDOMButton.on("click", this.OnPreviousButtonPressed, this);
    this.nextButtonEntity.script.MPDOMButton.on("click", this.OnNextButtonPressed, this);
    
    this.options = [];
    this.optionIndex = 0;
    
    
};

DebugMenuOption.prototype.postInitialize = function() {
    this.UpdateOptionText();    
};

// update code called every frame
DebugMenuOption.prototype.update = function(dt) {
    
};

DebugMenuOption.prototype.OnPreviousButtonPressed = function() {
    this.SetOptionIndex(this.optionIndex - 1);
};

DebugMenuOption.prototype.OnNextButtonPressed = function() {
    this.SetOptionIndex(this.optionIndex + 1);
};

DebugMenuOption.prototype.SetOptionIndex = function(index) {
    this.optionIndex = index;
    
    if(this.optionIndex > this.options.length - 1){
        this.optionIndex = 0;
    }
    else if(this.optionIndex < 0){
        this.optionIndex = this.options.length - 1;
    }
    this.UpdateOptionText();
};

DebugMenuOption.prototype.UpdateOptionText = function() {
    this.optionTextEntity.element.text = this.options[this.optionIndex];
};

DebugMenuOption.prototype.OnPlayButtonPressed = function() {

    
};

// MPDOMToggleButtonSound.js
var MPDOMToggleButtonSound = pc.createScript('MPDOMToggleButtonSound');

if (!MPDOMButtonSound)
      var MPDOMButtonSound = function() {};
MPDOMToggleButtonSound.prototype = Object.create(MPDOMButtonSound.prototype);
MPDOMToggleButtonSound.prototype.constructor = MPDOMToggleButtonSound;

MPDOMToggleButtonSound.attributes.add("mpDomButtonEntity", { type: 'entity', title: "MPDOMButton Entity" });
MPDOMToggleButtonSound.attributes.add("soundLayer", { type: "string" });
MPDOMToggleButtonSound.attributes.add("enabledSoundName", { type: "string" });
MPDOMToggleButtonSound.attributes.add("disabledSoundName", { type: "string" });
MPDOMToggleButtonSound.attributes.add("soundVolume", { type: "number", default: 1 });
MPDOMToggleButtonSound.attributes.add("eventName", { type: 'string',
    enum: [
        { 'click': "click" },
        { 'over': "over" },
        { 'out': "out" }
    ],
    default: 'click'
});

MPDOMToggleButtonSound.prototype.initialize = function() {
    MPDOMButtonSound.prototype.initialize.call(this);

    this.MPDOMButton.on("toggle", this.UpdateToggleSound, this);
    this.UpdateToggleSound();
};

MPDOMToggleButtonSound.prototype.UpdateToggleSound = function() {
    if(this.MPDOMButton.toggle){
        this.soundName = this.enabledSoundName;
    }
    else{
        this.soundName = this.disabledSoundName;
    }
};


// MPDOMIcon.js
var MPDOMIcon = pc.createScript('MPDOMIcon');

MPDOMIcon.prototype.initialize = function() {
    this.on("destroy", this.Destroy, this);
    
    this.hasPanelParent = this.entity.parent && this.entity.parent.script && this.entity.parent.script.MPDOMPanel !== undefined;
    
    this.ConfigureClass();
    
    this._onScreenResize = this.OnScreenResize.bind(this);
    
    window.addEventListener("resize", this._onScreenResize, true);
};

MPDOMIcon.prototype.OnScreenResize = function(){
    this.ConfigureClass();
};

MPDOMIcon.prototype.ConfigureClass = function(){
    // Config params 
    var buttonSize = MPDOMClasses.GetButtonSize();
    
    //Only update if button size has changed
    if(this.buttonSize != buttonSize){
        this.buttonSize = buttonSize;
        
        this.domClass = MPDOMClasses.GetClassConfig("dom_button std");
        this.platformClass = this.domClass[buttonSize];
        
        if(this.platformClass){
            this.entity.element.width = this.platformClass.buttonWidth;
            this.entity.element.height = this.platformClass.buttonHeight;
            
            //Handle scaling ourselves if no panel as parent
            if(!this.hasPanelParent && !this.scaler){
                this.scaler = this.entity.script.create("MPDOMScaler");
            }
        }
        
        this.fire("updatedClass", this);    
    }
};

MPDOMIcon.prototype.Destroy = function() {
    window.removeEventListener("resize", this._onScreenResize, true);
};

// Brim.js
var Brim = pc.createScript('brim');

Brim.attributes.add("brimImageAsset", {type: 'asset'});
// initialize code called once per entity
Brim.prototype.initialize = function() {
    this.visible = false;
    
    var displayBrim = Device.Instance().shouldDisplayBrim;

    if(!displayBrim){
        return;
    }
    var spec = this.GetSpec();

    if(!spec) {
        return;
    }

    this.height = spec[0];

    window.addEventListener("resize", this.OnResize.bind(this));

    this.brimElement = document.createElement("div");
    this.brimElement.id = "brim";
    this.brimElement.style.backgroundImage = "url('" + this.brimImageAsset.getFileUrl() + "')";

    var containerDiv = MPHelper.GetContainerDiv();
    containerDiv.appendChild(this.brimElement);

    this.OnResize();
};

// update code called every frame
Brim.prototype.update = function(dt) {
    
};

Brim.prototype.GetSpec = function() {
    var devices = [
        [320, 480, 2, "iPhone 4"],
        [320, 568, 2, "iPhone 5 or 5s"],
        [375, 667, 2, "iPhone 6"],
        [414, 736, 3, "iPhone 6 plus"]
    ];

    for (var t = 0; t < devices.length; t++) {
        var device = devices[t];
        var isDevice = window.screen.height == device[0] && window.screen.width == device[1] || window.screen.width == device[0] && window.screen.height == device[1];
        if (isDevice) {
            return device;
        }
    }
    
    // Create a spec in case one can't be found (newer device)
    var min = Math.min(window.screen.height, window.screen.width);
    var max = Math.max(window.screen.height, window.screen.width);
    var spec = [min, max, 3, "Unknown device"];

    return spec;
};

Brim.prototype.ShowBrim = function() {
    this.visible = true;

    this.brimElement.style.visibility = "visible";
    this.brimElement.style.height = "999999px";
    this.brimElement.style.pointerEvents = "all";
};

Brim.prototype.ShowGame = function() {
    this.visible = false;

    this.brimElement.style.visibility = "hidden";
    this.brimElement.style.height = this.height + 1 + "px";
    this.brimElement.style.pointerEvents = "none";
};

Brim.prototype.OnResize = function() {
    if (window.innerHeight > window.innerWidth
        || window.innerHeight == this.height) {
        this.ShowGame();
        window.scrollTo(0, 0);
    }
    else {
        this.ShowBrim();

        window.scrollTo(0, 0);
    }
};

// ContentFitLayout.js
var ContentFitLayout = pc.createScript('contentFitLayout');

ContentFitLayout.attributes.add('layoutEntity', {type: 'entity'});

// initialize code called once per entity
ContentFitLayout.prototype.initialize = function() {
    this.layoutGroup = this.layoutEntity.layoutgroup;
    this.RecalculateSizing();
};

// update code called every frame
ContentFitLayout.prototype.update = function(dt) {

};

ContentFitLayout.prototype.RecalculateSizing = function() {    
    switch(this.layoutGroup.orientation){
        case pc.ORIENTATION_HORIZONTAL:{
            this.RecalculateHorizontalSizing();
            break;
        }
        case pc.ORIENTATION_VERTICAL:{
            this.RecalculateVerticalSizing();
            break;
        }
    }
};


ContentFitLayout.prototype.RecalculateHorizontalSizing = function() {
    switch(this.layoutGroup.wrap){
        case true:{
            this.RecalculateHorizontalWrappedSizing();
            break;
        }
        case false:{
            this.RecalculateHorizontalUnwrappedSizing();
            break;
        }
    }
    
    
};

ContentFitLayout.prototype.RecalculateVerticalSizing = function() {
    this.RecalculateVerticalUnwrappedSizing();
};

ContentFitLayout.prototype.RecalculateVerticalUnwrappedSizing = function() {
    this.entity.element.width = this.layoutEntity.element.width;
    
    var totalHeight = this.layoutGroup.padding.y + this.layoutGroup.padding.w;
    
    for(var i = 0; i<this.layoutEntity.children.length; i++){
        if(!this.layoutEntity.children[i].enabled) continue;
        
        var element = this.layoutEntity.children[i].element;
        totalHeight += element.height;
        
        if(i<this.layoutEntity.children.length - 1){
            totalHeight += this.layoutGroup.spacing.y;
        }
    }
    
    this.entity.element.height = Math.max(this.layoutEntity.element.height, totalHeight);
};

ContentFitLayout.prototype.RecalculateHorizontalUnwrappedSizing = function() {
    this.entity.element.height = this.layoutEntity.element.height;
    
    var totalWidth = this.layoutGroup.padding.x + this.layoutGroup.padding.z;
    
    for(var i = 0; i<this.layoutEntity.children.length; i++){
        if(!this.layoutEntity.children[i].enabled) continue;
        
        var element = this.layoutEntity.children[i].element;
        totalWidth += element.width;
        
        if(i<this.layoutEntity.children.length - 1){
            totalWidth += this.layoutGroup.spacing.x;
        }
    }
    
    this.entity.element.width = Math.max(this.layoutEntity.element.width, totalWidth);
};

ContentFitLayout.prototype.RecalculateHorizontalWrappedSizing = function() {
    this.entity.element.width = this.layoutEntity.element.width;
    var currentRowWidth = 0;
    var maxRowWidth = this.layoutEntity.element.width - (this.layoutGroup.padding.x + this.layoutGroup.padding.z);
    var totalHeight = this.layoutGroup.padding.y + this.layoutGroup.padding.w;
    var rowCount = 0;
    
    for(var i = 0; i<this.layoutEntity.children.length; i++){
        if(!this.layoutEntity.children[i].enabled) continue;
        
        var element = this.layoutEntity.children[i].element;
        var newRowWidth = currentRowWidth + element.width + this.layoutGroup.spacing.x;
        
        if(newRowWidth > maxRowWidth || i === 0){
            //New row
            currentRowWidth = element.width;
            totalHeight += element.height;
            
            if(rowCount > 0){
                totalHeight += this.layoutGroup.spacing.y;
            }
            
            rowCount++;
        }
        else{
            currentRowWidth = newRowWidth;
        }
    }
    
    this.entity.element.height = Math.max(this.layoutEntity.element.height, totalHeight);
    
    
};

// Path.js
var Path = pc.createScript('Path');

Path.attributes.add('actorEntity', {type: 'entity'});
Path.attributes.add('loop', {type: 'boolean', default: false});
Path.attributes.add('yoyo', {type: 'boolean', default: false});
Path.attributes.add('playOnStart', {type: 'boolean', default: false});
Path.attributes.add('saveData', {type: 'boolean', default: false});

// initialize code called once per entity
Path.prototype.initialize = function() {
    this.pathPoints = [];
    
    for(var i = 0; i<this.entity.children.length; i++){
        this.pathPoints.push(this.entity.children[i].script.pathPoint);
    }
    
    this.pathPointIndex = 0;
    this.isRunning = false;
    this.direction = 1;
    
    this.targetDistance = 0.1;

    if(this.playOnStart){
        this.StartPathing();
    }
    
    if(this.saveData){
        this.app.on("saveGameData", this.SaveData, this);
        this.LoadData();
    }
    
    this.on("destroy", this.OnDestroy);
    
};

// update code called every frame
Path.prototype.update = function(dt) {

};

Path.prototype.StartPathing = function() {
    this.isRunning = true;
    this.direction = 1;
    
    this.SetPathPointIndex(0);
};

Path.prototype.IncrementPathPointIndex = function() {
    var newPointIndex = this.pathPointIndex;
    
    if(this.yoyo){
        if(this.pathPointIndex >= this.pathPoints.length - 1){
            this.direction = -1;
        }
        if(this.loop && this.pathPointIndex <= 0){
            this.direction = 1;
        }
    }
    
    newPointIndex += this.direction;
    
    if(this.loop && newPointIndex >= this.pathPoints.length){
        newPointIndex = 0;
    }
    
    var finished = newPointIndex > this.pathPoints.length - 1 || newPointIndex < 0;
    
    if(finished){
        this.OnPathMovementComplete();
    }
    else{
        var locked = this.pathPoints[newPointIndex].locked;
        if(!locked){
            this.SetPathPointIndex(newPointIndex);
        }
    }   
    
};

Path.prototype.SetPathPointIndex = function(index) {
    this.pathPointIndex = index;
    
    this.SetTarget(this.pathPoints[this.pathPointIndex].entity.getPosition());
};

Path.prototype.SetTarget = function(targetPosition) {
    
};

Path.prototype.RemoveTarget = function() {

};

Path.prototype.OnPathMovementComplete = function() {
    this.RemoveTarget();
    this.isRunning = false;
    
    this.fire("complete");
};

Path.prototype.LoadData = function() {
    var saveData = SaveDataManager.Instance.GetGameData(this);
    
    if(saveData){
        this.isRunning = saveData.isRunning;
        this.pathPointIndex = saveData.pathPointIndex;
        this.direction = saveData.direction;
    }
};

Path.prototype.SaveData = function() {
    var saveData = {
        isRunning: this.isRunning,
        pathPointIndex: this.pathPointIndex,
        direction: this.direction
    };
    SaveDataManager.Instance.SetGameData(this, saveData);
};

Path.prototype.OnDestroy = function() {    
    if(this.saveData){
        this.app.off("saveGameData", this.SaveData, this);
    }
    
};

