//Allow override material for sprites, allows animated sprites to easily have a shader

var oldShowFrame = pc.SpriteComponent.prototype._showFrame;
pc.SpriteComponent.prototype._showFrame = function(frame) {
    var slicedMaterial = this.system.default9SlicedMaterialSlicedMode;
    var tiledMaterial = this.system.default9SlicedMaterialTiledMode;
    var defaultMaterial = this.system.defaultMaterial;
    
    if(this.overrideMaterial){
        this.system.default9SlicedMaterialSlicedMode = this.overrideMaterial;
        this.system.default9SlicedMaterialTiledMode = this.overrideMaterial;
        this.system.defaultMaterial = this.overrideMaterial;
    }
    
    oldShowFrame.call(this, frame);
    
    
    this.system.default9SlicedMaterialSlicedMode = slicedMaterial;
    this.system.default9SlicedMaterialTiledMode = tiledMaterial;
    this.system.defaultMaterial = defaultMaterial;

};

