// unmuteIOSAudio.js


var USER_ACTIVATION_EVENTS = [
  'auxclick',
  'click',
  'contextmenu',
  'dblclick',
  'keydown',
  'keyup',
  'mousedown',
  'mouseup',
  'touchend'
]

function unmuteIosAudio () {
  var AudioContext = window.webkitAudioContext

  // To detect iOS, check for touch device and confirm Safari-only
  // webkitAudioContext is present.
  var isIos = navigator.maxTouchPoints > 0 && AudioContext != null

  if (!isIos) return

  // state can be 'blocked', 'pending', 'allowed'
  let htmlAudioState = 'blocked'
  let webAudioState = 'blocked'

  let audio
  let context
  let source

  var sampleRate = (new AudioContext()).sampleRate
  var silentAudioFile = createSilentAudioFile(sampleRate)
  
  for(var i = 0; i<USER_ACTIVATION_EVENTS.length; i++){
      var eventName = USER_ACTIVATION_EVENTS[i];
      window.addEventListener(eventName, handleUserActivation, { capture: true, passive: true })
  }


  // Return a seven samples long 8 bit mono WAVE file
  function createSilentAudioFile (sampleRate) {
    var arrayBuffer = new ArrayBuffer(10)
    var dataView = new DataView(arrayBuffer)

    dataView.setUint32(0, sampleRate, true)
    dataView.setUint32(4, sampleRate, true)
    dataView.setUint16(8, 1, true)

    var missingCharacters =
      window.btoa(String.fromCharCode(new Uint8Array(arrayBuffer)))
        .slice(0, 13)

    return "data:audio/wav;base64,UklGRisAAABXQVZFZm10IBAAAAABAAEA" +  missingCharacters + "AgAZGF0YQcAAACAgICAgICAAAA=";
  }

  function handleUserActivation (e) {
    if (htmlAudioState === 'blocked') {
      htmlAudioState = 'pending'
      createHtmlAudio()
    }
    if (webAudioState === 'blocked') {
      webAudioState = 'pending'
      createWebAudio()
    }
  }

  function createHtmlAudio () {
    audio = document.createElement('audio')

    audio.setAttribute('x-webkit-airplay', 'deny') // Disable the iOS control center media widget
    audio.preload = 'auto'
    audio.loop = true
    audio.src = silentAudioFile
    audio.load()

    audio.play().then(
      function(){
        htmlAudioState = 'allowed'
        maybeCleanup()
      },
      function(){
        htmlAudioState = 'blocked'

        audio.pause()
        audio.removeAttribute('src')
        audio.load()
        audio = null
      }
    )
  }

  function createWebAudio () {
    context = new AudioContext()

    source = context.createBufferSource()
    source.buffer = context.createBuffer(1, 1, 22050) // .045 msec of silence
    source.connect(context.destination)
    source.start()

    if (context.state === 'running') {
      webAudioState = 'allowed'
      maybeCleanup()
    } else {
      webAudioState = 'blocked'

      source.disconnect(context.destination)
      source = null

      context.close()
      context = null
    }
  }

  function maybeCleanup () {
    if (htmlAudioState !== 'allowed' || webAudioState !== 'allowed') return
    
    for(var i = 0; i<USER_ACTIVATION_EVENTS.length; i++){
      var eventName = USER_ACTIVATION_EVENTS[i];
      window.removeEventListener(eventName, handleUserActivation, { capture: true, passive: true })
    }
  }
}


unmuteIosAudio();

// AudioLayer.js
function AudioLayer (name, config) {
    this.name = name;
    
    this.soundComponent = config.soundComponent;
    this.overlap = config.overlap !== undefined ? config.overlap : true;
    this.solo = config.solo !== undefined ? config.solo : false;
    this.subtitles = config.subtitles !== undefined ? config.subtitles : false;
    this.volume = config.volume !== undefined ? config.volume : 1;
    this.loop = config.loop !== undefined ? config.loop : false;
    this.assets = [];
    this.sounds = [];
    this.useHowler = config.useHowler;
    
}
AudioLayer.prototype.constructor = AudioLayer;

AudioLayer.prototype.update = function(dt) {
    for(var i = 0; i<this.sounds.length; i++){
        this.sounds[i].update(dt);
    }
};

AudioLayer.prototype.AddSounds = function (sounds) {    
    for (var i = 0; i < sounds.length; i++) {
        var asset = sounds[i];
        if (this.assets.indexOf(asset) == -1) {
            this.assets.push(asset);
            
            var soundClass = this.useHowler ? AudioLayerSoundHowler : AudioLayerSoundPlayCanvas;
            
            var name = GetFileName(asset.name);
        
            var sound = new soundClass({
                name: name, 
                asset: asset, 
                soundComponent: this.soundComponent,
                layerKey: this.name,
                layerVolume: this.volume,
                loop: this.loop,
                overlap: this.overlap,
                subtitles: this.subtitles
            }); 


            this.sounds.push(sound);
        }
    }
};

AudioLayer.prototype.RemoveSounds = function (sounds) {
    for (var i = 0; i < sounds.length; i++) {
        var asset = sounds[i];
        var indexOf = this.assets.indexOf(asset);
        
        if (indexOf != -1) {
            
            for(var j = 0; j<this.sounds.length; j++){
                if(this.sounds[j].asset.id == asset.id){
                    var sound = this.sounds[j];
                    
                    sound.Stop();
                    sound.Destroy();
                }
            }
            
            this.assets.splice(indexOf, 1);
        }
    }
};

AudioLayer.prototype.Play = function (soundKey, config) {
    var sound = this.GetSound(soundKey);

    if(!sound) return;
    
    if(!config){
        config = {};
    }
    
    var solo = config.solo !== undefined ? config.solo : this.solo;
    if(solo){
        this.StopAll();
    }

    sound.Play(config);
    return sound;
};

AudioLayer.prototype.Stop = function (soundKey, config) {
    var sound = this.GetSound(soundKey);

    if(!sound) return;
    
    if(!config){
        config = {};
    }

    sound.Stop(config);
    return sound;
};

AudioLayer.prototype.StopAll = function () {
    for(var i = 0; i<this.sounds.length; i++){
        this.sounds[i].Stop();
    }
};


AudioLayer.prototype.PlayPositional = function (key, config){
    var sound = this.GetSound(key);
    
    if(!sound) return;
    
    if(!config){
        config = {};
    }
    
    var solo = config.solo !== undefined ? config.solo : this.solo;
    if(solo){
        this.StopAll();
    }
    
    sound.PlayPositional(config);
    return sound;
};

AudioLayer.prototype.TweenVolume = function(soundKey, entity, volume, duration, easing, delay, repeat, yoyo) {
    var sound = this.GetSound(soundKey);

    if(!sound) return;

    sound.TweenVolume(entity, volume, duration, easing, delay, repeat, yoyo);
    return sound;
};

AudioLayer.prototype.SetVolume = function (volume) {
    for (var i = 0; i < this.sounds.length; i++) {
        this.sounds[i].SetLayerVolume(volume);
    }
};

AudioLayer.prototype.Pause = function () {
    for (var i = 0; i < this.sounds.length; i++) {
        var sound = this.sounds[i];
        
        if(sound.IsPlaying()) {
            // var t = sound.instances[0].currentTime;//Have to do this for some reason?
            sound.wasPlaying = true;
            sound.Pause();
        }
    }

    this.isPaused = true;
};

AudioLayer.prototype.Resume = function () {
    for (var i = 0; i < this.sounds.length; i++) {
        var sound = this.sounds[i];
        if(sound.wasPlaying) {
            sound.wasPlaying = false;
            sound.Resume();
        }
    }

    this.isPaused = false;
};

AudioLayer.prototype.Destroy = function () {
    for (var i = 0; i < this.sounds.length; i++) {
        var sound = this.sounds[i];
        sound.Stop();
        sound.Destroy();
    }

};

AudioLayer.prototype.GetSound = function (soundKey) {
    for (var i = 0; i < this.sounds.length; i++) {
        var sound = this.sounds[i];
        if(sound.name == soundKey){
            return sound;
        }
    }
};





