// p2-integration.js
////////////////////////////////////////////////////////////////////////////////////////////////////
// PHYSICS WORLD ///////////////////////////////////////////////////////////////////////////////////
////////////////////////////////////////////////////////////////////////////////////////////////////
var P2World = pc.createScript('p2World');

P2World.attributes.add('gravity', { 
    type: 'vec2', 
    default: [ 0, -9.8 ],
    title: 'Gravity',
    description: 'Gravity to use when approximating the friction max force.',
    placeholder: ['X', 'Y']
});
P2World.attributes.add('axes', {
    type: 'number',
    enum: [
        { 'XY': 1 },
        { 'XZ': 2 },
        { 'YZ': 3 }
    ],
    default: 1,
    title: 'Axes',
    description: 'The axes on which the simulation is run.'
});
P2World.attributes.add('defaultFriction', { 
    type: 'number', 
    default: 0.3,
    title: 'Default Friction',
    description: 'The default global friction.'
});
P2World.attributes.add('maxSubSteps', { 
    type: 'number',
    default: 10,
    title: 'Max Substeps',
    description: 'Maximum number of fixed steps to take when stepping the simulation.'
});
P2World.attributes.add('solverIterations', { 
    type: 'number',
    default: 10,
    title: 'Solver Iterations',
    description: 'The maximum number of iterations to do when solving. More gives better results, but is more expensive.'
});
P2World.attributes.add('solverTolerance', {
    type: 'number',
    default: 0,
    title: 'Solver Tolerance',
    description: 'The error tolerance, per constraint. If the total error is below this limit, the solver will stop iterating. Set to zero for as good solution as possible, but to something larger than zero to make computations faster.'
});
P2World.attributes.add('sleepMode', {
    type: 'number',
    enum: [
        { 'No Sleeping': 0 },
        { 'Body Sleeping': 1 },
        { 'Island Sleeping': 2 }
    ],
    default: 0,
    title: 'Sleep Mode',
    description: 'How to deactivate bodies during simulation. Possible modes are: "No Sleeping", "Body Sleeping" and "Island Sleeping". If sleeping is enabled, you might need to wake up the bodies if they fall asleep. If you want to enable sleeping in the world, but want to disable it for a particular body, see p2Body.allowSleep.'
});
P2World.attributes.add('islandSplit', {
    type: 'boolean',
    default: true,
    title: 'Island Split',
    description: 'Whether to enable island splitting. Island splitting can be an advantage for both precision and performance.'
});
P2World.attributes.add('debugDraw', {
    type: 'boolean',
    default: false,
    title: 'Debug Draw',
    description: 'Render a visual representation of the physics world in the running app.'
});

P2World.prototype.initialize = function() {
    var sleepModes = [
        p2.World.NO_SLEEPING,
        p2.World.BODY_SLEEPING,
        p2.World.ISLAND_SLEEPING
    ];

    // Create a physics world
    var world = new p2.World({
        gravity: [
            this.gravity.x,
            this.gravity.y
        ],
        islandSplit: this.islandSplit
    });
    world.sleepMode = sleepModes[this.sleepMode];
    world.solver.iterations = this.solverIterations;
    world.solver.tolerance = this.solverTolerance;
    world.defaultContactMaterial.friction = this.defaultFriction;
    
    //Contact events
    world.on("beginContact", this.beginContactHandler, this);
    world.on("endContact", this.endContactHandler, this);

    // Handle changes to the World's properties
    this.on('attr:defaultFriction', function (value, prev) {
        world.defaultContactMaterial.friction = value;
    });
    this.on('attr:gravity', function (value, prev) {
        world.gravity[0] = value.x;
        world.gravity[1] = value.y;
    });
    this.on('attr:islandSplit', function (value, prev) {
        world.islandSplit = value;
    });
    this.on('attr:sleepMode', function (value, prev) {
        world.sleepMode = sleepModes[value];
    });
    this.on('attr:solverIterations', function (value, prev) {
        world.solver.iterations = Math.round(value);
    });
    this.on('attr:solverTolerance', function (value, prev) {
        world.solver.tolerance = value;
    });

    var self = this;

    this.app.on('p2:getPosition', function (entity, position) {
        var pos = entity.getPosition();
        switch (self.axes) {
            case 1:
                position = [ pos.x, pos.y ];
                break;
            case 2:
                position = [ pos.x, -pos.z ];
                break;
            case 3:
                position = [ -pos.z, pos.y ];
                break;
        }
    });
    this.app.on('p2:addBody', function (body) {
        var pos = body.entity.getPosition();
        var eulerAngles = body.entity.getEulerAngles();
        switch (self.axes) {
            case 1:
                body.position = [ pos.x, pos.y ];
                body.angle = eulerAngles.z * pc.math.DEG_TO_RAD;
                break;
            case 2:
                body.position = [ pos.x, -pos.z ];
                body.angle = eulerAngles.y * pc.math.DEG_TO_RAD;
                break;
            case 3:
                body.position = [ -pos.z, pos.y ];
                body.angle = eulerAngles.x * pc.math.DEG_TO_RAD;
                break;
        }

        world.addBody(body);
    });
    this.app.on('p2:removeBody', function (body) {
        world.removeBody(body);
    });

    world.on("postStep", function (evt) {
        self.app.fire('p2:postStep');
    });

    this.world = world;
    this.paused = false;
    this.targetPos = new pc.Vec3();
    
    this.debugStart = new pc.Vec3(0, 0, 0);
    this.debugEnd = new pc.Vec3(100, 0, 0);
    this.debugColor = new pc.Color(1, 0, 0);
    
    this.dooo = 0;

};

P2World.prototype.postUpdate = function(dt) {
    if(this.paused){
        return;
    }
    var i, j;
    var body, bodies, numBodies;
    var shape, shapes, numShapes;
    var entity, pos, eulerAngles;

    bodies = this.world.bodies;
    numBodies = bodies.length;

    // Set the transforms of kinematic rigid bodies from parent entities
    for (i = 0; i < numBodies; i++) {
        body = bodies[i];
        if (body.type === p2.Body.KINEMATIC) {
            // TODO: handle angle
            entity = body.entity;

            pos = entity.getPosition();
            eulerAngles = entity.getEulerAngles();
            
            switch (this.axes) {
                case 1:
                    body.position[0] = pos.x;
                    body.position[1] = pos.y;
                    body.angle = eulerAngles.z * pc.math.DEG_TO_RAD;
                    break;
                case 2:
                    body.position[0] = pos.x;
                    body.position[1] = -pos.z;
                    body.angle = eulerAngles.y * pc.math.DEG_TO_RAD;
                    break;
                case 3:
                    body.position[0] = pos.y;
                    body.position[1] = -pos.z;
                    body.angle = eulerAngles.x * pc.math.DEG_TO_RAD;
                    break;
            }
            
            
                
            
        }
    }
    
    

    // Update the simulation
    this.world.step(1 / 60, dt, this.maxSubSteps);
    
    // for (i = 0; i < numBodies; i++) {
    //     body = bodies[i];
    //     console.log(body.entity.name)
    // }
    // if(bodies.length > 1){
    //     console.log(bodies[0].entity.name)
    // console.log(bodies[1].entity.name)
    // }
    
    // Set the transforms of entities from dynamic bodies
    
    for (i = 0; i < numBodies; i++) {
        body = bodies[i];
        
        if(!body) continue;
        if (body.type === p2.Body.DYNAMIC) {
            entity = body.entity;
            
            // TODO: 

            //Another thing that p2.js does is interpolation of movement. If you pass all three parameters to world.step(), 
            //then you'll get an interpolated position for each Body via body.interpolatedPosition and body.interpolatedAngle. 
            //The movement will look a lot smoother if you use these values for rendering instead of .position and .angle.
            pos = body.useInterpolatedPosition !== false ? body.interpolatedPosition : body.position;
            
            
            switch (this.axes) {
                case 1:
                    entity.setPosition(pos[0], pos[1], entity.getPosition().z);                  
                    entity.setEulerAngles(0, 0, body.interpolatedAngle / Math.PI * 180);
                    break;
                case 2: //One we currently use (top down)
                    var currentPos = entity.getPosition();
                    var target = new pc.Vec3(pos[0], currentPos.y, -pos[1]);
                    target = target.lerp(currentPos, target, 0.3);
                    entity.setPosition(target.x, target.y, target.z);
                    entity.setEulerAngles(0, body.interpolatedAngle / Math.PI * 180, 0);
                    break;
                case 3:
                    entity.setPosition(entity.getPosition().x, pos[0], -pos[1]);
                    entity.setEulerAngles(body.interpolatedAngle / Math.PI * 180, 0, 0);
                    break;
            }
        }

        if (this.debugDraw) {
            shapes = body.shapes;
            numShapes = shapes.length;
            
            for (j = 0; j < numShapes; j++) {
                shape = shapes[j];
                
                var position = shape.body.entity.getPosition().clone();
                var points = [];
                var colors = [];
                var center = new pc.Vec3(position.x, position.y, position.z);
                var color = shape.sensor ? pc.Color.MAGENTA : pc.Color.RED;

                switch(shape.type){
                    case p2.Shape.CIRCLE:{
                        var radius = shape.radius;

                        var numSegments = 20;

                        var step = 2 * Math.PI / numSegments;
                        var angle = 0;
                        for (var k = 0; k < numSegments; k++) {
                          var sin0 = Math.sin(angle);
                          var cos0 = Math.cos(angle);
                          angle += step;
                          var sin1 = Math.sin(angle);
                          var cos1 = Math.cos(angle);

                          points.push(new pc.Vec3(center.x + radius * sin0, center.y + radius * cos0, center.z), new pc.Vec3(center.x + radius * sin1, center.y + radius * cos1, center.z));
                        }
                        break;
                    }
                    default:{
                        var angle = body.angle + shape.angle;
                        for(var k = 0; k<shape.vertices.length; k++){
                            
                            var vertStart = new pc.Vec2(shape.vertices[k][0], shape.vertices[k][1]);
                            vertStart = RotateVec2(vertStart, angle * pc.math.RAD_TO_DEG);
                            var pointStart = new pc.Vec3(position.x + shape.position[0] + vertStart.x, position.y + shape.position[1] + vertStart.y, position.z);
                            
                            var nextVert = k < shape.vertices.length - 1 ? shape.vertices[k + 1] : shape.vertices[0];
                            
                            var vertEnd = new pc.Vec2(nextVert[0], nextVert[1]);
                            vertEnd = RotateVec2(vertEnd, angle * pc.math.RAD_TO_DEG);
                            var pointEnd = new pc.Vec3(position.x + shape.position[0] + vertEnd.x, position.y + shape.position[1] + vertEnd.y, position.z);
                            
                            points.push(pointStart, pointEnd);
                        }
                        break;
                    }
                }
                
                if(points.length > 0){
                    for(var k = 0; k<points.length; k++){
                        colors.push(color);                        
                    }
                    this.app.renderLines(points, colors, {
                        depthTest: false
                    });
                }
            }
        }
    }
    
    
};


P2World.prototype.beginContactHandler = function(event){
    
    if (event.bodyA && event.bodyB)
    {
        //this.onBeginContact.dispatch(event.bodyA, event.bodyB, event.shapeA, event.shapeB, event.contactEquations);
        if (event.bodyA)
        {
            if (typeof event.bodyA.onBeginContact === "function") { 
                event.bodyA.onBeginContact(event.bodyB, event.shapeA, event.shapeB, event.contactEquations);
            }
            
        }

        if (event.bodyB)
        {
            if (typeof event.bodyB.onBeginContact === "function") { 
                event.bodyB.onBeginContact(event.bodyA, event.shapeB, event.shapeA, event.contactEquations);
            }
                        
        }
    }
};

P2World.prototype.endContactHandler = function(event){
    if (event.bodyA && event.bodyB)
    {
        //this.onBeginContact.dispatch(event.bodyA, event.bodyB, event.shapeA, event.shapeB, event.contactEquations);
        if (event.bodyA)
        {
            if (typeof event.bodyA.onEndContact === "function") { 
                event.bodyA.onEndContact(event.bodyB, event.shapeA, event.shapeB, event.contactEquations);
            }
            
        }

        if (event.bodyB)
        {
            if (typeof event.bodyB.onEndContact === "function") { 
                event.bodyB.onEndContact(event.bodyA, event.shapeB, event.shapeA, event.contactEquations);
            }
                        
        }
    }
};



