// RTLSetup.js

var app = pc.Application.getApplication();

// These functions are imported from unicode.bidirectional.js and converter.js
var convertArabicToPresentationForms = arabicConverter.convertArabic;
var resolveRtlOrLtr = UnicodeBidirectional.resolve;
var calculateIndices = UnicodeBidirectional.reorderPermutation;

// Unicode Converter takes the original unicode string and transforms into a different set of unicode charactesr
// In the case of arabic, we convert the unicode input string which contains the regular arabic alphabet and
// converts it into the "presentation forms" which are the characters that are specific to the location in the word
//app.systems.element.registerUnicodeConverter(convertArabicToPresentationForms);

var rtlReorder = function (symbols) {
    // Convert array of symbols to codepoints
    var codes = symbols.map(function (s) {
        return s.codePointAt(0);
    });

    // resolve levels and generate mapping
    var levels = resolveRtlOrLtr(codes, 0, true);
    var indices = calculateIndices(levels);

    var rtl = (levels[0] === 1);

    return { mapping: rtl ? indices.reverse() : indices, rtl: rtl };
};

app.systems.element.registerRtlReorder(rtlReorder);


pc.TextElement.prototype._setText = function _setText(text) {
    if (this.unicodeConverter) {
        var unicodeConverterFunc = this._system.getUnicodeConverter();

        if (unicodeConverterFunc) {
            text = unicodeConverterFunc(text);
        } else {
            //console.warn('Element created with unicodeConverter option but no unicodeConverter function registered');
        }
    }

    if (this._text !== text) {
        if (this._font) {
            this._updateText(text);
        }

        this._text = text;
    }
};

// RtlElement.js
var RtlElement = pc.createScript('rtlElement');

RtlElement.attributes.add("overrideColorForArabic", { type: 'boolean', default: false });
RtlElement.attributes.add("overrideColor", { type: 'rgb' });
/*
 * Attach this script to Text Element components that need to support RTL text
 * When rendering text the element will use a pre-registered converter
 * to correctly render the RTL text. (See also RtlSetup.js)
 */
RtlElement.prototype.initialize = function() {
    if(this.entity.element && this.app.i18n.locale == "ar") {
        this.entity.element.rtlReorder = true;
        this.entity.element.unicodeConverter = true;
        this.entity.element.outlineThickness = 0;
        this.entity.element.shadowOffset = new pc.Vec2(0, 0);
        
        if(this.entity.element.alignment.x === 0){
            this.entity.element.alignment = new pc.Vec2(0, this.entity.element.alignment.y);
        }

        if(this.overrideColorForArabic){
            this.entity.element.color = this.overrideColor;
        }

        
    }
};

// WarpShader.js
var WarpShader = pc.createScript('warpShader');

WarpShader.attributes.add('transformVS', { type: 'asset', assetType: 'shader' });

WarpShader.curveAngle = 0;
WarpShader.curveStrength = 0;
WarpShader.curveStartDepth = 0;
WarpShader.curveEndDepth = 0;

// initialize code called once per entity
WarpShader.prototype.initialize = function() {
    this.materials = [];
    this.time = 0;
};

WarpShader.prototype.postInitialize = function() {        
    var render = this.entity.model ? this.entity.model : this.entity.render;
    
    for (var i = 0; i < render.meshInstances.length; i++) {
        var material = new pc.StandardMaterial();
        material.chunks.transformVS = this.transformVS.resource;
        
        var meshInstance = render.meshInstances[i];
        var diffuseMap = meshInstance.material.diffuseMap;
        var emissiveMap = meshInstance.material.emissiveMap;
        var opacityMap = meshInstance.material.opacityMap;
        var emissiveIntensity = meshInstance.material.emissiveIntensity;
        var opacity = meshInstance.material.opacity;
        var blendType = meshInstance.material.blendType;
        var opacityMapChannel = meshInstance.material.opacityMapChannel;
        var useGammaTonemap = meshInstance.material.useGammaTonemap;
        var useLighting = meshInstance.material.useLighting;
        var depthWrite = meshInstance.material.depthWrite;
        
        meshInstance.material = material;
        meshInstance.material.setParameter('texture_diffuseMap', diffuseMap);
        meshInstance.material.diffuseMap = diffuseMap;
        meshInstance.material.emissiveMap = emissiveMap;
        meshInstance.material.opacityMap = opacityMap;
        meshInstance.material.emissiveIntensity = emissiveIntensity;
        meshInstance.material.opacity = opacity;
        meshInstance.material.blendType = blendType;
        meshInstance.material.opacityMapChannel = opacityMapChannel;
        meshInstance.material.useGammaTonemap = useGammaTonemap;
        meshInstance.material.useLighting = useLighting;
        meshInstance.material.depthWrite = depthWrite;
        this.materials.push(material);
    }
    
    
    for(var i = 0; i<this.materials.length; i++){
        this.materials[i].setParameter('curveAngle', WarpShader.curveAngle);
        this.materials[i].setParameter('curveStrength', WarpShader.curveStrength);
        this.materials[i].setParameter('curveStartDepth', WarpShader.curveStartDepth);
        this.materials[i].setParameter('curveEndDepth', WarpShader.curveEndDepth);
        this.materials[i].update();
    }
    
    
};

// update code called every frame
WarpShader.prototype.update = function(dt) {
    if(GameManager.Instance.IsPaused()) return;
    this.time += dt;
    
    for(var i = 0; i<this.materials.length; i++){
        this.materials[i].setParameter('curveAngle', WarpShader.curveAngle);
        this.materials[i].setParameter('curveStrength', WarpShader.curveStrength);
        this.materials[i].setParameter('curveStartDepth', WarpShader.curveStartDepth);
        this.materials[i].setParameter('curveEndDepth', WarpShader.curveEndDepth);
        this.materials[i].update();
    }
    
};



// TunnelManager.js
var TunnelManager = pc.createScript('tunnelManager');

TunnelManager.attributes.add('curveAngle', { type: 'number', default: 0, min: 0, max: 360 });
TunnelManager.attributes.add('curveStrength', { type: 'number', default: 90, min: 20, max: 200 });
TunnelManager.attributes.add('curveStartDepth', { type: 'number', default: 10, min: 10, max: 50 });
TunnelManager.attributes.add('curveEndDepth', { type: 'number', default: 100, min: 50, max: 100 });
TunnelManager.attributes.add("tunnelEntity", { type: 'entity' });
TunnelManager.attributes.add("gameProgressEntity", { type: 'entity' });

// initialize code called once per entity
TunnelManager.prototype.initialize = function() {
    this.scene = SceneManager.Instance.loadedSceneEntity.script.gameScene;

    this.tunnel = this.tunnelEntity.script.tunnel;
    this.gameProgress = this.gameProgressEntity.script.gameProgress;
    
    this.obstacleIndex = 0;
    
    WarpShader.curveAngle = this.curveAngle;
    WarpPosition.curveAngle = this.curveAngle;

    WarpShader.curveStartDepth = this.curveStartDepth;
    WarpPosition.curveStartDepth = this.curveStartDepth;
    
    WarpShader.curveEndDepth = this.curveEndDepth;
    WarpPosition.curveEndDepth = this.curveEndDepth;
    
    WarpShader.curveStrength = this.curveStrength;
    WarpPosition.curveStrength = this.curveStrength;
    
    this.on('attr:curveAngle', this.OnAttributeCurveAngleChanged, this);
    this.on('attr:curveStrength', this.OnAttributeCurveStrengthChanged, this);
    this.on('attr:curveStartDepth', this.OnAttributeCurveStartDepthChanged, this);
    this.on('attr:curveEndDepth', this.OnAttributeCurveEndDepthChanged, this);
    
    this.curveStrengthRng = new Math.seedrandom(GameScene.levelID + "_rndCurveStrength");
    this.curveAngleRng = new Math.seedrandom(GameScene.levelID + "_rndCurveAngle");
    
    this.curveAngle = this.curveAngleRng() * 360;
    this.curveStrength = 25 + (this.curveStrengthRng() * 175);
    
    this.spawnZ = -60;
    this.tunnelSpawnDistance = 20;
    this.currentSpawnDistance = 0;
    this.completeLevelDistance = 0;
    this.tunnelTravelStartSpeed = this.scene.levelData.startSpeed ? this.scene.levelData.startSpeed : 10; //m/s
    this.tunnelTravelEndSpeed = this.scene.levelData.endSpeed ? this.scene.levelData.endSpeed : this.tunnelTravelStartSpeed;
    this.tunnelTravelEndSpeedTime = 120; //How many seconds till we reach max speed
    this.tunnelTravelEndSpeedTimer = this.tunnelTravelEndSpeedTime;
    this.tunnelTravelSpeed = this.tunnelTravelStartSpeed; 
    this.distanceTravelled = 0;


    if(!this.scene.isEndless){
        this.totalDistance = Math.abs(this.spawnZ);

        for(var i = 0; i<this.scene.levelData.obstacles.length; i++){
            this.totalDistance += this.tunnelSpawnDistance;
        }

        this.totalDistance -= 10;
    }
    
    
    
    this.playerZ = -5;
    this.startCheckCollisionZ = this.playerZ - 1;
    this.endCheckCollisionZ = this.playerZ + 1;
    this.midCheckCollisionZ = pc.math.lerp(this.startCheckCollisionZ, this.endCheckCollisionZ, 0.5);
    this.distanceToMidCollision = this.spawnZ - this.midCheckCollisionZ;
    this.despawnTunnelObjectZ = this.playerZ + 2;
    
    this.previousObstacleTemplateID = null;
    
    this.curveChangeTimeMultiplier = 5;
    
    this.tweenCurveAngle = this.curveAngle;
    
    this.tunnelObjects = [];
    this.tunnelObjectsPool = [];
    
    
    
    
    this.curveStrengthTween = this.entity.tween(this);
    this.curveAngleTween = this.entity.tween(this);
    
    
    
    this.state = null;
};

// update code called every frame
TunnelManager.prototype.update = function(dt) {
    if(GameManager.Instance.IsPaused()) return;
    
    switch(this.state){
        case GameScene.State.Game:{
            this.UpdateGameState(dt);
            break;
        }
    }
};

TunnelManager.prototype.UpdateGameState = function(dt) {
    this.TravelTunnel(dt);
};


TunnelManager.prototype.SetState = function(state) {
    this.state = state;
    
    this.tunnel.SetState(state);
    
    for(var i = 0; i<this.tunnelObjects.length; i++){
        this.tunnelObjects[i].SetState(state);
    }
    
    switch(this.state){
        case GameScene.State.Game:{
            this.OnEnterGameState();
            break;
        }
        case GameScene.State.GameOver:{
            this.OnEnterGameOverState();
            break;
        }
        case GameScene.State.HitButton:{
            this.OnEnterHitButtonState();
            break;
        }
    }
};

TunnelManager.prototype.OnEnterGameState = function() {
    this.TweenRandomCurveStrength();
    this.TweenRandomCurveAngle();
    
    this.SpawnNextTunnelObject();
};

TunnelManager.prototype.OnEnterGameOverState = function() {
    this.curveAngleTween.stop();
    this.curveStrengthTween.stop();
};

TunnelManager.prototype.OnEnterHitButtonState = function() {
    this.curveAngleTween.stop();
    this.curveStrengthTween.stop();
};


TunnelManager.prototype.TravelTunnel = function(dt) {   
    
    if(this.tunnelTravelEndSpeedTimer > 0){
        this.tunnelTravelEndSpeedTimer -= dt;
        this.tunnelTravelEndSpeedTimer = Math.max(this.tunnelTravelEndSpeedTimer, 0);
        
        this.tunnelTravelSpeed = pc.math.lerp(this.tunnelTravelStartSpeed, this.tunnelTravelEndSpeed, 1-(this.tunnelTravelEndSpeedTimer / this.tunnelTravelEndSpeedTime));
    }
    
    var moveAmount = this.tunnelTravelSpeed * dt;
    //moveAmount = 0.0000001;
    
    this.distanceTravelled += moveAmount;

    if(this.scene.isEndless){
        this.gameProgress.SetProgress(Math.round(this.distanceTravelled));
    }
    else{
        this.gameProgress.SetProgress(Math.min(1, this.distanceTravelled / this.totalDistance));
    }

    this.tunnel.Travel(moveAmount);
    
    for(var i = this.tunnelObjects.length - 1; i>=0; i--){
        this.tunnelObjects[i].Move(moveAmount);
        
        var position = this.tunnelObjects[i].entity.getPosition();
        
        if(position.z > this.startCheckCollisionZ && position.z < this.endCheckCollisionZ){
            if(!this.tunnelObjects[i].collisionActive){
                this.tunnelObjects[i].EnableCollision();
            }
        }
        else { 
            if(this.tunnelObjects[i].collisionActive){
                this.tunnelObjects[i].OnPassedPlayer();
                this.tunnelObjects[i].DisableCollision();
            }
        }
        
        if(position.z >= this.despawnTunnelObjectZ){
            this.tunnelObjects[i].entity.enabled = false;
            this.tunnelObjectsPool.push(this.tunnelObjects[i]);
            this.tunnelObjects.splice(i, 1);
        }
    }
    
    if(this.currentSpawnDistance <= this.tunnelSpawnDistance){
        this.currentSpawnDistance += moveAmount;

        if(this.currentSpawnDistance >= this.tunnelSpawnDistance){
            this.SpawnNextTunnelObject();
        }
    }
    
    if(this.completeLevelDistance > 0){
        this.completeLevelDistance -= moveAmount;
        
        if(this.completeLevelDistance <= 0){
            this.SpawnTunnelObject({
                "templateID": "TunnelEndButton"
            });
            
        }
    }
    
};

TunnelManager.prototype.SetCurveAngle = function(curveAngle) {  
    this.curveAngle = curveAngle;
    WarpShader.curveAngle = this.curveAngle;
    WarpPosition.curveAngle = this.curveAngle;
};

TunnelManager.prototype.TweenRandomCurveStrength = function() {  
    var curveStrength = 0;
    var minStrength = 0;
    var maxStrength = 200;
    if(this.scene.isEndless){
        curveStrength = pc.math.random(minStrength, maxStrength);
    }
    else{
        curveStrength = minStrength + (this.curveStrengthRng() * (maxStrength - minStrength));
    }
    var delay = 0;
    var duration = Math.max(0.01, Math.abs(this.curveStrength - curveStrength) / this.tunnelTravelSpeed);
    this.curveStrengthTween.stop();
    this.curveStrengthTween = this.entity.tween(this);
    this.curveStrengthTween.to({curveStrength: curveStrength}, duration * this.curveChangeTimeMultiplier, pc.SineInOut, delay);
    this.curveStrengthTween.on("complete", this.TweenRandomCurveStrength, this);
    this.curveStrengthTween.start();
};

TunnelManager.prototype.TweenRandomCurveAngle = function() {  
    
    var curveAngle = 0;
    if(this.scene.isEndless){
        curveAngle = pc.math.random(0, 360);
    }
    else{
        curveAngle = this.curveAngleRng() * 360;
    }
    
    
    var delay = 0;
    var duration = Math.max(0.01, Math.abs(this.tweenCurveAngle - curveAngle) / this.tunnelTravelSpeed);
    this.curveAngleTween.stop();
    this.curveAngleTween = this.entity.tween(this);
    this.curveAngleTween.to({tweenCurveAngle: curveAngle}, duration * this.curveChangeTimeMultiplier, pc.SineInOut, delay);
    this.curveAngleTween.on("update", function(){
        this.SetCurveAngle(this.tweenCurveAngle);
    }, this);
    this.curveAngleTween.on("complete", this.TweenRandomCurveAngle, this);
    this.curveAngleTween.start();
};


TunnelManager.prototype.OnAttributeCurveAngleChanged = function(value, prev) {    
    WarpShader.curveAngle = this.curveAngle;
    WarpPosition.curveAngle = this.curveAngle;
};


TunnelManager.prototype.OnAttributeCurveStartDepthChanged = function(value, prev) {    
    WarpShader.curveStartDepth = this.curveStartDepth;
    WarpPosition.curveStartDepth = this.curveStartDepth;
};

TunnelManager.prototype.OnAttributeCurveEndDepthChanged = function(value, prev) {    
    WarpShader.curveEndDepth = this.curveEndDepth;
    WarpPosition.curveEndDepth = this.curveEndDepth;
};

TunnelManager.prototype.OnAttributeCurveStrengthChanged = function(value, prev) {    
    WarpShader.curveStrength = this.curveStrength;
    WarpPosition.curveStrength = this.curveStrength;
};


TunnelManager.prototype.SpawnNextTunnelObject = function() {  
    var obstacleData = null;
    
    var spawnZOffset = 0;
    var spawnedFromDistanceTraveled = this.currentSpawnDistance > this.tunnelSpawnDistance;
    if(spawnedFromDistanceTraveled){
        spawnZOffset = this.currentSpawnDistance - this.tunnelSpawnDistance;
    }
    
    if(this.scene.isEndless){
        var templateIDIndex = Math.floor(pc.math.random(0, this.scene.levelData.obstacles.length));
        obstacleData = this.scene.levelData.obstacles[templateIDIndex];
        
        //If this is the same obstacle as previously spawned and the obstacle doesn't allow consecutive placement, recall function
        if(obstacleData.templateID == this.previousObstacleTemplateID && !obstacleData.allowConsecutive){
            this.SpawnNextTunnelObject();
            return;
        }
        
        if(spawnedFromDistanceTraveled){
            this.currentSpawnDistance -= this.tunnelSpawnDistance;
        }
    }
    else{
        obstacleData = this.scene.levelData.obstacles[this.obstacleIndex];
        
        this.obstacleIndex++;
        if(this.obstacleIndex < this.scene.levelData.obstacles.length){
            if(spawnedFromDistanceTraveled){
                this.currentSpawnDistance -= this.tunnelSpawnDistance;
            }
            
        }
        else{
            this.completeLevelDistance = this.tunnelSpawnDistance;
        }
    }

    this.SpawnTunnelObject(obstacleData, spawnZOffset);
};

TunnelManager.prototype.SpawnTunnelObject = function(obstacleData, zOffset) {  
    if(obstacleData && obstacleData.templateID){
        if(!zOffset){
            zOffset = 0;
        }
        this.previousObstacleTemplateID = obstacleData.templateID;
        
        var tunnelObjectTemplate = this.app.assets.find(obstacleData.templateID, "template");

        var tunnelObject = null;

        for(var i = 0; i<this.tunnelObjectsPool.length; i++){
            if(!this.tunnelObjectsPool[i].entity.enabled && this.tunnelObjectsPool[i].entity.name == obstacleData.templateID){
                tunnelObject = this.tunnelObjectsPool[i];
                this.tunnelObjectsPool.splice(i, 1);
                break;
            }
        }

        if(!tunnelObject){
            var clonedEntity = tunnelObjectTemplate.resource.instantiate();
            clonedEntity.name = obstacleData.templateID;
            this.entity.addChild(clonedEntity);

            tunnelObject = clonedEntity.tunnelObject;
        }

        this.tunnelObjects.push(tunnelObject);


        tunnelObject.entity.setPosition(0, 0, this.spawnZ + zOffset);

        tunnelObject.Spawn(this, obstacleData);
    }
};


// WarpPosition.js
var WarpPosition = pc.createScript('warpPosition');

WarpPosition.curveAngle = 0;
WarpPosition.curveStrength = 0;
WarpPosition.curveStartDepth = 0;
WarpPosition.curveEndDepth = 0;

// initialize code called once per entity
WarpPosition.prototype.initialize = function() {
    this.unwarpedPosition = this.entity.getPosition();
    this.warpedPosition = new pc.Vec3();
    this.warpOffset = new pc.Vec2();
    this.vertPosition = new pc.Vec3();
    
    this.curveAxis = new pc.Vec3();
};

// update code called every frame
WarpPosition.prototype.update = function(dt) {
    if(GameManager.Instance.IsPaused()) return;
    this.WarpPosition();
};


WarpPosition.prototype.QuatFromAxisAngle = function(axis, angle)
{ 
    var qr = new pc.Vec4();
    var half_angle = (angle * 0.5) * 3.14159 / 180.0;
    qr.x = axis.x * Math.sin(half_angle);
    qr.y = axis.y * Math.sin(half_angle);
    qr.z = axis.z * Math.sin(half_angle);
    qr.w = Math.cos(half_angle);
    return qr;
};

WarpPosition.prototype.RotatePosition = function(position, axis, angle)
{
    var q = this.QuatFromAxisAngle(axis, angle);
    var v = position.clone();
    var q_xyz = new pc.Vec3(q.x, q.y, q.z);
    
    var crossA = new pc.Vec3().cross(q_xyz, v);
    var vw = v.clone();
    vw.mulScalar(q.w);
    crossA.add(vw);
    var crossB = new pc.Vec3().cross(q_xyz, crossA);
    crossB.mulScalar(2.0);
    var result = v.clone();
    result.add(crossB);
    return result;
};

WarpPosition.prototype.WarpPosition = function()
{   
    var depth = -this.unwarpedPosition.z;
    
    var depthPercent = pc.math.clamp((depth - WarpPosition.curveStartDepth) / (WarpPosition.curveEndDepth - WarpPosition.curveStartDepth), 0.0, 1.0);
    
    var ease = pc.CircularIn(depthPercent);
    var currentAngle = pc.math.lerp(0.0, 90.0, ease);
    
    
    var radians = pc.math.DEG_TO_RAD * WarpPosition.curveAngle;
    
    
    this.vertPosition.set(this.unwarpedPosition.x, this.unwarpedPosition.y, 0.0);
    this.curveAxis.set(Math.cos(radians), -Math.sin(radians), 0.0);
    var rotatedPosition = this.RotatePosition(this.vertPosition, this.curveAxis, currentAngle);
    
    this.warpOffset.set(this.curveAxis.y * (ease * WarpPosition.curveStrength), this.curveAxis.x * (ease * -WarpPosition.curveStrength));
    this.warpedPosition.x = rotatedPosition.x + this.warpOffset.x;
    this.warpedPosition.y = rotatedPosition.y + this.warpOffset.y;
    this.warpedPosition.z = this.unwarpedPosition.z - rotatedPosition.z;
    
    this.entity.setPosition(this.warpedPosition.x, this.warpedPosition.y, this.warpedPosition.z);
};


// TunnelObject.js
var TunnelObject = pc.createScript('tunnelObject');

TunnelObject.attributes.add("bodyEntities", { type: 'entity', array: true });
TunnelObject.attributes.add("modelEntities", { type: 'entity', array: true });

// initialize code called once per entity
TunnelObject.prototype.initialize = function() {
    this.scene = SceneManager.Instance.loadedSceneEntity.script.gameScene;
    
    this.entity.tunnelObject = this;
    
    this.hasPassedPlayer = false;
    this.collisionActive = false;
    
    this.collisionShapes = [];
    this.bodies = [];
    this.tunnelObstacleShaders = [];
    
    
    
    for(var i = 0; i<this.bodyEntities.length; i++){
        if(this.bodyEntities[i].script.p2Convex){
            this.collisionShapes.push(this.bodyEntities[i].script.p2Convex);
        }
        if(this.bodyEntities[i].script.p2PhysicsEditorShape){
            this.collisionShapes.push(this.bodyEntities[i].script.p2PhysicsEditorShape);
        }
    }
    
};

TunnelObject.prototype.postInitialize = function() {
    for(var i = 0; i<this.bodyEntities.length; i++){
        this.bodies.push(this.bodyEntities[i].script.p2Body.body);
        this.bodyEntities[i].script.p2Body.body.onBeginContact = this.OnBeginContact.bind(this);
    }
};

// update code called every frame
TunnelObject.prototype.update = function(dt) {
    if(GameManager.Instance.IsPaused()) return;
};

TunnelObject.prototype.Spawn = function(tunnelManager, obstacleData) {
    this.entity.enabled = true;
    this.hasPassedPlayer = false;
    
    for(var i = 0; i<this.tunnelObstacleShaders.length; i++){
        this.tunnelObstacleShaders[i].Spawn();
    }
};


TunnelObject.prototype.Move = function(amount) {
    this.entity.translate(0, 0, amount);
};


TunnelObject.prototype.OnPassedPlayer = function() {
    this.hasPassedPlayer = true;
    
    for(var i = 0; i<this.tunnelObstacleShaders.length; i++){
        this.tunnelObstacleShaders[i].OnPassedPlayer();
    }
};

TunnelObject.prototype.EnableCollision = function() {
    for(var i = 0; i<this.collisionShapes.length; i++){
        this.collisionShapes[i].AddToBody();
    }
    
    this.collisionActive = true;
};

TunnelObject.prototype.DisableCollision = function() {
    for(var i = 0; i<this.collisionShapes.length; i++){
        this.collisionShapes[i].RemoveFromBody();
    }

    this.collisionActive = false;
};

TunnelObject.prototype.SetState = function(state) {
    for(var i = 0; i<this.tunnelObstacleShaders.length; i++){
        this.tunnelObstacleShaders[i].SetState(state);
    }
    
};

TunnelObject.prototype.OnBeginContact = function(body, shape, shapeB, contactEquations) {

};


// Player.js
var Player = pc.createScript('player');

Player.attributes.add("playerAnimationEntity", { type: 'entity' });

// initialize code called once per entity
Player.prototype.initialize = function() {
    this.scene = SceneManager.Instance.loadedSceneEntity.script.gameScene;
    Object.defineProperty(this, 'body', { get: function() { return this.entity.script ? this.entity.script.p2Body.body : {velocity:{},position:[]}; } });
    
    this.playerInput = this.entity.script.playerInput;
    this.playerAnimation = this.playerAnimationEntity.script.playerAnimation;
    
    this.moveSpeed = 5;
    
    this.moveMaxDistance = 2.9;
    this.invincible = false;
    
    this.state = null;
};

Player.prototype.postInitialize = function() {
    this.body.player = this;
};


// update code called every frame
Player.prototype.update = function(dt) {
    if(GameManager.Instance.IsPaused()) return;
    
    switch(this.state){
        case GameScene.State.Game:{
            this.UpdateGameState(dt);
            break;
        }
    }
};

Player.prototype.UpdateGameState = function(dt) {
    this.Move(this.playerInput.moveVector, dt);
};


Player.prototype.SetState = function(state) {
    this.state = state;

    switch(this.state){
        case GameScene.State.Dead:{
            this.OnEnterDeadState();
            break;
        }
        case GameScene.State.HitButton:{
            this.OnEnterHitButtonState();
            break;
        }
        case GameScene.State.GameComplete:{
            this.OnEnterGameCompleteState();
            break;
        }
    }
    
    this.playerInput.SetState(state);
};

Player.prototype.OnEnterDeadState = function() {
    this.playerAnimation.PlayAnimation(PlayerAnimation.Animation.Hit);
};

Player.prototype.OnEnterHitButtonState = function() {
    this.playerAnimation.PlayAnimation(PlayerAnimation.Animation.End);
};

Player.prototype.OnEnterGameCompleteState = function() {
    this.playerAnimation.PlayAnimation(PlayerAnimation.Animation.Win);
};

Player.prototype.Move = function(moveVector, dt) {
    this.body.position[0] += moveVector.x * this.moveSpeed * dt;
    this.body.position[1] += moveVector.y * this.moveSpeed * dt;
    
    
    var animation = this.GetAnimationFromMoveVector(moveVector);
    this.playerAnimation.PlayAnimation(animation);

    var distance = Math.dist(this.body.position[0], this.body.position[1], 0, 0);
    
    if(distance > this.moveMaxDistance){
        var change = this.moveMaxDistance / distance;
        
        var newX = this.body.position[0] * change;
        var newY = this.body.position[1]* change;
        
        this.body.position[0] = newX;
        this.body.position[1] = newY;
    }
};


Player.prototype.GetAnimationFromMoveVector = function(moveVector) {
    var animation = PlayerAnimation.Animation.Idle;
    
    if(moveVector.x != 0 || moveVector.y != 0){
        if(Math.abs(moveVector.x) > Math.abs(moveVector.y)){
            animation = moveVector.x > 0 ? PlayerAnimation.Animation.Right : PlayerAnimation.Animation.Left;
        }
        else{
            animation = moveVector.y > 0 ? PlayerAnimation.Animation.Up : PlayerAnimation.Animation.Down;
        }
    }
    
    return animation;
};


Player.prototype.OnHitObstacle = function() {
    if(!this.invincible){
        AudioManager.Instance.Play("sfx_game", "crash");
        this.scene.SetState(GameScene.State.Dead);
    }
    
};

Player.prototype.OnHitEndButton = function() {
    this.scene.SetState(GameScene.State.HitButton);
};

// PlayerInput.js
var PlayerInput = pc.createScript('playerInput');

PlayerInput.attributes.add('mobileTouchControllerEntity', { type: 'entity' });

// initialize code called once per entity
PlayerInput.prototype.initialize = function() {
    this.moveVector = new pc.Vec2();
    
    this.mobileTouchController = this.mobileTouchControllerEntity.script.mobileTouchController;
    
    this.state = null;
};


// update code called every frame
PlayerInput.prototype.update = function(dt) {
    if(GameManager.Instance.IsPaused()) return;
    
    switch(this.state){
        case GameScene.State.Game:{
            this.UpdateGameState(dt);
            break;
        }
    }
};

PlayerInput.prototype.UpdateGameState = function(dt) {
    this.moveVector.set(0, 0);
    
    this.moveVector.x += this.mobileTouchController.moveVector.x;
    this.moveVector.y += this.mobileTouchController.moveVector.y;
    
    if(this.moveVector.x == 0 && this.moveVector.y == 0){
        if(this.app.keyboard.isPressed(pc.KEY_UP) || this.app.keyboard.isPressed(pc.KEY_W)){
            this.moveVector.y += 1;
        } 
        if(this.app.keyboard.isPressed(pc.KEY_DOWN) || this.app.keyboard.isPressed(pc.KEY_S)){
            this.moveVector.y += -1;
        } 
        if(this.app.keyboard.isPressed(pc.KEY_LEFT) || this.app.keyboard.isPressed(pc.KEY_A)){
            this.moveVector.x += -1;
        } 
        if(this.app.keyboard.isPressed(pc.KEY_RIGHT) || this.app.keyboard.isPressed(pc.KEY_D)){
            this.moveVector.x += 1;
        } 

        this.moveVector.normalize();
    }
};


PlayerInput.prototype.SetState = function(state) {
    this.state = state;
};


// GameCamera.js
var GameCamera = pc.createScript('gameCamera');

GameCamera.attributes.add('cameraEntity', { type: 'entity' });
GameCamera.attributes.add('followEntity', { type: 'entity' });
GameCamera.attributes.add('followLerpStrength', { type: 'number' });

// initialize code called once per entity
GameCamera.prototype.initialize = function() {
    this.scene = SceneManager.Instance.loadedSceneEntity.script.gameScene;
    
    this.followEntityPosition = this.followEntity.getPosition().clone();
    this.tempVec3 = this.followEntityPosition.clone();
    
    this.cameraShake = this.cameraEntity.script.cameraShake;
    
    this.cameraCrashInTween = this.entity.tween(this.entity.getLocalPosition());
    this.cameraCrashOutTween = this.entity.tween(this.entity.getLocalPosition());
    
    this.crashInDistance = 1.25;
    
    this.state = null;
};

GameCamera.prototype.postInitialize = function() {
    this.LerpCameraToTarget(1);
};

// update code called every frame
GameCamera.prototype.update = function(dt) {
    if(GameManager.Instance.IsPaused()) return;
    
    switch(this.state){
        case GameScene.State.Game:{
            this.UpdateGameState(dt);
            break;
        }
    }
};

GameCamera.prototype.UpdateGameState = function(dt) {
    this.LerpCameraToTarget(this.followLerpStrength);
};

GameCamera.prototype.SetState = function(state) {
    this.state = state;
    
    switch(this.state){
        case GameScene.State.Dead:{
            this.OnEnterDeadState();
            break;
        }
    }
};

GameCamera.prototype.OnEnterDeadState = function() {
    var currentPosition = this.entity.getLocalPosition();
    
    var crashInTime = (1 / this.scene.tunnelManager.tunnelTravelSpeed) * this.crashInDistance;
    this.cameraCrashInTween.stop();
    this.cameraCrashInTween = this.entity.tween(this.entity.getLocalPosition());
    this.cameraCrashInTween.pausable = false;
    this.cameraCrashInTween.to({x: currentPosition.x, y: currentPosition.y, z: currentPosition.z - this.crashInDistance}, crashInTime, pc.Linear);
    this.cameraCrashInTween.on("complete", this.OnCameraCrashInTweenComplete, this);
    this.cameraCrashInTween.start();
};

GameCamera.prototype.OnCameraCrashInTweenComplete = function() {
    this.cameraShake.Start(0.025, 0.15, 0.25);
    
    var currentPosition = this.entity.getLocalPosition();
    this.cameraCrashOutTween.stop();
    this.cameraCrashOutTween = this.entity.tween(this.entity.getLocalPosition());
    this.cameraCrashOutTween.pausable = false;
    this.cameraCrashOutTween.to({x: currentPosition.x, y: currentPosition.y, z: currentPosition.z + this.crashInDistance}, 0.25, pc.SineOut);
    this.cameraCrashOutTween.on("complete", this.OnCameraCrashOutTweenComplete, this);
    this.cameraCrashOutTween.start();
};

GameCamera.prototype.OnCameraCrashOutTweenComplete = function() {
    this.scene.SetState(GameScene.State.GameOver);
};

GameCamera.prototype.LerpCameraToTarget = function(lerpStrength) {
    var lerpPosition = this.GetLerpPosition(lerpStrength);
    
    this.followEntityPosition.set(lerpPosition.x, lerpPosition.y, lerpPosition.z);
    this.entity.setPosition(this.followEntityPosition.x, this.followEntityPosition.y, this.followEntityPosition.z);
};

GameCamera.prototype.GetLerpPosition = function(lerpStrength) {
    var followLerpStrength = pc.math.clamp(lerpStrength, 0, 1);
    var followEntityPosition = this.followEntity.getPosition();
    
    var position = this.entity.getPosition();
    
    this.tempVec3.x = pc.math.lerp(position.x, followEntityPosition.x, followLerpStrength);
    this.tempVec3.y = pc.math.lerp(position.y, followEntityPosition.y, followLerpStrength);
    this.tempVec3.z = position.z;
    return this.tempVec3;
};

