// MobileTouchController.js
var MobileTouchController = pc.createScript('mobileTouchController');

MobileTouchController.attributes.add("screenEntity", { type: 'entity' });
MobileTouchController.attributes.add("containerEntity", { type: 'entity' });
MobileTouchController.attributes.add("analogContainerEntity", { type: 'entity' });
MobileTouchController.attributes.add("analogBaseEntity", { type: 'entity' });
MobileTouchController.attributes.add("analogStickEntity", { type: 'entity' });

// initialize code called once per entity
MobileTouchController.prototype.initialize = function() {
    this.analogContainerEntity.element.on(pc.EVENT_MOUSEDOWN, this.OnAnalogContainerPointerDown, this);
    this.analogContainerEntity.element.on(pc.EVENT_TOUCHSTART, this.OnAnalogContainerPointerDown, this);
    
    this.defaultAnalogBasePosition = this.analogBaseEntity.getLocalPosition().clone();
    this.eventPosition = new pc.Vec2();
    this.downPosition = new pc.Vec2();
    this.maxStickDistance = 80;
    this.UpdateContainerSize();
    
    this.paddingX = 150;
    this.paddingY = 150;
    
    this.moveVector = new pc.Vec2();
    
    this.containerEntity.enabled = false;
    this.on("destroy", this.OnDestroy, this);

    if(!Device.Instance().desktop){
        this.containerEntity.enabled = true;
        
    }  
    
    this.analogTouch = null;
};

// update code called every frame
MobileTouchController.prototype.update = function(dt) {
    this.UpdateContainerSize();
};

MobileTouchController.prototype.UpdateContainerSize = function() {
    this.analogContainerEntity.element.width = (this.screenEntity.screen.resolution.x * 0.5);
    this.analogContainerEntity.element.height = this.screenEntity.screen.resolution.y;
};

MobileTouchController.prototype.OnAnalogContainerPointerDown = function(event) {    
    var eventX = event.x !== undefined ? event.x : event.changedTouches[0].x;
    var eventY = event.y !== undefined ? event.y : event.changedTouches[0].y;
    this.eventPosition.set(eventX, eventY);
    
    var uiPosition = ScreenToUI(this.eventPosition);
    
    this.downPosition.set(pc.math.clamp(uiPosition.x + (this.screenEntity.screen.resolution.x * 0.5), this.paddingX, (this.screenEntity.screen.resolution.x * 0.5) - this.paddingX), 
                          pc.math.clamp(uiPosition.y + (this.screenEntity.screen.resolution.y * 0.5), this.paddingY, (this.screenEntity.screen.resolution.y) - this.paddingY));
    
    this.analogBaseEntity.setLocalPosition(this.downPosition.x, this.downPosition.y, 0);
    
    this.analogTouch = event.touch;
    
    this.OnAnalogContainerPointerMove(event);
    
    if(this.app.mouse){
        this.analogContainerEntity.element.on(pc.EVENT_MOUSEMOVE, this.OnAnalogContainerPointerMove, this);
        this.analogContainerEntity.element.on(pc.EVENT_MOUSEUP, this.OnAnalogContainerPointerUp, this);
    }
    
    if(this.app.touch){
        this.analogContainerEntity.element.on(pc.EVENT_TOUCHMOVE, this.OnAnalogContainerPointerMove, this);
        this.analogContainerEntity.element.on(pc.EVENT_TOUCHEND, this.OnAnalogContainerPointerUp, this);
        this.analogContainerEntity.element.on(pc.EVENT_TOUCHCANCEL, this.OnAnalogContainerPointerUp, this);
    }
    
};

MobileTouchController.prototype.OnAnalogContainerPointerMove = function(event) {    
    var eventX = event.x !== undefined ? event.x : event.changedTouches[0].x;
    var eventY = event.y !== undefined ? event.y : event.changedTouches[0].y;
    
    this.eventPosition.set(eventX, eventY);
    
    var uiPosition = ScreenToUI(this.eventPosition);
    
    var moveX = (uiPosition.x + (this.screenEntity.screen.resolution.x * 0.5)) - this.downPosition.x;
    var moveY = (uiPosition.y + (this.screenEntity.screen.resolution.y * 0.5)) - this.downPosition.y;
    
    var distance = Math.dist(moveX, moveY, 0, 0);
                
    if(distance > this.maxStickDistance){
        var change = this.maxStickDistance / distance;
        
        moveX *= change;
        moveY *= change;
    }
    
    this.analogStickEntity.setLocalPosition(moveX, moveY, 0);
    
    this.moveVector.set(moveX, moveY);
    this.moveVector.normalize();
    
    var scalar = distance != 0 ? Math.min(1, distance / this.maxStickDistance) : 0;
    
    this.moveVector.mulScalar(scalar);
};

MobileTouchController.prototype.OnAnalogContainerPointerUp = function(event) {    
    if(this.app.mouse){
        this.analogContainerEntity.element.off(pc.EVENT_MOUSEMOVE, this.OnAnalogContainerPointerMove, this);
        this.analogContainerEntity.element.off(pc.EVENT_MOUSEUP, this.OnAnalogContainerPointerUp, this);
    }
    
    if(this.app.touch){
        this.analogContainerEntity.element.off(pc.EVENT_TOUCHMOVE, this.OnAnalogContainerPointerMove, this);
        this.analogContainerEntity.element.off(pc.EVENT_TOUCHEND, this.OnAnalogContainerPointerUp, this);
        this.analogContainerEntity.element.off(pc.EVENT_TOUCHCANCEL, this.OnAnalogContainerPointerUp, this);
    }
    
    this.analogBaseEntity.setLocalPosition(this.defaultAnalogBasePosition.x, this.defaultAnalogBasePosition.y, this.defaultAnalogBasePosition.z);
    this.analogStickEntity.setLocalPosition(0, 0, 0);
    this.moveVector.set(0, 0);
};



MobileTouchController.prototype.OnDestroy = function() {    

};

