// LevelSelectScreen.js
var LevelSelectScreen = pc.createScript('levelSelectScreen');

if (!MPScene)
      var MPScene = function() {};
LevelSelectScreen.prototype = Object.create(MPScene.prototype);
LevelSelectScreen.prototype.constructor = LevelSelectScreen;

LevelSelectScreen.attributes.add('gameModeSelectEntity', { type: 'entity' });
LevelSelectScreen.attributes.add('levelSelectEntity', { type: 'entity' });
LevelSelectScreen.attributes.add('leaderboardEntity', { type: 'entity' });

LevelSelectScreen.State = Object.freeze({
    LevelSelect:            0,
    GameModeSelect:         1,
    Leaderboard:            2
    
});

LevelSelectScreen.prototype.initialize = function() {  
    MPScene.prototype.initialize.call(this);
    
    this.gameModeSelect = this.gameModeSelectEntity.script.gameModeSelect;
    this.levelSelect = this.levelSelectEntity.script.levelSelect;
    this.leaderboard = this.leaderboardEntity.script.levelSelectLeaderboard;
    this.justCompletedLevel = false;    
};

LevelSelectScreen.prototype.postInitialize = function() {  
    MPScene.prototype.postInitialize.call(this);

    AudioManager.Instance.Play("music_shared", "music_menu");
    
    this.LoadData(); 
};

LevelSelectScreen.prototype.OnSceneLoaded = function(data) {
    MPScene.prototype.OnSceneLoaded.call(this, data);

    this.justCompletedLevel = data && data.justCompletedLevel !== undefined ? data.justCompletedLevel : false;
    
    this.SetState(LevelSelectScreen.State.LevelSelect);
};

LevelSelectScreen.prototype.SetState = function(state) {
    
    var previousState = this.state;

    this.state = state;
    
    switch(this.state){
        case LevelSelectScreen.State.GameModeSelect:{
            this.OnEnterGameModeSelectState();
            break;
        }
        case LevelSelectScreen.State.LevelSelect:{
            this.OnEnterLevelSelectState();
            break;
        }
        case LevelSelectScreen.State.Leaderboard:{
            this.OnEnterLeaderboardState();
            break;
        }
    }
};

LevelSelectScreen.prototype.OnEnterGameModeSelectState = function() {
    this.gameModeSelect.Show(this.levelSelect.levelSelectOptions[this.levelSelect.levelIndex].id);
    this.levelSelect.Hide();
    this.leaderboard.Hide();
};


LevelSelectScreen.prototype.OnEnterLevelSelectState = function() {
    this.gameModeSelect.Hide();
    this.leaderboard.Hide();
    this.levelSelect.Show(this.justCompletedLevel);
    
    this.justCompletedLevel = false;
};

LevelSelectScreen.prototype.OnEnterLeaderboardState = function() {
    this.gameModeSelect.Hide();
    this.levelSelect.Hide();
    this.leaderboard.Show(this.levelSelect.levelSelectOptions[this.levelSelect.levelIndex].id);
};


LevelSelectScreen.prototype.StartGame = function() {
    this.SaveData();

    AudioManager.Instance.Stop("music_shared", "music_menu");
    SceneManager.Instance.SetState("GameScene");
};

LevelSelectScreen.prototype.LoadData = function() {
    this.levelsSaveData = SaveDataManager.Instance.GetGameData("levels");
    
    if(!this.levelsSaveData){
        this.levelsSaveData = {};
    }
    
    for(var i = 0; i<this.levelSelect.levelSelectOptions.length; i++){
        if(!this.levelsSaveData[this.levelSelect.levelSelectOptions[i].id]){
            this.levelsSaveData[this.levelSelect.levelSelectOptions[i].id] = {};
        }
    }
    
    this.levelSelect.LoadData();
};

LevelSelectScreen.prototype.SaveData = function() {
    this.levelSelect.SaveData();
    SaveDataManager.Instance.SetGameData("levels", this.levelsSaveData);
    SaveDataManager.Instance.SaveToStorage();
};

