GameModeSelect.attributes.add('endlessButtonEntity', { type: 'entity' });
GameModeSelect.attributes.add('leaderboardButtonEntity', { type: 'entity' });

// initialize code called once per entity
GameModeSelect.prototype.initialize = function() {
    this.scene = SceneManager.Instance.loadedSceneEntity.script.levelSelectScreen;
    
    this.containerEntity.enabled = false;

    this.overlay = this.overlayEntity.element;
    this.overlay.on("click", this.OnBackButtonPressed, this);
    this.overlayMaxOpacity = this.overlay.opacity;
    
    this.backButtonEntity.script.MPDOMButton.on("click", this.OnBackButtonPressed, this);
    this.campaignButtonEntity.script.MPDOMButton.on("click", this.OnCampaignButtonPressed, this);
    this.endlessButtonEntity.script.MPDOMButton.on("click", this.OnEndlessButtonPressed, this);
    this.leaderboardButtonEntity.script.MPDOMButton.on("click", this.OnLeaderboardButtonPressed, this);

    this.scaleTween = this.panelEntity.tween(this.panelEntity.getLocalScale());
    this.overlayOpacityTween = this.overlayEntity.tween(this.overlay);
};

// update code called every frame
GameModeSelect.prototype.update = function(dt) {
    
};

GameModeSelect.prototype.Show = function(levelID) {
    this.containerEntity.enabled = true;
    
    var levelSaveData = this.scene.levelsSaveData[levelID];
    
    var isEndlessUnlocked = levelSaveData.unlockedEndless;

    this.overlay.opacity = 0;
    this.overlayOpacityTween.stop();
    this.overlayOpacityTween = this.overlayEntity.tween(this.overlay);
    this.overlayOpacityTween.to({opacity: this.overlayMaxOpacity}, 0.25, pc.Linear);
    this.overlayOpacityTween.start();


    this.panelEntity.setLocalScale(0.75, 0.75, 0.75);
    this.scaleTween.stop();
    this.scaleTween = this.panelEntity.tween(this.panelEntity.getLocalScale());
    this.scaleTween.to({x: 1, y: 1, z: 1}, 0.5, pc.BackOut);
    this.scaleTween.start();

    AudioManager.Instance.Play("sfx_level_select", "ui_mode_appear");
    
    if(isEndlessUnlocked){
        this.endlessButtonEntity.script.MPDOMButton.Enable();
    }
    else{
        this.endlessButtonEntity.script.MPDOMButton.Enable();//Triggers tween
        this.endlessButtonEntity.script.MPDOMButton.Disable();
    }

    this.leaderboardButtonEntity.script.MPDOMButton.Enable();
    
};

GameModeSelect.prototype.Hide = function() {
    this.containerEntity.enabled = false;
};

GameModeSelect.prototype.OnBackButtonPressed = function() {
    this.scene.SetState(LevelSelectScreen.State.LevelSelect);
};



GameModeSelect.prototype.OnCampaignButtonPressed = function() {
    GameScene.levelType = "campaign";
    this.scene.StartGame();
};

GameModeSelect.prototype.OnEndlessButtonPressed = function() {
    GameScene.levelType = "endless";
    this.scene.StartGame();
};

GameModeSelect.prototype.OnLeaderboardButtonPressed = function() {
    this.scene.SetState(LevelSelectScreen.State.Leaderboard);
};

// LevelSelect.js
var LevelSelect = pc.createScript('levelSelect');

LevelSelect.attributes.add('containerEntity', { type: 'entity' });
LevelSelect.attributes.add("backButtonEntity", { type: 'entity' });
LevelSelect.attributes.add('previousButtonEntity', { type: 'entity' });
LevelSelect.attributes.add('nextButtonEntity', { type: 'entity' });
LevelSelect.attributes.add("gameDataAsset", { type: 'asset', assetType: 'json' });
LevelSelect.attributes.add('levelSelectCameraEntity', { type: 'entity' });
LevelSelect.attributes.add('levelSelectOptionsEntity', { type: 'entity' });
LevelSelect.attributes.add('playButtonEntity', { type: 'entity' });


// initialize code called once per entity
LevelSelect.prototype.initialize = function() {
    this.scene = SceneManager.Instance.loadedSceneEntity.script.levelSelectScreen;
    
    this.backButtonEntity.script.MPDOMButton.on("click", this.OnBackButtonPressed, this);
    this.previousButtonEntity.script.MPDOMButton.on("click", this.OnPreviousButtonPressed, this);
    this.nextButtonEntity.script.MPDOMButton.on("click", this.OnNextButtonPressed, this);
    
    
    this.levelIndex = 0;
    
    this.levelSelectOptions = [];
    
    for(var i = 0; i<this.levelSelectOptionsEntity.children.length; i++){
        this.levelSelectOptions.push(this.levelSelectOptionsEntity.children[i].script.levelSelectOption);
    }
    
    
    this.lerpTime = 1;
    
    this.defaultCameraPositionZ = this.levelSelectCameraEntity.getPosition().z;
    this.zoomOutDistance = 2.5;
    
    this.containerEntity.enabled = false;
    
    this.levelsSaveData = null;
    
    this.cameraPanTween = this.levelSelectCameraEntity.tween(this.levelSelectCameraEntity.getLocalPosition());
    this.cameraZoomOutTween = this.levelSelectCameraEntity.tween(this.levelSelectCameraEntity.getLocalPosition());
    this.cameraZoomInTween = this.levelSelectCameraEntity.tween(this.levelSelectCameraEntity.getLocalPosition());

    this.playButton = this.playButtonEntity.script.MPDOMButton;
    this.playButton.on("click", this.OnPlayButtonPressed, this);
};

LevelSelect.prototype.postInitialize = function() {

};

// update code called every frame
LevelSelect.prototype.update = function(dt) {

};

LevelSelect.prototype.Show = function(justCompletedLevel) {
    this.levelSelectOptionsEntity.layoutgroup.reflow();
    this.containerEntity.enabled = true;
    this.MoveCameraToLevelSelectOption(this.levelSelectOptions[this.levelIndex], true);
    this.CheckButtonsToEnable();
    
    if(justCompletedLevel && this.levelIndex < this.levelSelectOptions.length - 1){
        AudioManager.Instance.Play("sfx_level_select", "ui_button_right");
        this.OnNextButtonPressed();
    }
};

LevelSelect.prototype.Hide = function() {
    this.containerEntity.enabled = false;
};

LevelSelect.prototype.OnBackButtonPressed = function() {
    SceneManager.Instance.SetState("MainMenu");    
};


LevelSelect.prototype.OnPreviousButtonPressed = function() {
    this.SetLevelIndex(this.levelIndex - 1);
};

LevelSelect.prototype.OnNextButtonPressed = function() {
    this.SetLevelIndex(this.levelIndex + 1);
};


LevelSelect.prototype.SetLevelIndex = function(index) {

    this.levelSelectOptions[this.levelIndex].Disable();
    
    this.levelIndex = index;
    if(this.levelIndex > this.levelSelectOptions.length - 1){
        this.levelIndex = 0;
    }
    else if(this.levelIndex < 0){
        this.levelIndex = this.levelSelectOptions.length - 1;
    }
    
    this.MoveCameraToLevelSelectOption(this.levelSelectOptions[this.levelIndex]);
};




LevelSelect.prototype.MoveCameraToLevelSelectOption = function(levelSelectOption, snap) {
    this.playButtonEntity.enabled = false;
    this.previousButtonEntity.enabled = false;
    this.nextButtonEntity.enabled = false;
    
    this.cameraPanTween.stop();
    this.cameraZoomOutTween.stop();
    this.cameraZoomInTween.stop();
    
    
    var targetEntity = levelSelectOption.entity;
    var targetEntityPosition = targetEntity.getPosition();
    targetEntityPosition.y -= 0.75;
    var targetEntityAngles = targetEntity.getEulerAngles();

    if(snap){
        
        this.levelSelectCameraEntity.setLocalPosition(targetEntityPosition.x, targetEntityPosition.y, this.defaultCameraPositionZ);
    }
    else{
        var lerpEaseType = pc.SineInOut;
        this.cameraPanTween = this.levelSelectCameraEntity.tween(this.levelSelectCameraEntity.getLocalPosition());
        this.cameraPanTween.to({x: targetEntityPosition.x, y: targetEntityPosition.y}, this.lerpTime, lerpEaseType);
        this.cameraPanTween.on("complete", this.OnCameraPanTweenComplete, this);
        this.cameraPanTween.start();

        this.cameraZoomOutTween = this.levelSelectCameraEntity.tween(this.levelSelectCameraEntity.getLocalPosition());
        this.cameraZoomOutTween.to({z: this.defaultCameraPositionZ + this.zoomOutDistance}, this.lerpTime * 0.5, pc.SineOut);
        this.cameraZoomOutTween.on("complete", this.OnCameraZoomOutTweenComplete, this);
        this.cameraZoomOutTween.start();
    }
};

LevelSelect.prototype.OnCameraZoomOutTweenComplete = function() {
    this.cameraZoomInTween = this.levelSelectCameraEntity.tween(this.levelSelectCameraEntity.getLocalPosition());
    this.cameraZoomInTween.to({z: this.defaultCameraPositionZ}, this.lerpTime * 0.5, pc.SineIn);
    this.cameraZoomInTween.start();
};


LevelSelect.prototype.OnCameraPanTweenComplete = function() {
    this.CheckButtonsToEnable();
};


LevelSelect.prototype.CheckButtonsToEnable = function() {
    this.previousButtonEntity.enabled = this.levelIndex > 0;

    this.levelSelectOptions[this.levelIndex].Enable();
    
    var levelSelectData = this.scene.levelsSaveData[this.levelSelectOptions[this.levelIndex].id];

    this.nextButtonEntity.enabled = levelSelectData && levelSelectData.unlockedEndless && this.levelIndex < this.levelSelectOptions.length - 1;

    this.playButtonEntity.enabled = true;
    this.playButton.Enable();
};

LevelSelect.prototype.OnPlayButtonPressed = function() {
    GameScene.levelID = this.levelSelectOptions[this.levelIndex].id;

    this.playButton.Disable();
    
    this.scene.SetState(LevelSelectScreen.State.GameModeSelect);
};


LevelSelect.prototype.LoadData = function() {
    var levelSelectData = SaveDataManager.Instance.GetGameData("levelSelect");
    this.levelIndex = levelSelectData && levelSelectData.levelIndex !== undefined ? levelSelectData.levelIndex : 0;
};

LevelSelect.prototype.SaveData = function() {
    SaveDataManager.Instance.SetGameData("levelSelect", { levelIndex: this.levelIndex });
    SaveDataManager.Instance.SaveToStorage();
};

