// TunnelGateObstacle.js
var TunnelGateObstacle = pc.createScript('tunnelGateObstacle');

if (!TunnelObstacle)
      var TunnelObstacle = function() {};
TunnelGateObstacle.prototype = Object.create(TunnelObstacle.prototype);
TunnelGateObstacle.prototype.constructor = TunnelGateObstacle;

TunnelGateObstacle.State = Object.freeze({
    Open:              0,
    Closing:           1,
    Closed:            2,
    Opening:           3
});

TunnelGateObstacle.attributes.add("bodyEntities", { type: 'entity', array: true });
TunnelGateObstacle.attributes.add("modelEntities", { type: 'entity', array: true });
TunnelGateObstacle.attributes.add("hasLaser", { type: 'boolean' });
TunnelGateObstacle.attributes.add("hasGlass", { type: 'boolean' });
TunnelGateObstacle.attributes.add("leftGateEntity", { type: 'entity' });
TunnelGateObstacle.attributes.add("rightGateEntity", { type: 'entity' });
TunnelGateObstacle.attributes.add("closedGap", { type: 'number', default: 0 });
TunnelGateObstacle.attributes.add("openGap", { type: 'number', default: 3 });
TunnelGateObstacle.attributes.add("openDistance", { type: 'number', default: 10 });
TunnelGateObstacle.attributes.add("closingDistance", { type: 'number', default: 10 });
TunnelGateObstacle.attributes.add("closedDistance", { type: 'number', default: 10 });
TunnelGateObstacle.attributes.add("openingDistance", { type: 'number', default: 10 });

// initialize code called once per entity
TunnelGateObstacle.prototype.initialize = function() {
    TunnelObstacle.prototype.initialize.call(this);
    
    this.statePosition = 0;
    this.state = null;
};

// update code called every frame
TunnelGateObstacle.prototype.update = function(dt) {
    if(GameManager.Instance.IsPaused()) return;
    TunnelObstacle.prototype.update.call(this, dt);
};

TunnelGateObstacle.prototype.Spawn = function(tunnelManager, obstacleData) {
    TunnelObstacle.prototype.Spawn.call(this, tunnelManager, obstacleData);
    
    if(obstacleData.closedGap != undefined){
        this.closedGap = obstacleData.closedGap;
    }
    if(obstacleData.openGap != undefined){
        this.openGap = obstacleData.openGap;
    }
    if(obstacleData.openDistance != undefined){
        this.openDistance = obstacleData.openDistance;
    }
    if(obstacleData.closingDistance != undefined){
        this.closingDistance = obstacleData.closingDistance;
    }
    if(obstacleData.closedDistance != undefined){
        this.closedDistance = obstacleData.closedDistance;
    }
    if(obstacleData.openingDistance != undefined){
        this.openingDistance = obstacleData.openingDistance;
    }

    
    //Work out where to start so that when the obstacle reaches the player, it is halfway through the open state
    var startStatePosition = (Math.abs(tunnelManager.distanceToMidCollision) + (this.openDistance * 0.5)) % (this.openDistance + this.closingDistance + this.closedDistance + this.openingDistance);
    var state = null;
    this.statePosition = 0;
    

    //startStatePosition += this.openDistance * 0.5;
    
    if(startStatePosition <= this.openDistance){
        state = TunnelGateObstacle.State.Open;
        this.statePosition = startStatePosition;
    }
    else if(startStatePosition <= (this.openDistance + this.openingDistance)){
        state = TunnelGateObstacle.State.Opening;
        this.statePosition = startStatePosition - (this.openDistance);
    }
    else if(startStatePosition <= (this.openDistance + this.openingDistance + this.closedDistance)){
        state = TunnelGateObstacle.State.Closed;
        this.statePosition = startStatePosition - (this.openDistance + this.openingDistance);
    }
    else{
        state = TunnelGateObstacle.State.Closing;
        this.statePosition = startStatePosition - (this.openDistance + this.openingDistance + this.closedDistance);
    }


    this.SetState(state);
};

TunnelGateObstacle.prototype.SetState = function(state) {
    this.state = state;
    
    switch(this.state){
        case TunnelGateObstacle.State.Open:{
            this.OnEnterOpenState();
            break;
        }
        case TunnelGateObstacle.State.Closing:{
            this.OnEnterClosingState();
            break;
        }
        case TunnelGateObstacle.State.Closed:{
            this.OnEnterClosedState();
            break;
        }
        case TunnelGateObstacle.State.Opening:{
            this.OnEnterOpeningState();
            break;
        }
    }
};

TunnelGateObstacle.prototype.OnEnterOpenState = function() {
    //console.warn("Enter Open State")
    if(this.statePosition < 0){
        this.statePosition += this.openDistance;
    }

    var dist = Math.abs(this.scene.player.entity.getPosition().z - this.entity.getPosition().z);

    var volume = this.GetVolume();

    if(volume > 0){
        AudioManager.Instance.Play("sfx_game", "game_gate_open", {volume: volume});
    }

    
    
    var leftGateLocalPosition = this.leftGateEntity.getLocalPosition();
    this.leftGateEntity.setLocalPosition(-this.openGap, leftGateLocalPosition.y, leftGateLocalPosition.z);
    
    var rightGateLocalPosition = this.rightGateEntity.getLocalPosition();
    this.rightGateEntity.setLocalPosition(this.openGap, rightGateLocalPosition.y, rightGateLocalPosition.z);
};

TunnelGateObstacle.prototype.OnEnterClosingState = function() {
    //console.warn("Enter Closing State")
    if(this.statePosition < 0){
        this.statePosition += this.closingDistance;
    }
    
    var leftGateLocalPosition = this.leftGateEntity.getLocalPosition();
    this.leftGateEntity.setLocalPosition(-this.openGap, leftGateLocalPosition.y, leftGateLocalPosition.z);
    
    var rightGateLocalPosition = this.rightGateEntity.getLocalPosition();
    this.rightGateEntity.setLocalPosition(this.openGap, rightGateLocalPosition.y, rightGateLocalPosition.z);
};

TunnelGateObstacle.prototype.OnEnterClosedState = function() {
    //console.warn("Enter Closed State")
    if(this.statePosition < 0){
        this.statePosition += this.closedDistance;
    }

    var volume = this.GetVolume();

    if(volume > 0){
        AudioManager.Instance.Play("sfx_game", "game_gate_close", {volume: volume});
    }
    
    var leftGateLocalPosition = this.leftGateEntity.getLocalPosition();
    this.leftGateEntity.setLocalPosition(-this.closedGap, leftGateLocalPosition.y, leftGateLocalPosition.z);
    
    var rightGateLocalPosition = this.rightGateEntity.getLocalPosition();
    this.rightGateEntity.setLocalPosition(this.closedGap, rightGateLocalPosition.y, rightGateLocalPosition.z);
};

TunnelGateObstacle.prototype.OnEnterOpeningState = function() {
    //console.warn("Enter Opening State")
    if(this.statePosition < 0){
        this.statePosition += this.openingDistance;
    }
    
    var leftGateLocalPosition = this.leftGateEntity.getLocalPosition();
    this.leftGateEntity.setLocalPosition(-this.closedGap, leftGateLocalPosition.y, leftGateLocalPosition.z);
    
    var rightGateLocalPosition = this.rightGateEntity.getLocalPosition();
    this.rightGateEntity.setLocalPosition(this.closedGap, rightGateLocalPosition.y, rightGateLocalPosition.z);
};

TunnelGateObstacle.prototype.GetVolume = function() {

    var dist = Math.abs(this.scene.player.entity.getPosition().z - this.entity.getPosition().z);
    var maxDistance = 45;

    if(dist < maxDistance){
        return 1 - (dist / maxDistance);
    }

    return 0;

};

TunnelGateObstacle.prototype.Move = function(amount) {
    TunnelObstacle.prototype.Move.call(this, amount);  
    
    if(this.hasPassedPlayer) return;
    
    
    if(this.statePosition < 0){
        this.TransitionToNextState();
    }
    
    this.statePosition -= amount;

    if(this.statePosition < 0){
        this.TransitionToNextState();
    }
    else{
        switch(this.state){
            case TunnelGateObstacle.State.Closing:{
                this.UpdateGatePositionClosingState();
                break;
            }
            case TunnelGateObstacle.State.Opening:{
                this.UpdateGatePositionOpeningState();
                break;
            }
        }
    }
};

TunnelGateObstacle.prototype.UpdateGatePositionClosingState = function() {   
    var closingPercent = pc.math.clamp(1- (this.statePosition / this.closingDistance), 0, 1);
    
    var gateX = pc.math.lerp(this.openGap, this.closedGap, pc.QuadraticIn(closingPercent));
    
    var leftGateLocalPosition = this.leftGateEntity.getLocalPosition();
    this.leftGateEntity.setLocalPosition(-gateX, leftGateLocalPosition.y, leftGateLocalPosition.z);
    
    var rightGateLocalPosition = this.rightGateEntity.getLocalPosition();
    this.rightGateEntity.setLocalPosition(gateX, rightGateLocalPosition.y, rightGateLocalPosition.z);
};

TunnelGateObstacle.prototype.UpdateGatePositionOpeningState = function() {   
    var openingPercent = pc.math.clamp(1- (this.statePosition / this.openingDistance), 0, 1);
    
    var gateX = pc.math.lerp(this.closedGap, this.openGap, pc.QuadraticOut(openingPercent));
    
    var leftGateLocalPosition = this.leftGateEntity.getLocalPosition();
    this.leftGateEntity.setLocalPosition(-gateX, leftGateLocalPosition.y, leftGateLocalPosition.z);
    
    var rightGateLocalPosition = this.rightGateEntity.getLocalPosition();
    this.rightGateEntity.setLocalPosition(gateX, rightGateLocalPosition.y, rightGateLocalPosition.z);
};

TunnelGateObstacle.prototype.OnPassedPlayer = function() {
    TunnelObstacle.prototype.OnPassedPlayer.call(this);

    
};


TunnelGateObstacle.prototype.TransitionToNextState = function() {   
    
    switch(this.state){
        case TunnelGateObstacle.State.Open:{
            this.SetState(TunnelGateObstacle.State.Closing);
            break;
        }
        case TunnelGateObstacle.State.Closing:{
            this.SetState(TunnelGateObstacle.State.Closed);
            break;
        }
        case TunnelGateObstacle.State.Closed:{
            this.SetState(TunnelGateObstacle.State.Opening);
            break;
        }
        case TunnelGateObstacle.State.Opening:{
            this.SetState(TunnelGateObstacle.State.Open);
            break;
        }
    }
};



// TunnelShader.js
var TunnelShader = pc.createScript('tunnelShader');

if (!WarpShader)
      var WarpShader = function() {};
TunnelShader.prototype = Object.create(WarpShader.prototype);
TunnelShader.prototype.constructor = TunnelShader;

TunnelShader.attributes.add('transformVS', { type: 'asset', assetType: 'shader' });
TunnelShader.attributes.add('diffusePS', { type: 'asset', assetType: 'shader' });
TunnelShader.attributes.add('emissionPS', { type: 'asset', assetType: 'shader' });

// initialize code called once per entity
TunnelShader.prototype.initialize = function() {
    WarpShader.prototype.initialize.call(this);
    
    this.scene = SceneManager.Instance.loadedSceneEntity.script.gameScene;
    
    this.tunnelTextureCount = 4;
    this.textureUVChange = 1;
    this.uvScrollSpeedScalar = 0.05;
    this.materialEmissiveScalar = 1;
    
    this.fadeEmissiveTween = this.entity.tween(this);
};

TunnelShader.prototype.postInitialize = function() {    
    WarpShader.prototype.postInitialize.call(this);
    
    this.levelDiffuseTextures = [];
    this.levelEmissiveTextures = [];

    for(var i = 0; i<this.scene.levelData.tunnelTextures.length; i++){
        this.levelDiffuseTextures.push(this.app.assets.find(this.scene.levelData.tunnelTextures[i] + '.png', "texture").resource);
        
        var emissiveTextureAsset = this.app.assets.find(this.scene.levelData.tunnelTextures[i] + "_emissive.png", "texture");
        this.levelEmissiveTextures.push(emissiveTextureAsset ? emissiveTextureAsset.resource : this.app.assets.find("default_emissive.png", "texture").resource);
    }
    
    this.textureChangeIndex = this.tunnelTextureCount;
    
    this.levelTexturesLength = this.levelDiffuseTextures.length;
    
    // diffuseTex = meshInstance.material.diffuseMap;
    //     meshInstance.material = this.material;
    // console.log(this.material)
    // this.material.blendType = pc.BLEND_NORMAL;
    // this.material.opacity = 0.1;
    
    this.travelDistance = 0;
    this.textureIndexTravelDistance = 0;
    
    for(var i = 0; i<this.materials.length; i++){
        this.materials[i].chunks.diffusePS = this.diffusePS.resource;
        this.materials[i].chunks.emissivePS = this.emissionPS.resource;
        this.materials[i].setParameter('uTunnelTextureCount', this.tunnelTextureCount - 1);
        this.materials[i].setParameter('uTravelDistance', this.travelDistance);
        this.materials[i].setParameter('uEmissiveScalar', this.materialEmissiveScalar);
        this.materials[i].update();
    }
    
    
    
    this.UpdateTextures();
};

// update code called every frame
TunnelShader.prototype.update = function(dt) {
    WarpShader.prototype.update.call(this, dt);
};

TunnelShader.prototype.UpdateTextures = function() {
    for(var i = 0; i<this.tunnelTextureCount; i++){
        for(var j = 0; j<this.materials.length; j++){
            this.materials[j].setParameter('texture_diffuseMap' + i, this.levelDiffuseTextures[i % this.levelTexturesLength]);
            this.materials[j].setParameter('texture_emissiveMap' + i, this.levelEmissiveTextures[i % this.levelTexturesLength]);
            this.materials[j].update();
        }
        
    }
};

TunnelShader.prototype.Travel = function(amount) {
    amount *= this.uvScrollSpeedScalar;
    
    this.travelDistance += amount;
    this.textureIndexTravelDistance += amount;
    
    for(var i = 0; i<this.materials.length; i++){
        this.materials[i].setParameter('uTravelDistance', this.travelDistance);
    }
    
    
    if(this.textureIndexTravelDistance >= this.textureUVChange){
        this.textureIndexTravelDistance -= this.textureUVChange;
        
        
        var materialTextureIndex = this.textureChangeIndex % this.tunnelTextureCount;
        
        for(var i = 0; i<this.materials.length; i++){
            this.materials[i].setParameter('texture_diffuseMap' + materialTextureIndex, this.levelDiffuseTextures[this.textureChangeIndex % this.levelTexturesLength]);
            this.materials[i].setParameter('texture_emissiveMap' + materialTextureIndex, this.levelEmissiveTextures[this.textureChangeIndex % this.levelTexturesLength]);
        }
        this.textureChangeIndex++;
    }
};

TunnelShader.prototype.SetState = function(state) {
    switch(state){
        case GameScene.State.HitButton:{
            this.fadeEmissiveTween.stop();
            this.fadeEmissiveTween = this.entity.tween(this);
            this.fadeEmissiveTween.to({materialEmissiveScalar: 0.1}, 0.25, pc.Linear, 0.3);
            this.fadeEmissiveTween.on("update", this.OnFadeEmissiveTweenUpdate, this);
            this.fadeEmissiveTween.start();                 
            break;
        }
    }
    
};

TunnelShader.prototype.OnFadeEmissiveTweenUpdate = function() {
    for(var i = 0; i<this.materials.length; i++){
        this.materials[i].setParameter('uEmissiveScalar', this.materialEmissiveScalar);
        this.materials[i].update();
    }
};

// p2PhysicsEditorShape.js
var P2PhysicsEditorShape = pc.createScript('p2PhysicsEditorShape');

P2PhysicsEditorShape.attributes.add('physicsData', { type: 'asset', assetType: "json" });
P2PhysicsEditorShape.attributes.add('shapeKey', { type: 'string' });
P2PhysicsEditorShape.attributes.add('verticesScale', { type: 'number', default: 0.1 });
P2PhysicsEditorShape.attributes.add('angle', {
    type: 'number',
    default: 0,
    title: 'Angle',
    description: 'Body-local angle of the shape in degrees.',
    placeholder: 'degrees'
});
P2PhysicsEditorShape.attributes.add('position', {
    type: 'vec2',
    default: [ 0, 0 ],
    title: 'Position',
    description: 'Body-local position of the shape.',
    placeholder: [ 'X', 'Y' ]
});
P2PhysicsEditorShape.attributes.add('collisionGroup', {
    type: 'string',
    default: '00111111',
    title: 'Collision Group',
    description: 'Collision group that this shape belongs to (bit mask).'
});
P2PhysicsEditorShape.attributes.add('collisionMask', {
    type: 'string',
    default: '00111111',
    title: 'Collision Mask',
    description: 'Collision mask of this shape. See collisionGroup.'
});
P2PhysicsEditorShape.attributes.add('sensor', {
    type: 'boolean',
    default: false,
    title: 'Sensor',
    description: 'Set to true if you want this shape to be a sensor. A sensor does not generate contacts, but it still reports contact events. This is good if you want to know if a shape is overlapping another shape, without them generating contacts.'
});
P2PhysicsEditorShape.attributes.add('autoAttachDetachToBody', {
    type: 'boolean',
    default: true
});


// initialize code called once per entity
P2PhysicsEditorShape.prototype.initialize = function() {
    var scale = this.entity.getLocalScale();
    var shapeAngle = this.angle;   

    var axes = [
        p2.vec2.fromValues(1, 0),
        p2.vec2.fromValues(0, 1)
    ];
    
    this.shapes = [];
    
    var shapesData = this.physicsData.resource[this.shapeKey];
    
    for(var i = 0; i<shapesData.length; i++){
        var verts = [];
        
        var shapeVertices = shapesData[i].shape;

        
        for(var j = shapeVertices.length - 1; j>=0; j-=2){
            verts.push(p2.vec2.fromValues((shapeVertices[j - 1] * this.verticesScale) + this.position.x, -((shapeVertices[j] * this.verticesScale) + this.position.y)));
        }

        var shape = new p2.Convex({
            angle: this.angle,
            collisionGroup: parseInt(this.collisionGroup, 2),
            collisionMask: parseInt(this.collisionMask, 2),
            vertices: verts,
            axes: axes,
            position: [ 0, 0 ],
            sensor: this.sensor
        });
        
        this.shapes.push(shape);
    }
    
    // Handle changes to the box's properties
    this.on('attr:angle', function (value, prev) {
        for(var i = 0; i<this.shapes.length; i++){
            this.shapes[i].angle = value * Math.PI / 180;
        }
        
    });
    this.on('attr:collisionGroup', function (value, prev) {
        for(var i = 0; i<this.shapes.length; i++){
            this.shapes[i].collisionGroup = parseInt(value, 2);
        }
        
    });
    this.on('attr:collisionMask', function (value, prev) {
        for(var i = 0; i<this.shapes.length; i++){
            this.shapes[i].collisionMask = parseInt(value, 2);
        }
        
    });
    this.on('attr:sensor', function (value, prev) {
        for(var i = 0; i<this.shapes.length; i++){
            this.shapes[i].sensor = value;
        }
        
    });

    // If there's already a body created, simply add the shape to it
    if(this.autoAttachDetachToBody){
        this.AddToBody();
    }

    this.on("enable", function () {
        if(this.autoAttachDetachToBody){
            this.AddToBody();
        }
    });
    this.on("disable", function () {
        if(this.autoAttachDetachToBody){
            this.RemoveFromBody();
        }
    });
};

P2PhysicsEditorShape.prototype.postInitialize = function() {    

};

P2PhysicsEditorShape.prototype.AddToBody = function() {    
    if (this.entity.script.p2Body) {
        var body = this.entity.script.p2Body.body;
        if (body) {
            for(var i = 0; i<this.shapes.length; i++){
                body.addShape(this.shapes[i]);
            }
            
        }
    }
};

P2PhysicsEditorShape.prototype.RemoveFromBody = function() {    
    if (this.entity.script.p2Body) {
        var body = this.entity.script.p2Body.body;
        if (body) {
            for(var i = 0; i<this.shapes.length; i++){
                body.removeShape(this.shapes[i]);
            }
            
        }
    }
};

// update code called every frame
P2PhysicsEditorShape.prototype.update = function(dt) {
    
};

