// PlayerAnimation.js
var PlayerAnimation = pc.createScript('playerAnimation');

PlayerAnimation.attributes.add("playSpineEntity", { type: 'entity' });
PlayerAnimation.attributes.add("endSpineEntity", { type: 'entity' });

PlayerAnimation.Animation = Object.freeze({
    Idle: {spine: "play", trackIndex: 0, name: "idle", loop: true},
    Left: {spine: "play", trackIndex: 0, name: "left", loop: false},
    Right: {spine: "play", trackIndex: 0, name: "right", loop: false},
    Up: {spine: "play", trackIndex: 0, name: "up", loop: false},
    Down: {spine: "play", trackIndex: 0, name: "down", loop: false},
    Hit: {spine: "play", trackIndex: 0, name: "hit", loop: false},
    End: {spine: "play", trackIndex: 0, name: "end", loop: false},
    Lose: {spine: "end", trackIndex: 0, name: "lose", loop: false},
    Win: {spine: "end", trackIndex: 0, name: "win", loop: false}
});

// initialize code called once per entity
PlayerAnimation.prototype.initialize = function() {
    this.playSpine = this.playSpineEntity.script.spine;
    this.endSpine = this.endSpineEntity.script.spine;
    
    this.animationState = PlayerAnimation.Animation.Idle;
};

// update code called every frame
PlayerAnimation.prototype.update = function(dt) {
    
};

PlayerAnimation.prototype.PlayAnimation = function(animation) {
    if(this.animationState != animation){
        this.animationState = animation;

        var spineEntity = this[animation.spine + "SpineEntity"];
        var spine = this[animation.spine + "Spine"];

        if(this.playSpineEntity != spineEntity){
            this.playSpineEntity.enabled = false;
        }
        if(this.endSpineEntity != spineEntity){
            this.endSpineEntity.enabled = false;
        }
        spineEntity.enabled = true;
        spine.PlayAnimation(animation.trackIndex, animation.name, animation.loop);
    }
    
};

// TunnelObstacleShader.js
var TunnelObstacleShader = pc.createScript('tunnelObstacleShader');

if (!WarpShader)
      var WarpShader = function() {};
TunnelObstacleShader.prototype = Object.create(WarpShader.prototype);
TunnelObstacleShader.prototype.constructor = TunnelObstacleShader;

TunnelObstacleShader.attributes.add('transformVS', { type: 'asset', assetType: 'shader' });
TunnelObstacleShader.attributes.add('opacityPS', { type: 'asset', assetType: 'shader' });
TunnelObstacleShader.attributes.add('emissionPS', { type: 'asset', assetType: 'shader' });

// initialize code called once per entity
TunnelObstacleShader.prototype.initialize = function() {
    WarpShader.prototype.initialize.call(this);
    
    this.materialAlphaScalar = 1;
    this.materialEmissiveScalar = 1;
    this.laserOffsetX = 0;
    
    this.progress = 0;
    
    this.fadeAlphaTween = this.entity.tween(this);
    this.fadeEmissiveTween = this.entity.tween(this);
};

TunnelObstacleShader.prototype.postInitialize = function() {    
    WarpShader.prototype.postInitialize.call(this);
    
    this.materialAlphas = [];
    
    for(var i = 0; i<this.materials.length; i++){
        this.materialAlphas.push(this.materials[i].opacity);
        
        this.materials[i].blendType = pc.BLEND_NORMAL;
        this.materials[i].chunks.opacityPS = this.opacityPS.resource;
        this.materials[i].chunks.emissivePS = this.emissionPS.resource;
        this.materials[i].setParameter('uAlpha', this.materials[i].opacity);
        this.materials[i].setParameter('uOpacityMap', this.materials[i].opacityMap);
        this.materials[i].setParameter('uEmissiveScalar', this.materialEmissiveScalar);
        this.materials[i].update();
    }
    
    
};

// update code called every frame
TunnelObstacleShader.prototype.update = function(dt) {
    if(GameManager.Instance.IsPaused()) return;
    WarpShader.prototype.update.call(this, dt);
    
    
    if(this.materials.length == 2){
        this.laserOffsetX = pc.math.random(0, 1);
        this.materials[1].diffuseMapOffset.x = this.laserOffsetX;
        this.materials[1].emissiveMapOffset.x = this.laserOffsetX;
        this.materials[1].opacityMapOffset.x = this.laserOffsetX;
        this.materials[1].update();
    }
    
    // for(var i = 0; i<this.materials.length; i++){
    //     this.materials[i].setParameter('progress', this.progress * this.materialAlphaScalar);
    //     this.materials[i].update();
    // }
};

TunnelObstacleShader.prototype.Spawn = function() {
    this.fadeAlphaTween.stop();
    
    this.materialAlphaScalar = 1;
    this.progress = 0;

    for(var i = 0; i<this.materials.length; i++){
        this.materials[i].setParameter('uAlpha', this.materialAlphas[i]);
        this.materials[i].update();
    }
};

