TunnelObstacleShader.prototype.OnPassedPlayer = function() {
    
    // this.fadeAlphaTween.stop();
    // this.fadeAlphaTween = this.entity.tween(this);
    // this.fadeAlphaTween.to({materialAlphaScalar: 0}, 0.25, pc.Linear);
    // this.fadeAlphaTween.on("update", this.OnFadeAlphaTweenUpdate, this);
    // this.fadeAlphaTween.start();
    
};

TunnelObstacleShader.prototype.SetState = function(state) {
    switch(state){
        case GameScene.State.HitButton:{
            this.fadeEmissiveTween.stop();
            this.fadeEmissiveTween = this.entity.tween(this);
            this.fadeEmissiveTween.to({materialEmissiveScalar: 0.1}, 0.25, pc.Linear, 0.3);
            this.fadeEmissiveTween.on("update", this.OnFadeEmissiveTweenUpdate, this);
            this.fadeEmissiveTween.start();            
            break;
        }
    }
    
};


TunnelObstacleShader.prototype.OnFadeAlphaTweenUpdate = function() {
    for(var i = 0; i<this.materials.length; i++){
        this.materials[i].setParameter('uAlpha', this.materialAlphas[i] * this.materialAlphaScalar);
    }
};

TunnelObstacleShader.prototype.OnFadeEmissiveTweenUpdate = function() {
    for(var i = 0; i<this.materials.length; i++){

        this.materials[i].setParameter('uEmissiveScalar', this.materialEmissiveScalar);
        this.materials[i].update();
    }
};

// motionblur.js
//--------------- POST EFFECT DEFINITION ------------------------//
pc.extend(pc, function () {
    function createRenderTarget(gd) {
        // Create a 512x512x24-bit render target with a depth buffer
        var colorBuffer = new pc.Texture(gd, {
            width: gd.width,
            height: gd.height,
            format: pc.PIXELFORMAT_R8_G8_B8,
            autoMipmap: false
        });
        colorBuffer.minFilter = pc.FILTER_LINEAR;
        colorBuffer.magFilter = pc.FILTER_LINEAR;
        colorBuffer.addressU = pc.ADDRESS_CLAMP_TO_EDGE;
        colorBuffer.addressV = pc.ADDRESS_CLAMP_TO_EDGE;
        var renderTarget = new pc.RenderTarget(gd, colorBuffer, {
            depth: true
        });
        
        return renderTarget;
    }

    /**
     * @name pc.MotionBlur
     * @class Implements the motion blur effect.
     * @constructor Creates new instance of the post effect.
     * @extends pc.PostEffect
     * @param {pc.Device} graphicsDevice The graphics device of the application
     * @property {Number} amount Controls the intensity of the effect. Ranges from 0 to 1.
     */
    var MotionBlur = function (graphicsDevice) {
        var vertexShader = [
            "attribute vec2 aPosition;",
            "",
            "varying vec2 vUv0;",
            "",
            "void main(void)",
            "{",
            "    gl_Position = vec4(aPosition, 0.0, 1.0);",
            "    vUv0 = (aPosition.xy + 1.0) * 0.5;",
            "}"
        ].join("\n");
        
        this.blurShader = new pc.Shader(graphicsDevice, {
            attributes: {
                aPosition: pc.SEMANTIC_POSITION
            },
            vshader: vertexShader,
            fshader: [
                "precision " + graphicsDevice.precision + " float;",
                "",
                "uniform float uAmount;",
                "uniform sampler2D uCurrColorBuffer;",
                "uniform sampler2D uPrevColorBuffer;",
                "",
                "varying vec2 vUv0;",
                "",
                "void main() {",
                "    vec4 color1 = texture2D(uCurrColorBuffer, vUv0);",
                "    vec4 color2 = texture2D(uPrevColorBuffer, vUv0);",
                "",
                "    gl_FragColor = mix(color1, color2, uAmount);",
                "}"
            ].join("\n")
        });

        this.copyShader = new pc.Shader(graphicsDevice, {
            attributes: {
                aPosition: pc.SEMANTIC_POSITION
            },
            vshader: vertexShader,
            fshader: [
                "precision " + graphicsDevice.precision + " float;",
                "",
                "uniform sampler2D uColorBuffer;",
                "",
                "varying vec2 vUv0;",
                "",
                "void main() {",
                "    vec4 color = texture2D(uColorBuffer, vUv0);",
                "",
                "    gl_FragColor = color;",
                "}"
            ].join("\n")
        });

        this.tempTarget = createRenderTarget(graphicsDevice);

        // Uniforms
        this.amount = 1;
    };

    MotionBlur = pc.inherits(MotionBlur, pc.PostEffect);

    MotionBlur.prototype = pc.extend(MotionBlur.prototype, {
        render: function (inputTarget, outputTarget, rect) {
            var device = this.device;
            var scope = device.scope;

            if (!this.prevTarget) {
                this.prevTarget = createRenderTarget(device);
                scope.resolve("uColorBuffer").setValue(inputTarget.colorBuffer);
                pc.drawFullscreenQuad(device, this.tempTarget, this.vertexBuffer, this.copyShader, rect);
            } else {
                scope.resolve("uAmount").setValue(this.amount);
                scope.resolve("uCurrColorBuffer").setValue(inputTarget.colorBuffer);
                scope.resolve("uPrevColorBuffer").setValue(this.prevTarget.colorBuffer);
                pc.drawFullscreenQuad(device, this.tempTarget, this.vertexBuffer, this.blurShader, rect);
            }

            scope.resolve("uColorBuffer").setValue(this.tempTarget.colorBuffer);
            pc.drawFullscreenQuad(device, this.prevTarget, this.vertexBuffer, this.copyShader, rect);

            scope.resolve("uColorBuffer").setValue(this.tempTarget.colorBuffer);
            pc.drawFullscreenQuad(device, outputTarget, this.vertexBuffer, this.copyShader, rect);
        }
    });

    return {
        MotionBlur: MotionBlur
    };
}());


var MotionBlur = pc.createScript('motionBlur');

MotionBlur.attributes.add('amount', { type: 'number', default: 1, min: 0, max: 1, step: 0.01 });

MotionBlur.prototype.initialize = function () {
    this.effect = new pc.MotionBlur(this.app.graphicsDevice);
    this.effect.amount = this.amount;
    this.on('set', this.onAttributeChanged, this);
    
    this.on('attr', function(name, value, prev) {
        this.effect[name] = value;
    });    

    this.on("enable", function () {
        this.entity.camera.postEffects.addEffect(this.effect);
    });

    this.on("disable", function () {
        this.entity.camera.postEffects.removeEffect(this.effect);
    });
    
    this.entity.camera.renderTarget = this.effect.prevTarget;
    this.entity.camera.postEffects.addEffect(this.effect);
};


// CameraPostEffect.js
var CameraPostEffect = pc.createScript('cameraPostEffect');

CameraPostEffect.attributes.add('vertexShader', { type: 'asset', assetType: 'shader', title: 'Vertex Shader' });
CameraPostEffect.attributes.add('fragmentShader', { type: 'asset', assetType: 'shader', title: 'Fragment Shader' });

// initialize code called once per entity
CameraPostEffect.prototype.initialize = function() {
    var effect = new pc.ExamplePostEffect(this.app.graphicsDevice, this.vertexShader.resource, this.fragmentShader.resource);
    var queue = this.entity.camera.postEffects;
    queue.addEffect(effect);
    
    // when the script is enabled add our effect to the camera's postEffects queue
    this.on('enable', function () {
        queue.addEffect(effect, false); 
    });
    
    // when the script is disabled remove our effect from the camera's postEffects queue
    this.on('disable', function () {
        queue.removeEffect(effect); 
    });
};

// update code called every frame
CameraPostEffect.prototype.update = function(dt) {
    
};

pc.extend(pc, function () {
    // Constructor - Creates an instance of our post effect
    var ExamplePostEffect = function (graphicsDevice, vs, fs) {
        // this is the shader definition for our effect
        this.shader = new pc.Shader(graphicsDevice, {
            attributes: {
                aPosition: pc.SEMANTIC_POSITION
            },
            vshader: vs,
            fshader: fs
        });
    };

    // Our effect must derive from pc.PostEffect
    ExamplePostEffect = pc.inherits(ExamplePostEffect, pc.PostEffect);

    ExamplePostEffect.prototype = pc.extend(ExamplePostEffect.prototype, {
        // Every post effect must implement the render method which 
        // sets any parameters that the shader might require and 
        // also renders the effect on the screen
        render: function (inputTarget, outputTarget, rect) {
            var device = this.device;
            var scope = device.scope;

            // Set the input render target to the shader. This is the image rendered from our camera
            scope.resolve("uColorBuffer").setValue(inputTarget.colorBuffer);
            scope.resolve("iResolution").setValue([ScaleManager.Instance.dimensions.x, ScaleManager.Instance.dimensions.y]);
            // Draw a full screen quad on the output target. In this case the output target is the screen.
            // Drawing a full screen quad will run the shader that we defined above
            pc.drawFullscreenQuad(device, outputTarget, this.vertexBuffer, this.shader, rect);
        }
    });

    return {
        ExamplePostEffect: ExamplePostEffect
    };
}());

