// EndlessGameOverPopup.js
var EndlessGameOverPopup = pc.createScript('endlessGameOverPopup');

if (!GameOverPopup)
      var GameOverPopup = function() {};
EndlessGameOverPopup.prototype = Object.create(GameOverPopup.prototype);
EndlessGameOverPopup.prototype.constructor = EndlessGameOverPopup;

EndlessGameOverPopup.attributes.add('containerEntity', { type: 'entity' });
EndlessGameOverPopup.attributes.add('resultsEntity', { type: 'entity' });
EndlessGameOverPopup.attributes.add('retryButtonEntity', { type: 'entity' });
EndlessGameOverPopup.attributes.add('exitButtonEntity', { type: 'entity' });
EndlessGameOverPopup.attributes.add('scoreTextEntity', { type: 'entity' });
EndlessGameOverPopup.attributes.add('highscoreTextEntity', { type: 'entity' });
EndlessGameOverPopup.attributes.add('endlessGameOverInitialsSelectEntity', { type: 'entity' });
EndlessGameOverPopup.attributes.add('endlessGameOverLeaderboardEntity', { type: 'entity' });
EndlessGameOverPopup.attributes.add('newHighscorePopupEntity', { type: 'entity' });


EndlessGameOverPopup.State = Object.freeze({
    NewHighScore:   0,
    Results:        1,
    InitialsSelect:  2,
    Leaderboard:    3
});


// initialize code called once per entity
EndlessGameOverPopup.prototype.initialize = function() {
    GameOverPopup.prototype.initialize.call(this);

    this.newHighscorePopup = this.newHighscorePopupEntity.script.newHighscorePopup;
    this.endlessGameOverLeaderboard = this.endlessGameOverLeaderboardEntity.script.endlessGameOverLeaderboard;
    this.endlessGameOverInitialsSelect = this.endlessGameOverInitialsSelectEntity.script.endlessGameOverInitialsSelect;

    this.state = null;
    this.score = 0;
    this.highscore = 0;
};

// update code called every frame
EndlessGameOverPopup.prototype.update = function(dt) {
    GameOverPopup.prototype.update.call(this, dt);

};

EndlessGameOverPopup.prototype.Show = function(config) {
    GameOverPopup.prototype.Show.call(this);

    var roundedScore = Math.round(config.score);
    this.scoreTextEntity.element.key = "distance_score";
    this.scoreTextEntity.element.text = this.scoreTextEntity.element.text.replace("<num>", roundedScore);

    var roundedHighscore = Math.round(config.highscore);
    this.highscoreTextEntity.element.key = "distance_score";
    this.highscoreTextEntity.element.text = this.highscoreTextEntity.element.text.replace("<num>", roundedHighscore);

    this.score = roundedScore;
    this.highscore = roundedHighscore;

    if(this.score >= this.highscore){
        this.SetState(EndlessGameOverPopup.State.NewHighScore);
    }
    else{
        this.SetState(EndlessGameOverPopup.State.Results);
    }
};


EndlessGameOverPopup.prototype.SetState = function(state) {
    this.state = state;

    switch(state){
        case EndlessGameOverPopup.State.NewHighScore:{
            this.OnEnterNewHighScoreState();
            break;
        }

        case EndlessGameOverPopup.State.Results:{
            this.OnEnterResultsState();
            break;
        }
        case EndlessGameOverPopup.State.InitialsSelect:{
            this.OnEnterInitialsSelectState();
            break;
        }
        case EndlessGameOverPopup.State.Leaderboard:{
            this.OnEnterLeaderboardState();
            break;
        }
    }
};

EndlessGameOverPopup.prototype.OnEnterNewHighScoreState = function() {
    this.resultsEntity.enabled = false;
    this.endlessGameOverInitialsSelect.Hide();

    this.newHighscorePopup.Show(this.highscore);
};

EndlessGameOverPopup.prototype.OnEnterResultsState = function() {
    this.newHighscorePopup.Hide();

    this.endlessGameOverInitialsSelect.Hide();

    this.resultsEntity.enabled = true;
};

EndlessGameOverPopup.prototype.OnEnterInitialsSelectState = function() {
    this.newHighscorePopup.Hide();
    this.endlessGameOverInitialsSelect.Show();

};

EndlessGameOverPopup.prototype.OnEnterLeaderboardState = function() {
    this.newHighscorePopup.Hide();
    this.endlessGameOverInitialsSelect.Hide();

    this.endlessGameOverLeaderboard.Show(GameScene.levelID);

};


EndlessGameOverPopup.prototype.SubmitScore = function(onSuccess, onFailed) {
    var initials = SaveDataManager.Instance.GetGameData("initials");
    Hydra.UpsertUniqueObjectForOwner({ object_type_slug: GameScene.levelID + "-score", unique_key: "score", operations: [["set", "data.score", this.score], ["set", "data.initials", initials], ["set", "data.levelEndID", this.scene.levelStartID]] }, function(response) {
        this.endlessGameOverLeaderboard.scoreHydraObjectID = response.id;

        this.levelsSaveData = SaveDataManager.Instance.GetGameData("levels");
        
        if(this.levelsSaveData[GameScene.levelID]){
            this.levelsSaveData[GameScene.levelID].highscoreSubmitted = true;
        }
        SaveDataManager.Instance.SetGameData("levels", this.levelsSaveData);
        SaveDataManager.Instance.SaveToStorage();

        onSuccess.call(this, response);
    }.bind(this), onFailed);
};




