// posteffect-bloom.js
//--------------- POST EFFECT DEFINITION------------------------//
pc.extend(pc, function () {
    var SAMPLE_COUNT = 15;

    function computeGaussian(n, theta) {
        return ((1.0 / Math.sqrt(2 * Math.PI * theta)) * Math.exp(-(n * n) / (2 * theta * theta)));
    }

    function calculateBlurValues(sampleWeights, sampleOffsets, dx, dy, blurAmount) {
        // Look up how many samples our gaussian blur effect supports.

        // Create temporary arrays for computing our filter settings.
        // The first sample always has a zero offset.
        sampleWeights[0] = computeGaussian(0, blurAmount);
        sampleOffsets[0] = 0;
        sampleOffsets[1] = 0;

        // Maintain a sum of all the weighting values.
        var totalWeights = sampleWeights[0];

        // Add pairs of additional sample taps, positioned
        // along a line in both directions from the center.
        var i, len;
        for (i = 0, len = Math.floor(SAMPLE_COUNT / 2); i < len; i++) {
            // Store weights for the positive and negative taps.
            var weight = computeGaussian(i + 1, blurAmount);
            sampleWeights[i*2] = weight;
            sampleWeights[i*2+1] = weight;
            totalWeights += weight * 2;

            // To get the maximum amount of blurring from a limited number of
            // pixel shader samples, we take advantage of the bilinear filtering
            // hardware inside the texture fetch unit. If we position our texture
            // coordinates exactly halfway between two texels, the filtering unit
            // will average them for us, giving two samples for the price of one.
            // This allows us to step in units of two texels per sample, rather
            // than just one at a time. The 1.5 offset kicks things off by
            // positioning us nicely in between two texels.
            var sampleOffset = i * 2 + 1.5;

            // Store texture coordinate offsets for the positive and negative taps.
            sampleOffsets[i*4] = dx * sampleOffset;
            sampleOffsets[i*4+1] = dy * sampleOffset;
            sampleOffsets[i*4+2] = -dx * sampleOffset;
            sampleOffsets[i*4+3] = -dy * sampleOffset;
        }

        // Normalize the list of sample weightings, so they will always sum to one.
        for (i = 0, len = sampleWeights.length; i < len; i++) {
            sampleWeights[i] /= totalWeights;
        }
    }

    /**
     * @name pc.BloomEffect
     * @class Implements the BloomEffect post processing effect
     * @constructor Creates new instance of the post effect.
     * @extends pc.PostEffect
     * @param {pc.GraphicsDevice} graphicsDevice The graphics device of the application
     * @property {Number} bloomThreshold Only pixels brighter then this threshold will be processed. Ranges from 0 to 1
     * @property {Number} blurAmount Controls the amount of blurring.
     * @property {Number} bloomIntensity The intensity of the effect.
     */
    var BloomEffect = function (graphicsDevice) {
        // Shaders
        var attributes = {
            aPosition: pc.SEMANTIC_POSITION
        };

        var passThroughVert = [
            "attribute vec2 aPosition;",
            "",
            "varying vec2 vUv0;",
            "",
            "void main(void)",
            "{",
            "    gl_Position = vec4(aPosition, 0.0, 1.0);",
            "    vUv0 = (aPosition + 1.0) * 0.5;",
            "}"
        ].join("\n");

        // Pixel shader extracts the brighter areas of an image.
        // This is the first step in applying a bloom postprocess.
        var bloomExtractFrag = [
            "precision " + graphicsDevice.precision + " float;",
            "",
            "varying vec2 vUv0;",
            "",
            "uniform sampler2D uBaseTexture;",
            "uniform float uBloomThreshold;",
            "",
            "void main(void)",
            "{",
                 // Look up the original image color.
            "    vec4 color = texture2D(uBaseTexture, vUv0);",
            "",
                 // Adjust it to keep only values brighter than the specified threshold.
            "    gl_FragColor = clamp((color - uBloomThreshold) / (1.0 - uBloomThreshold), 0.0, 1.0);",
            "}"
        ].join("\n");

        // Pixel shader applies a one dimensional gaussian blur filter.
        // This is used twice by the bloom postprocess, first to
        // blur horizontally, and then again to blur vertically.
        var gaussianBlurFrag = [
            "precision " + graphicsDevice.precision + " float;",
            "",
            "#define SAMPLE_COUNT " + SAMPLE_COUNT,
            "",
            "varying vec2 vUv0;",
            "",
            "uniform sampler2D uBloomTexture;",
            "uniform vec2 uBlurOffsets[SAMPLE_COUNT];",
            "uniform float uBlurWeights[SAMPLE_COUNT];",
            "",
            "void main(void)",
            "{",
            "    vec4 color = vec4(0.0);",
                 // Combine a number of weighted image filter taps.
            "    for (int i = 0; i < SAMPLE_COUNT; i++)",
            "    {",
            "        color += texture2D(uBloomTexture, vUv0 + uBlurOffsets[i]) * uBlurWeights[i];",
            "    }",
            "",
            "    gl_FragColor = color;",
            "}"
        ].join("\n");

        // Pixel shader combines the bloom image with the original
        // scene, using tweakable intensity levels.
        // This is the final step in applying a bloom postprocess.
        var bloomCombineFrag = [
            "precision " + graphicsDevice.precision + " float;",
            "",
            "varying vec2 vUv0;",
            "",
            "uniform float uBloomEffectIntensity;",
            "uniform sampler2D uBaseTexture;",
            "uniform sampler2D uBloomTexture;",
            "",
            "void main(void)",
            "{",
                 // Look up the bloom and original base image colors.
            "    vec4 bloom = texture2D(uBloomTexture, vUv0) * uBloomEffectIntensity;",
            "    vec4 base = texture2D(uBaseTexture, vUv0);",
            "",
                 // Darken down the base image in areas where there is a lot of bloom,
                 // to prevent things looking excessively burned-out.
            "    base *= (1.0 - clamp(bloom, 0.0, 1.0));",
            "",
                 // Combine the two images.
            "    gl_FragColor = base + bloom;",
            "}"
        ].join("\n");

        this.extractShader = new pc.Shader(graphicsDevice, {
            attributes: attributes,
            vshader: passThroughVert,
            fshader: bloomExtractFrag
        });
        this.blurShader = new pc.Shader(graphicsDevice, {
            attributes: attributes,
            vshader: passThroughVert,
            fshader: gaussianBlurFrag
        });
        this.combineShader = new pc.Shader(graphicsDevice, {
            attributes: attributes,
            vshader: passThroughVert,
            fshader: bloomCombineFrag
        });

        // Render targets
        var width = graphicsDevice.width;
        var height = graphicsDevice.height;
        this.targets = [];
        for (var i = 0; i < 2; i++) {
            var colorBuffer = new pc.Texture(graphicsDevice, {
                format: pc.PIXELFORMAT_R8_G8_B8_A8,
                width: width >> 1,
                height: height >> 1
            });
            colorBuffer.minFilter = pc.FILTER_LINEAR;
            colorBuffer.magFilter = pc.FILTER_LINEAR;
            colorBuffer.addressU = pc.ADDRESS_CLAMP_TO_EDGE;
            colorBuffer.addressV = pc.ADDRESS_CLAMP_TO_EDGE;
            var target = new pc.RenderTarget(graphicsDevice, colorBuffer, { depth: false });

            this.targets.push(target);
        }

        // Effect defaults
        this.bloomThreshold = 0.25;
        this.blurAmount = 4;
        this.bloomIntensity = 1.25;

        // Uniforms
        this.sampleWeights = new Float32Array(SAMPLE_COUNT);
        this.sampleOffsets = new Float32Array(SAMPLE_COUNT * 2);
    }

    BloomEffect = pc.inherits(BloomEffect, pc.PostEffect);

    BloomEffect.prototype = pc.extend(BloomEffect.prototype, {
        render: function (inputTarget, outputTarget, rect) {
            var device = this.device;
            var scope = device.scope;

            // Pass 1: draw the scene into rendertarget 1, using a
            // shader that extracts only the brightest parts of the image.
            scope.resolve("uBloomThreshold").setValue(this.bloomThreshold);
            scope.resolve("uBaseTexture").setValue(inputTarget.colorBuffer);
            pc.drawFullscreenQuad(device, this.targets[0], this.vertexBuffer, this.extractShader);

            // Pass 2: draw from rendertarget 1 into rendertarget 2,
            // using a shader to apply a horizontal gaussian blur filter.
            calculateBlurValues(this.sampleWeights, this.sampleOffsets, 1.0 / this.targets[1].width, 0, this.blurAmount);
            scope.resolve("uBlurWeights[0]").setValue(this.sampleWeights);
            scope.resolve("uBlurOffsets[0]").setValue(this.sampleOffsets);
            scope.resolve("uBloomTexture").setValue(this.targets[0].colorBuffer);
            pc.drawFullscreenQuad(device, this.targets[1], this.vertexBuffer, this.blurShader);

            // Pass 3: draw from rendertarget 2 back into rendertarget 1,
            // using a shader to apply a vertical gaussian blur filter.
            calculateBlurValues(this.sampleWeights, this.sampleOffsets, 0, 1.0 / this.targets[0].height, this.blurAmount);
            scope.resolve("uBlurWeights[0]").setValue(this.sampleWeights);
            scope.resolve("uBlurOffsets[0]").setValue(this.sampleOffsets);
            scope.resolve("uBloomTexture").setValue(this.targets[1].colorBuffer);
            pc.drawFullscreenQuad(device, this.targets[0], this.vertexBuffer, this.blurShader);

            // Pass 4: draw both rendertarget 1 and the original scene
            // image back into the main backbuffer, using a shader that
            // combines them to produce the final bloomed result.
            scope.resolve("uBloomEffectIntensity").setValue(this.bloomIntensity);
            scope.resolve("uBloomTexture").setValue(this.targets[0].colorBuffer);
            scope.resolve("uBaseTexture").setValue(inputTarget.colorBuffer);
            pc.drawFullscreenQuad(device, outputTarget, this.vertexBuffer, this.combineShader, rect);
        }
    });

    return {
        BloomEffect: BloomEffect
    };
}());

//--------------- SCRIPT DEFINITION------------------------//
var Bloom = pc.createScript('bloom');

Bloom.attributes.add('bloomIntensity', {
    type: 'number',
    default: 1,
    min: 0,
    title: 'Intensity'
});

Bloom.attributes.add('bloomThreshold', {
    type: 'number',
    default: 0.25,
    min: 0,
    max: 1,
    precision: 2,
    title: 'Threshold'
});

Bloom.attributes.add('blurAmount', {
    type: 'number',
    default: 4,
    min: 1,
    'title': 'Blur amount'
});

Bloom.prototype.initialize = function() {
    this.effect = new pc.BloomEffect(this.app.graphicsDevice);

    this.effect.bloomThreshold = this.bloomThreshold;
    this.effect.blurAmount = this.blurAmount;
    this.effect.bloomIntensity = this.bloomIntensity;

    var queue = this.entity.camera.postEffects;

    queue.addEffect(this.effect);

    this.on('attr', function (name, value) {
        this.effect[name] = value;
    }, this);

    this.on('state', function (enabled) {
        if (enabled) {
            queue.addEffect(this.effect);
        } else {
            queue.removeEffect(this.effect);
        }
    });

    this.on('destroy', function () {
        queue.removeEffect(this.effect);
    });
};


// TunnelEndButton.js
var TunnelEndButton = pc.createScript('tunnelEndButton');

if (!TunnelObject)
      var TunnelObject = function() {};
TunnelEndButton.prototype = Object.create(TunnelObject.prototype);
TunnelEndButton.prototype.constructor = TunnelEndButton;

TunnelEndButton.attributes.add("bodyEntities", { type: 'entity', array: true });
TunnelEndButton.attributes.add("modelEntities", { type: 'entity', array: true });

// initialize code called once per entity
TunnelEndButton.prototype.initialize = function() {
    TunnelObject.prototype.initialize.call(this);
    
    
    for(var i = 0; i<this.modelEntities.length; i++){
        var tunnelObstacleShader = this.modelEntities[i].script.tunnelObstacleShader;
        this.tunnelObstacleShaders.push(tunnelObstacleShader);
        
        var render = this.modelEntities[i].model ? this.modelEntities[i].model : this.modelEntities[i].render;
        var diffuseMap = this.app.assets.find(this.scene.levelData.obstaclesPrimaryMaterialTexture+'.png', "texture");
        var emissiveMap = this.app.assets.find(this.scene.levelData.obstaclesPrimaryMaterialTexture+'_emissive.png', "texture");
        
        render.meshInstances[0].material.diffuseMap = diffuseMap.resource;
        render.meshInstances[0].material.emissiveMap = emissiveMap ? emissiveMap.resource : this.app.assets.find("default_emissive.png", "texture").resource;
        render.meshInstances[1].material.diffuseMap = render.meshInstances[0].material.diffuseMap;
        render.meshInstances[1].material.emissiveMap = render.meshInstances[1].material.emissiveMap;
        
        var tunnelDiffuseMap = this.app.assets.find(this.scene.levelData.tunnelTextures[0] + '.png', "texture");
        render.meshInstances[2].material.diffuseMap = tunnelDiffuseMap.resource;
        var tunnelEmissiveTextureAsset = this.app.assets.find(this.scene.levelData.tunnelTextures[0] + "_emissive.png", "texture");
        render.meshInstances[2].material.emissiveMap = tunnelEmissiveTextureAsset ? tunnelEmissiveTextureAsset.resource : this.app.assets.find("default_emissive.png", "texture").resource;
    }
};

TunnelEndButton.prototype.postInitialize = function() {
    TunnelObject.prototype.postInitialize.call(this);
    
};

TunnelEndButton.prototype.update = function(dt) {
    if(GameManager.Instance.IsPaused()) return;
    TunnelObject.prototype.update.call(this, dt);
    
};


TunnelEndButton.prototype.OnBeginContact = function(body, shape, shapeB, contactEquations) {
    TunnelObject.prototype.OnBeginContact.call(this, body, shape, shapeB, contactEquations);
    if(body.player){
        this.modelEntities[0].animation.play("button.glb");
        AudioManager.Instance.Play("sfx_game", "game_complete_panel");
        this.scene.player.OnHitEndButton();
    }
    
};



// ScrollingBackground.js
var ScrollingBackground = pc.createScript('scrollingBackground');

ScrollingBackground.posX = 0;
ScrollingBackground.posY = 0;

// initialize code called once per entity
ScrollingBackground.prototype.initialize = function() {
    this.on("state", this.SnapToPosition, this);
    this.SnapToPosition();
};

// update code called every frame
ScrollingBackground.prototype.update = function(dt) {
    this.entity.translateLocal(0, -50 * dt, 0);
    
    ScrollingBackground.posX = this.entity.getLocalPosition().x;
    ScrollingBackground.posY = this.entity.getLocalPosition().y;
    
    if(ScrollingBackground.posY < -306){
        this.entity.translateLocal(0, 306, 0);
        ScrollingBackground.posX = this.entity.getLocalPosition().x;
        ScrollingBackground.posY = this.entity.getLocalPosition().y;
    }
};

ScrollingBackground.prototype.SnapToPosition = function(dt) {
    this.entity.setLocalPosition(ScrollingBackground.posX, ScrollingBackground.posY, 0);
};

// MPDOMButtonOnEnableTween.js
var MPDOMOnEnableTween = pc.createScript('MPDOMOnEnableTween');

MPDOMOnEnableTween.attributes.add("attribute", { type: 'string',
    enum: [
        { 'scale': "scale" }
    ],
    default: 'scale'
});
MPDOMOnEnableTween.attributes.add("attributeStartValue", { type: 'number',  default: 0 });
MPDOMOnEnableTween.attributes.add("attributeEndValue", { type: 'number',  default: 1 });
MPDOMOnEnableTween.attributes.add("duration", { type: 'number',  default: 0.5 });
MPDOMOnEnableTween.attributes.add("easeType", { type: 'string',  default: "Linear" });
MPDOMOnEnableTween.attributes.add("delay", { type: 'number',  default: 0 });

// initialize code called once per entity
MPDOMOnEnableTween.prototype.initialize = function() {
    this.MPDOMButton = this.entity.MPDOMButton;

    this.MPDOMButton.on("enable", this.OnEnable, this);
    
    this.onEnableTween = this.entity.tween(this);
};

// update code called every frame
MPDOMOnEnableTween.prototype.update = function(dt) {

};

MPDOMOnEnableTween.prototype.OnEnable = function() {
    this.onEnableTween.stop();
    
    var target = null;
    
    switch(this.attribute){
        case "scale":{
            this.entity.setLocalScale(this.attributeStartValue, this.attributeStartValue, this.attributeStartValue);
            this.onEnableTween = this.entity.tween(this.entity.getLocalScale());
            target = {x: this.attributeEndValue, y: this.attributeEndValue, z: this.attributeEndValue};
            break;
        }
    }
    
    if(this.onEnableTween){
        this.onEnableTween.to(target, this.duration, pc[this.easeType], this.delay);
        this.onEnableTween.on("complete", this.OnTweenComplete, this);
        this.onEnableTween.pausable = false;
        this.onEnableTween.start();
    }
    
};

MPDOMOnEnableTween.prototype.OnTweenComplete = function() {
    this.MPDOMButton.PositionElement();

    this.fire("complete");
};




