// initialize code called once per entity
UnlockedNextLevelPopup.prototype.initialize = function() {
    this.containerEntity.enabled = false;

    this.hideTime = 3.5;
    this.hideTimer = 0;
};

// update code called every frame
UnlockedNextLevelPopup.prototype.update = function(dt) {
    if(this.hideTimer > 0){
        this.hideTimer -= dt;

        if(this.hideTimer <= 0){
            this.Hide();
        }
    }
};

UnlockedNextLevelPopup.prototype.Show = function(nextLevelID) {
    this.containerEntity.enabled = true;

    this.containerEntity.setLocalScale(0.75, 0.75, 0.75);
    var scaleTween = this.containerEntity.tween(this.containerEntity.getLocalScale());
    scaleTween.to({x: 1, y: 1, z: 1}, 0.5, pc.BackOut);
    scaleTween.pausable = false;
    scaleTween.start();

    if(nextLevelID){
        var nextLevelImageSprite = this.app.assets.find('ui_level_unlock_' + nextLevelID, "sprite");

        this.nextLevelImageEntity.element.spriteAsset = nextLevelImageSprite;
    }
    

    this.hideTimer = this.hideTime;
};

UnlockedNextLevelPopup.prototype.Hide = function() {
    this.containerEntity.enabled = false;
    this.fire("hide");
};

// UnlockedEndlessPopup.js
var UnlockedEndlessPopup = pc.createScript('unlockedEndlessPopup');

UnlockedEndlessPopup.attributes.add('containerEntity', { type: 'entity' });
UnlockedEndlessPopup.attributes.add('endlessTextEntity', { type: 'entity' });

// initialize code called once per entity
UnlockedEndlessPopup.prototype.initialize = function() {
    this.containerEntity.enabled = false;

    this.hideTime = 2;
    this.hideTimer = 0;

    this.endlessText = this.endlessTextEntity.element;
    
    this.endlessTextOutlineFullOpacityColor = new pc.Color(this.endlessText.outlineColor.r, this.endlessText.outlineColor.b, this.endlessText.outlineColor.g, this.endlessText.outlineColor.a);
    this.endlessTextOutlineColor = new pc.Color(this.endlessTextOutlineFullOpacityColor.r, this.endlessTextOutlineFullOpacityColor.g, this.endlessTextOutlineFullOpacityColor.b, this.endlessTextOutlineFullOpacityColor.a);
    this.endlessTextOutlineNoOpacityColor = new pc.Color(this.endlessText.outlineColor.r, this.endlessText.outlineColor.b, this.endlessText.outlineColor.g, 0);
    this.fadeEndlessTextOutlineTween = this.entity.tween(this.endlessTextOutlineColor);
};

// update code called every frame
UnlockedEndlessPopup.prototype.update = function(dt) {
    if(this.hideTimer > 0){
        this.hideTimer -= dt;

        if(this.hideTimer <= 0){
            this.Hide();
        }
    }

    if(this.fadeEndlessTextOutlineTween.playing){
        this.endlessText.outlineColor = this.endlessTextOutlineColor;
    }
};

UnlockedEndlessPopup.prototype.Show = function() {
    this.containerEntity.enabled = true;

    this.containerEntity.setLocalScale(0.75, 0.75, 0.75);
    var scaleTween = this.containerEntity.tween(this.containerEntity.getLocalScale());
    scaleTween.to({x: 1, y: 1, z: 1}, 0.5, pc.BackOut);
    scaleTween.pausable = false;
    scaleTween.start();

    var opacityTween = this.endlessTextEntity.tween(this.endlessTextEntity.element);
    opacityTween.to({opacity: 0}, 0.5, pc.Linear, 1);
    opacityTween.pausable = false;
    opacityTween.start();

    this.fadeEndlessTextOutlineTween = this.endlessTextEntity.tween(this.endlessTextOutlineColor);
    this.fadeEndlessTextOutlineTween.to({a: this.endlessTextOutlineNoOpacityColor.a}, 0.5, pc.Linear, 1);
    this.fadeEndlessTextOutlineTween.pausable = false;
    this.fadeEndlessTextOutlineTween.start();

    AudioManager.Instance.Play("sfx_game_complete", "unlock_mode");


    this.hideTimer = this.hideTime;
};

UnlockedEndlessPopup.prototype.Hide = function() {
    this.containerEntity.enabled = false;
    this.fire("hide");
};

// RobotDestructionCutscene.js
var RobotDestructionCutscene = pc.createScript('robotDestructionCutscene');

RobotDestructionCutscene.attributes.add('containerEntity', { type: 'entity' });
RobotDestructionCutscene.attributes.add('spineEntity', { type: 'entity' });
RobotDestructionCutscene.attributes.add('wellDoneTextEntity', { type: 'entity' });
RobotDestructionCutscene.attributes.add('continueButtonEntity', { type: 'entity' });

// initialize code called once per entity
RobotDestructionCutscene.prototype.initialize = function() {
    this.scene = SceneManager.Instance.loadedSceneEntity.script.gameCompleteScene;

    this.spine = this.spineEntity.script.spine;
    this.spine.on('complete', this.OnSpineAnimationComplete, this);

    this.containerEntity.enabled = false;

    this.continueButton = this.continueButtonEntity.script.MPDOMButton;
    this.continueButton.on("click", this.OnContinueButtonPressed, this);

    this.showFinalCutscene = false;
};

// update code called every frame
RobotDestructionCutscene.prototype.update = function(dt) {

};

RobotDestructionCutscene.prototype.Show = function(config) {
    this.showFinalCutscene = config.showFinalCutscene;
    this.containerEntity.enabled = true;
    this.continueButtonEntity.enabled = false;

    AudioManager.Instance.Play("sfx_game_complete", "well_done");

    this.wellDoneTextEntity.setLocalScale(0.0001, 0.0001, 0.0001);
    var scaleTween = this.wellDoneTextEntity.tween(this.wellDoneTextEntity.getLocalScale());
    scaleTween.to({x: 1, y: 1, z: 1}, 0.5, pc.BackOut, 1.5);
    scaleTween.pausable = false;
    scaleTween.start();

    this.spine.SetSkin(GameScene.levelID);
};

RobotDestructionCutscene.prototype.Hide = function() {
    this.containerEntity.enabled = false;
};

RobotDestructionCutscene.prototype.OnSpineAnimationComplete = function() {
    this.continueButtonEntity.enabled = true;
    AudioManager.Instance.Play("sfx_game_complete", "ui_continue_appear");
};

RobotDestructionCutscene.prototype.OnContinueButtonPressed = function() {
    this.Hide();

    if(this.showFinalCutscene){
        this.scene.SetState(GameCompleteScene.State.FinalCutscene);
    }
    else{
        this.scene.SetState(GameCompleteScene.State.GameReward);
    }
    
};

    

