// GameCompleteScene.js
var GameCompleteScene = pc.createScript('gameCompleteScene');


if (!MPScene)
      var MPScene = function() {};
GameCompleteScene.prototype = Object.create(MPScene.prototype);
GameCompleteScene.prototype.constructor = GameCompleteScene;

GameCompleteScene.State = Object.freeze({
    RobotDestructionCutscene:   1,
    FinalCutscene:              2,
    GameReward:                 3
});


GameCompleteScene.attributes.add("gameCompletePopupEntity", { type: 'entity' });
GameCompleteScene.attributes.add("robotDestructionCutscenEntity", { type: 'entity' });
GameCompleteScene.attributes.add("finalCutsceneEntity", { type: 'entity' });
GameCompleteScene.attributes.add("gameDataAsset", { type: 'asset', assetType: 'json' });

GameCompleteScene.prototype.initialize = function() {
    MPScene.prototype.initialize.call(this);   
    
    this.gameCompletePopup = this.gameCompletePopupEntity.script.gameCompletePopup;
    this.robotDestructionCutscene = this.robotDestructionCutscenEntity.script.robotDestructionCutscene;
    this.finalCutscene = this.finalCutsceneEntity.script.finalCutscene;

    var gameData = this.gameDataAsset.resource;
    this.levelsData = gameData.levels;
    this.levelData = null;

    for(var i = 0; i<this.levelsData.length; i++){
        if(this.levelsData[i].id == GameScene.levelID){
            this.levelData = this.levelsData[i][GameScene.levelType];
            break;
        }
    }
    
    this.LoadData(); 

    

};

GameCompleteScene.prototype.postInitialize = function() {
    MPScene.prototype.postInitialize.call(this);

    this.SetState(GameCompleteScene.State.RobotDestructionCutscene);
};

GameCompleteScene.prototype.OnSceneLoaded = function(data) {
    MPScene.prototype.OnSceneLoaded.call(this, data);
    
    //this.player.invincible = data && data.invincible !== undefined ? data.invincible : false;
};

GameCompleteScene.prototype.update = function(dt) {
    MPScene.prototype.update.call(this, dt);
    
    if(GameManager.Instance.IsPaused()) return;
    

};

GameCompleteScene.prototype.SetState = function(state) {
    
    var previousState = this.state;

    this.state = state;
    
    switch(this.state){
        case GameCompleteScene.State.RobotDestructionCutscene:{
            this.OnEnterRobotDestructionCutsceneState();
            break;
        }
        case GameCompleteScene.State.FinalCutscene:{
            this.OnEnterFinalCutsceneState();
            break;
        }
        case GameCompleteScene.State.GameReward:{
            this.OnEnterGameRewardState();
            break;
        }
    }
};



GameCompleteScene.prototype.OnEnterRobotDestructionCutsceneState = function() {
    var isLastLevel = this.levelsData[this.levelsData.length - 1].id == GameScene.levelID;
    var showFinalCutscene = false;

    if(isLastLevel && !this.hasPlayedFinalCutscene){
        showFinalCutscene = true;
    }

    this.robotDestructionCutscene.Show({ showFinalCutscene: showFinalCutscene });
};

GameCompleteScene.prototype.OnEnterFinalCutsceneState = function() {
    this.finalCutscene.Show();
};

GameCompleteScene.prototype.OnEnterGameRewardState = function() {
    var unlockEndless = this.levelsSaveData[GameScene.levelID].unlockedEndless != true;
    var unlockNextLevel = unlockEndless;
    
    if(unlockEndless){
        this.levelsSaveData[GameScene.levelID].unlockedEndless = true;
        SaveDataManager.Instance.SetGameData("levels", this.levelsSaveData);
        SaveDataManager.Instance.SaveToStorage();
        
        var isLastLevel = this.levelsData[this.levelsData.length - 1].id == GameScene.levelID;

        if(isLastLevel){
            unlockNextLevel = false;
        }
    }
    
    if(unlockEndless || unlockNextLevel){
        this.gameCompletePopup.Show({unlockEndless: unlockEndless, unlockNextLevel: unlockNextLevel, nextLevelID: this.levelData.nextLevelID});
    }
    else{
        this.Exit(true);
    }
    
};


GameCompleteScene.prototype.Enable = function() {
    MPScene.prototype.Enable.call(this);

};

GameCompleteScene.prototype.Pause = function() {
    MPScene.prototype.Pause.call(this);
    
};

GameCompleteScene.prototype.LoadData = function() {    
    var hasPlayedFinalCutscene = SaveDataManager.Instance.GetGameData("hasPlayedFinalCutscene");
    
    if(hasPlayedFinalCutscene !== undefined){
        this.hasPlayedFinalCutscene = hasPlayedFinalCutscene;
    }
    
    this.levelsSaveData = SaveDataManager.Instance.GetGameData("levels");
    
    if(!this.levelsSaveData){
        this.levelsSaveData = {};
    }
    
    if(!this.levelsSaveData[GameScene.levelID]){
        this.levelsSaveData[GameScene.levelID] = {};
    }
};


GameCompleteScene.prototype.Exit = function(justCompletedLevel) {
    SceneManager.Instance.ClearStateStack();
    SceneManager.Instance.SetState("LevelSelectScreen", {justCompletedLevel: justCompletedLevel});
    GameManager.Instance.ClearPauseLayers();
};


GameCompleteScene.prototype.OnDestroy = function() {
    MPScene.prototype.OnDestroy.call(this);
};

