// MPDOMButtonPulseTween.js
var MPDOMPulseTween = pc.createScript('MPDOMPulseTween');

MPDOMPulseTween.attributes.add("attribute", { type: 'string',
    enum: [
        { 'scale': "scale" }
    ],
    default: 'scale'
});
MPDOMPulseTween.attributes.add("attributeStartValue", { type: 'number',  default: 0 });
MPDOMPulseTween.attributes.add("attributeEndValue", { type: 'number',  default: 1 });
MPDOMPulseTween.attributes.add("duration", { type: 'number',  default: 0.5 });
MPDOMPulseTween.attributes.add("easeType", { type: 'string',  default: "Linear" });
MPDOMPulseTween.attributes.add("delay", { type: 'number',  default: 0 });

// initialize code called once per entity
MPDOMPulseTween.prototype.initialize = function() {
    this.MPDOMButton = this.entity.MPDOMButton;
    this.onEnableTween = this.entity.script.MPDOMOnEnableTween;

    this.MPDOMButton.on("enable", this.OnEnable, this);

    
    this.pulseTween = this.entity.tween(this);
};

// update code called every frame
MPDOMPulseTween.prototype.update = function(dt) {

};

MPDOMPulseTween.prototype.OnEnable = function() {
    this.onEnableTween.off("complete", this.Play, this);

    if(this.onEnableTween){
        this.onEnableTween.once("complete", this.Play, this);
    }
    else{
        this.Play();
    }
};

MPDOMPulseTween.prototype.Play = function() {
    this.pulseTween.stop();
    
    var target = null;
    
    switch(this.attribute){
        case "scale":{
            this.entity.setLocalScale(this.attributeStartValue, this.attributeStartValue, this.attributeStartValue);
            this.pulseTween = this.entity.tween(this.entity.getLocalScale());
            target = {x: this.attributeEndValue, y: this.attributeEndValue, z: this.attributeEndValue};
            break;
        }
    }
    
    if(this.pulseTween){
        this.pulseTween.to(target, this.duration, pc[this.easeType], this.delay, Infinity, true);
        this.pulseTween.pausable = false;
        this.pulseTween.start();
    }
    
};




