// HydraGlobalMessageBanner.js
var HydraGlobalMessageBanner = pc.createScript('hydraGlobalMessageBanner');

HydraGlobalMessageBanner.attributes.add("containerEntity", { type: 'entity' });
HydraGlobalMessageBanner.attributes.add("layoutGroupEntity", { type: 'entity' });
HydraGlobalMessageBanner.attributes.add("globalMessageContentTextTemplate", { type: 'asset', assetType: "template" });
HydraGlobalMessageBanner.attributes.add("globalMessageContentImageTemplate", { type: 'asset', assetType: "template" });
HydraGlobalMessageBanner.attributes.add("dcshg-logo", { type: 'asset', assetType: "sprite" });
HydraGlobalMessageBanner.attributes.add("cn-logo", { type: 'asset', assetType: "sprite" });
HydraGlobalMessageBanner.attributes.add("boing-logo", { type: 'asset', assetType: "sprite" });
HydraGlobalMessageBanner.attributes.add("ttg-logo", { type: 'asset', assetType: "sprite" });

HydraGlobalMessageBanner.messageCacheCount = 0;
HydraGlobalMessageBanner.messageCache = [];

// initialize code called once per entity
HydraGlobalMessageBanner.prototype.initialize = function() {
    this.containerEntity.enabled = false;
    this.messages = [];
    this.messagesLength = 0;
    this.messagesIndex = 0;

    this.currentMessage = null;
    this.currentContents = [];

    this.messageChangeTime = 5;
    this.messageChangeTimer = this.messageChangeTime;

    this.moveTween = this.entity.tween(this.entity.getLocalPosition());

    if(HydraGlobalMessageBanner.messageCacheCount == 0 || HydraGlobalMessageBanner.messageCache.length != HydraGlobalMessageBanner.messageCacheCount){
        Hydra.GetGlobalMessages({ global_message_type_slug: "banner-messages" }, this.OnGetGlobalMessagesSuccess.bind(this), this.OnGetGlobalMessagesFailed.bind(this));
    }
    else{
        this.messages = HydraGlobalMessageBanner.messageCache;
    }
};

HydraGlobalMessageBanner.prototype.postInitialize = function() {

};

// update code called every frame
HydraGlobalMessageBanner.prototype.update = function(dt) {
    this.messageChangeTimer -= dt;
    if(this.messageChangeTimer <= 0){
        var prevIndex = this.messagesIndex;
        this.messagesIndex++;

        this.messageChangeTimer = this.messageChangeTime;

        if(this.messagesIndex > this.messages.length - 1){
            this.messagesIndex = 0;
        }


        if(this.messagesIndex != prevIndex){
            this.Hide();
        }
        

    }

    if(this.messages && this.messages.length != this.messagesLength){
        this.messagesLength = this.messages.length;

        if(this.messages.length > 0){
            this.UpdateMessageText();
            
        }
    }
};

HydraGlobalMessageBanner.prototype.OnGetGlobalMessagesSuccess = function(response) {
    this.messages = [];
    HydraGlobalMessageBanner.messageCache = [];
    HydraGlobalMessageBanner.messageCacheCount = response.results.length;

    for(var i = 0; i<response.results.length; i++){
        if(response.results[i].enabled){

            var result = response.results[i];
            var responseText = result.on_activate.content._agValue.rendered;
            var contents = this.GetContentsFromMessageText(responseText);
            var message = {
                contents: contents,
                imageLoadCount: 0
            };

            for(var j = 0; j<contents.length; j++){
                var content = contents[j];

                if(content.type == "image"){
                    message.imageLoadCount++;

                    var data = result.data[content.text];
                    if(data && data._agValue && data._agValue.rendered){
                        var loadID = data._agValue.rendered;
                        if(content.text.includes("http")){
                            this.LoadContentImageFromURL(message, content, loadID);
                        }
                        else{
                            var imageAsset = this[loadID];
                            content.imageAsset = imageAsset;
    
                            content.hasLoaded = true;
                            message.imageLoadCount--;
                        }
                    }
                }
            }

            if(message.imageLoadCount == 0){
                this.AddMessage(message);
            }
        }
    }    
};

HydraGlobalMessageBanner.prototype.GetContentsFromMessageText = function(text) {
    //text = "{How}{are}you{doing}today my{friend?}";

    var contents = [];
    var hasMoreContent = false;


    var startIndex = 0;

    do
    {
        var imageStartIndex = text.indexOf('{');
        var imageEndIndex = text.indexOf('}');
        if(imageStartIndex != -1 && imageEndIndex != -1){
            if(imageStartIndex > 0){
                contents.push({
                    type: "text",
                    text: text.slice(0, imageStartIndex)
                });
            }
            
            contents.push({
                type: "image",
                text: text.slice(imageStartIndex + 1, imageStartIndex + (imageEndIndex - imageStartIndex)),
                imageAsset: null,
                hasLoaded: false
            });

            startIndex = imageEndIndex + 1;
            text = text.slice(startIndex);
            hasMoreContent = text.length > 0;
        }
        else{
            contents.push({
                type: "text",
                text: text
            });
            hasMoreContent = false;
        }
    }while(hasMoreContent);

    if(this.app.i18n.locale == "ar"){
        contents.reverse();
    }
    
    return contents;
};

    
    

HydraGlobalMessageBanner.prototype.OnGetGlobalMessagesFailed = function(response) {

};

HydraGlobalMessageBanner.prototype.OnGetFileStorageItemSuccess = function(message, content, response) {
    this.LoadContentImageFromURL(message, content, response.download_url);
};

HydraGlobalMessageBanner.prototype.LoadContentImageFromURL = function(message, content, url) {
    // allow cross origin texture requests
    this.app.loader.getHandler("texture").crossOrigin = "anonymous";
        
    var asset = new pc.Asset(content.text, "texture", {
        url: url
    });
    
    this.app.assets.add(asset);

    asset.on("load", function (asset) {
        content.imageAsset = asset;
        
        content.hasLoaded = true;
        message.imageLoadCount--;
        if(message.imageLoadCount == 0){
            this.AddMessage(message);
        }
    }.bind(this));
    
    this.app.assets.load(asset);
};


HydraGlobalMessageBanner.prototype.Show = function() {
    this.containerEntity.enabled = true;
    this.entity.setLocalPosition(0, -this.entity.element.height, 0);

    this.moveTween.stop();
    this.moveTween = this.entity.tween(this.entity.getLocalPosition());
    this.moveTween.to({x: 0, y: 0, z: 0}, 0.5, pc.SineOut, 1);
    this.moveTween.start();
    
};

HydraGlobalMessageBanner.prototype.Hide = function() {
    this.moveTween.stop();
    this.moveTween = this.entity.tween(this.entity.getLocalPosition());
    this.moveTween.to({x: 0, y: -this.entity.element.height, z: 0}, 0.5, pc.SineIn);
    this.moveTween.start();
    this.moveTween.on("complete", this.OnHideComplete, this);
    
};

HydraGlobalMessageBanner.prototype.OnHideComplete = function() {
    this.UpdateMessageText();
    
};


HydraGlobalMessageBanner.prototype.UpdateMessageText = function() {
    if(this.messages.length > 0 && this.currentMessage != this.messages[this.messagesIndex]){
        this.currentMessage = this.messages[this.messagesIndex];

        for(var i = 0; i<this.currentContents.length; i++){
            this.currentContents[i].destroy();
        }
        this.currentContents = [];

        var textCount = 0;

        for(var i = 0; i<this.currentMessage .contents.length; i++){
            var content = this.currentMessage .contents[i];
            var templateEntity = null;
            
            switch(content.type){
                case "text":{
                    templateEntity = this.globalMessageContentTextTemplate.resource.instantiate();
                    templateEntity.element.text = content.text;
                    textCount++;
                    break;
                }
                case "image":{
                    if(content.imageAsset){
                        templateEntity = this.globalMessageContentImageTemplate.resource.instantiate();

                        switch(content.imageAsset.type){
                            case "sprite":{
                                templateEntity.element.spriteAsset = content.imageAsset;
                                break;
                            }
                            case "texture":{
                                templateEntity.element.textureAsset = content.imageAsset;
                                break;
                            }
                        }
                    }
                    
                    
                    break;
                }

            }

            if(templateEntity){
                this.layoutGroupEntity.addChild(templateEntity);
                this.currentContents.push(templateEntity);
            }
        }

        this.layoutGroupEntity.layoutgroup.reflow();


        setTimeout(function(){
            var maxWidth = this.layoutGroupEntity.element.width / textCount;
            for(var i = 0; i<this.currentContents.length; i++){
                this.currentContents[i].layoutchild.maxWidth = maxWidth;
                this.currentContents[i].element.width = this.currentContents[i].element.textWidth;
            }
        }.bind(this), 1);

        this.Show();
        
    }
    
};


HydraGlobalMessageBanner.prototype.AddMessage = function(message) {
    this.messages.push(message);
    HydraGlobalMessageBanner.messageCache.push(message);
};


