// Leaderboard.js
var Leaderboard = pc.createScript('leaderboard');

Leaderboard.attributes.add('containerEntity', { type: 'entity' });
Leaderboard.attributes.add('entriesEntity', { type: 'entity' });
Leaderboard.attributes.add('leaderboardEntryTemplateAsset', { type: 'asset', assetType: "template" });
Leaderboard.attributes.add('playerLeaderboardEntryTemplateAsset', { type: 'asset', assetType: "template" });
Leaderboard.attributes.add("titleEntity", { type: 'entity' });
Leaderboard.attributes.add("fetchingStateEntity", { type: 'entity' });
Leaderboard.attributes.add("showingStateEntity", { type: 'entity' });
Leaderboard.attributes.add("failedStateEntity", { type: 'entity' });

Leaderboard.State = Object.freeze({
    Fetching:        0,
    Showing:         1,
    Failed:          2
    
});

// initialize code called once per entity
Leaderboard.prototype.initialize = function() {
    this.levelID = null;
    this.maxEntries = 4;
    this.leaders = [];

    this.state = null;

    this.containerEntity.enabled = false;

    this.entries = [];

    this.scoreHydraObjectID = null;
};

// update code called every frame
Leaderboard.prototype.update = function(dt) {

};

Leaderboard.prototype.Show = function(levelID) {
    this.containerEntity.enabled = true;

    this.levelID = levelID;

    this.SetState(Leaderboard.State.Fetching);
};

Leaderboard.prototype.Hide = function() {
    this.containerEntity.enabled = false;

    for(var i = 0; i<this.entries.length; i++){
        this.entries[i].entity.destroy();
    }
};

Leaderboard.prototype.SetState = function(state) {
    this.state = state;

    this.fetchingStateEntity.enabled = false;
    this.showingStateEntity.enabled = false;
    this.failedStateEntity.enabled = false;

    switch(state){
        case Leaderboard.State.Fetching:{
            this.OnEnterFetchingState();
            break;
        }
        case Leaderboard.State.Showing:{
            this.OnEnterShowingState();
            break;
        }
        case Leaderboard.State.Failed:{
            this.OnEnterFailedState();
            break;
        }
    }
};

Leaderboard.prototype.OnEnterFetchingState = function() {
    this.fetchingStateEntity.enabled = true;
    Hydra.GetObjectLeaderboardPage({ object_type_slug: this.levelID + "-score", leaderboard_type_id: "score-leaderboard", queryParameters: { count: this.maxEntries, page: 1, owner_account_fields: "data", fields: "data" } }, this.OnGetLeaderboardPageSuccess.bind(this), this.OnGetLeaderboardPageFailed.bind(this));
};

Leaderboard.prototype.OnEnterShowingState = function() {
    this.showingStateEntity.enabled = true;
    this.entries = [];
    var includesPlayer = false;

    for(var i = 0; i<this.leaders.length && i<this.maxEntries; i++){

        if(this.leaders[i].object.owner_id == Hydra.accountID && !includesPlayer){
            var entryEntity = this.playerLeaderboardEntryTemplateAsset.resource.instantiate();
            this.entriesEntity.addChild(entryEntity);

            var entry = entryEntity.script.playerLeaderboardEntry;
            entry.Show(this.leaders[i], i);
            this.entries.push(entry);
            includesPlayer = true;
        }
        else{
            var entryEntity = this.leaderboardEntryTemplateAsset.resource.instantiate();
            this.entriesEntity.addChild(entryEntity);

            var entry = entryEntity.script.leaderboardEntry;
            entry.Show(this.leaders[i], i);
            this.entries.push(entry);
        }
        
    }
};

Leaderboard.prototype.OnEnterFailedState = function() {
    this.failedStateEntity.enabled = true;
};

Leaderboard.prototype.OnGetLeaderboardPageSuccess = function(response) {
    this.leaders = response.leaders.slice(0, this.maxEntries);

    var playerInTop = false;

    for(var i = 0; i<this.leaders.length && i<this.maxEntries; i++){
        if(this.leaders[i].object.owner_id == Hydra.accountID){
            playerInTop = true;
        }
    }

    if(playerInTop){
        this.SetState(Leaderboard.State.Showing);
    }
    else{
        //Check if player has score
        var levelsSaveData = SaveDataManager.Instance.GetGameData("levels");
        if(levelsSaveData && levelsSaveData[this.levelID] && levelsSaveData[this.levelID].highscoreSubmitted){
            if(this.scoreHydraObjectID){
                this.GetScoreAndRank(this.scoreHydraObjectID);
            }
            else{
                Hydra.GetUniqueObjectForOwner({ object_type_slug: this.levelID + "-score", unique_key: "score" }, this.OnGetUniqueObjectForOwnerSuccess.bind(this), this.OnGetUniqueObjectForOwnerFailed.bind(this));
            }
            
        }
        else{
            this.SetState(Leaderboard.State.Showing);
        }
        
    }
    
};

Leaderboard.prototype.OnGetLeaderboardPageFailed = function(response) {
    this.SetState(Leaderboard.State.Failed);
};

Leaderboard.prototype.OnGetUniqueObjectForOwnerSuccess = function(response) {
    this.GetScoreAndRank(response.id);
};

Leaderboard.prototype.GetScoreAndRank = function(objectID) {
    Hydra.GetObjectLeaderboardObjectScoreAndRank({ object_type_slug: this.levelID + "-score", leaderboard_type_id: "score-leaderboard", object_id: objectID, queryParameters: { owner_account_fields: "data", fields: "data" } }, this.OnGetObjectLeaderboardObjectScoreAndRankSuccess.bind(this), this.OnGetObjectLeaderboardObjectScoreAndRankFailed.bind(this));
};

Leaderboard.prototype.OnGetUniqueObjectForOwnerFailed = function(response) {
    this.SetState(Leaderboard.State.Showing);
};

Leaderboard.prototype.OnGetObjectLeaderboardObjectScoreAndRankSuccess = function(response) {
    if(response.rank){
        this.leaders[this.leaders.length - 1] = response;
    }
    
    this.SetState(Leaderboard.State.Showing);

};

Leaderboard.prototype.OnGetObjectLeaderboardObjectScoreAndRankFailed = function(response) {
    this.SetState(Leaderboard.State.Showing);
};

