var EndlessGameOverInitialsSelect = pc.createScript('endlessGameOverInitialsSelect');

EndlessGameOverInitialsSelect.attributes.add('endlessGameOverPopupEntity', { type: 'entity' });
EndlessGameOverInitialsSelect.attributes.add('containerEntity', { type: 'entity' });
EndlessGameOverInitialsSelect.attributes.add('initialsEntity', { type: 'entity' });
EndlessGameOverInitialsSelect.attributes.add('submitButtonEntity', { type: 'entity' });

// initialize code called once per entity
EndlessGameOverInitialsSelect.prototype.initialize = function() {
    this.containerEntity.enabled = false;
    this.endlessGameOverPopup = this.endlessGameOverPopupEntity.script.endlessGameOverPopup;

    this.initialSelectors = [];

    for(var i = 0; i<this.initialsEntity.children.length; i++){
        this.initialSelectors.push(this.initialsEntity.children[i].script.initialSelector);
    }

    this.submitButton = this.submitButtonEntity.script.MPDOMButton;
    this.submitButton.on("click", this.OnSubmitButtonPressed, this);
};

// update code called every frame
EndlessGameOverInitialsSelect.prototype.update = function(dt) {

};

EndlessGameOverInitialsSelect.prototype.Show = function() {
    this.containerEntity.enabled = true;

    var initials = SaveDataManager.Instance.GetGameData("initials");

    if(initials){
        for(var i = 0; i<this.initialSelectors.length; i++){
            this.initialSelectors[i].SetInitialToCharacter(initials[i]);
        }
    }

    this.submitButton.entity.enabled = true;
    this.submitButton.Enable();
};

EndlessGameOverInitialsSelect.prototype.Hide = function() {
    this.containerEntity.enabled = false;
};

EndlessGameOverInitialsSelect.prototype.OnSubmitButtonPressed = function() {
    var initials = "";

    for(var i = 0; i<this.initialSelectors.length; i++){
        initials += this.initialSelectors[i].initial;
        this.initialSelectors[i].Disable();
    }

    SaveDataManager.Instance.SetGameData("initials", initials);
	SaveDataManager.Instance.SaveToStorage();

    this.endlessGameOverPopup.SubmitScore(this.OnSubmitScoreSuccess.bind(this), this.OnHydraFailed.bind(this));
    this.submitButton.Disable();
    this.submitButton.entity.enabled = false;
};

EndlessGameOverInitialsSelect.prototype.OnSubmitScoreSuccess = function(response) {
    this.endlessGameOverPopup.SetState(EndlessGameOverPopup.State.Leaderboard);
};

EndlessGameOverInitialsSelect.prototype.OnHydraFailed = function(response) {
    this.endlessGameOverPopup.SetState(EndlessGameOverPopup.State.Results);
};

// InitialSelector.js
var InitialSelector = pc.createScript('initialSelector');

InitialSelector.attributes.add("upButtonEntity", { type: 'entity' });
InitialSelector.attributes.add("downButtonEntity", { type: 'entity' });
InitialSelector.attributes.add("initialTextEntity", { type: 'entity' });
// initialize code called once per entity
InitialSelector.prototype.initialize = function() {
    this.upButton = this.upButtonEntity.script.MPDOMButton;
    this.upButton.on("click", this.OnUpButtonPressed, this);

    this.downButton = this.downButtonEntity.script.MPDOMButton;
    this.downButton.on("click", this.OnDownButtonPressed, this);

    this.validInitials = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ';
    this.initialIndex = 0;

    this.initial = 'A';
    this.UpdateInitial();
};

// update code called every frame
InitialSelector.prototype.update = function(dt) {

};

InitialSelector.prototype.OnDownButtonPressed = function() {
    this.initialIndex--;

    if(this.initialIndex < 0){
        this.initialIndex = this.validInitials.length - 1;
    }

    this.UpdateInitial();
};

InitialSelector.prototype.OnUpButtonPressed = function() {
    this.initialIndex++;

    if(this.initialIndex > this.validInitials.length - 1){
        this.initialIndex = 0;
    }

    this.UpdateInitial();
};

InitialSelector.prototype.SetInitialToCharacter = function(char) {
    if(char){
        var indexOf = this.validInitials.indexOf(char);

        if(indexOf != -1){
            this.initialIndex = indexOf;
            this.UpdateInitial();
        }
    }
};

InitialSelector.prototype.UpdateInitial = function() {
    this.initial = this.validInitials[this.initialIndex];
    this.initialTextEntity.element.text = this.initial;
};

InitialSelector.prototype.Disable = function() {
    this.upButton.Disable();
    this.downButton.Disable();
};

// MPDOMOnDisableTween.js
var MPDOMOnDisableTween = pc.createScript('MPDOMOnDisableTween');

MPDOMOnDisableTween.attributes.add("attribute", { type: 'string',
    enum: [
        { 'scale': "scale" }
    ],
    default: 'scale'
});
MPDOMOnDisableTween.attributes.add("attributeStartValue", { type: 'number',  default: 0 });
MPDOMOnDisableTween.attributes.add("attributeEndValue", { type: 'number',  default: 1 });
MPDOMOnDisableTween.attributes.add("duration", { type: 'number',  default: 0.5 });
MPDOMOnDisableTween.attributes.add("easeType", { type: 'string',  default: "Linear" });
MPDOMOnDisableTween.attributes.add("delay", { type: 'number',  default: 0 });

// initialize code called once per entity
MPDOMOnDisableTween.prototype.initialize = function() {
    this.MPDOMButton = this.entity.MPDOMButton;

    this.MPDOMButton.on("disable", this.OnDisable, this);
    
    this.onDisableTween = this.entity.tween(this);

    if(!this.MPDOMButton.enableOnInitialize){
        this.OnDisable();
    }
};

// update code called every frame
MPDOMOnDisableTween.prototype.update = function(dt) {

};

MPDOMOnDisableTween.prototype.OnDisable = function() {
    this.onDisableTween.stop();
    
    var target = null;
    
    switch(this.attribute){
        case "scale":{
            this.entity.setLocalScale(this.attributeStartValue, this.attributeStartValue, this.attributeStartValue);
            this.onDisableTween = this.entity.tween(this.entity.getLocalScale());
            target = {x: this.attributeEndValue, y: this.attributeEndValue, z: this.attributeEndValue};
            break;
        }
    }
    
    if(this.onDisableTween){
        this.onDisableTween.to(target, this.duration, pc[this.easeType], this.delay);
        this.onDisableTween.on("complete", this.OnTweenComplete, this);
        this.onDisableTween.pausable = false;
        this.onDisableTween.start();
    }
    
};

MPDOMOnDisableTween.prototype.OnTweenComplete = function() {
    this.MPDOMButton.PositionElement();

    this.fire("complete");
};



